INSERT INTO `recipe` (`recipeID`, `recipe_title`, `recipe_ingredients`, `recipe_method`, `recipe_note`, `catID`) VALUES
(2, 'Mom\'s Pound Cake', '<p><font size=\"2\">1 white cake mix, 1 instant vanilla pudding, 1/2 cup of oil, 1 cup water, 4 eggs.</font></p>\r\n<p><font size=\"2\">If you want to cut the fat, use 1/4 cup oil and 1/4 cup apple sauce.&nbsp; Use 2 whole eggs and 2 egg whites.</font></p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>', '<p>Whip all ingredients together and bake in either a greased angle food pan.&nbsp; Or I use a silicone bunt pan which requires no greasing.&nbsp; Bake at 350 for 40 to 50.</p>', '<p>This is Gramma Mary\'s recipe that Erika and Scott love as is.&nbsp; I have, however, done the lower fat version and they have not been able to tell the difference.&nbsp; I switch it up so they can never know!!</p>', 3),
(3, 'Simply Sensational Truffles - Kraft', '<p>2 1/2 pkg (20 sqs) Bakers Semi-sweet chocolate, divided.&nbsp; 1 pkg (250g) brick cream cheese, softened</p>', '<p>Melt 8 of the chocolate squares as directed on package.&nbsp; Beat cream cheese in medium bowl with electric mixer on medium speed until creamy.&nbsp; Add melted chocolate.&nbsp; Mix well.&nbsp; Refrigerate at least 1 hour or until firm.&nbsp;</p>\r\n<p>Cover baking sheet with waxed paper.&nbsp; Shape choc mixture into 36 balls, using approx. 2 tsp of the mixture for each ball.&nbsp; Place in single layer on cookie sheet.&nbsp;</p>\r\n<p>Melt remaining 12 squares of choc as directed on package.&nbsp; Dip truffles in the choc one at a time.&nbsp; Return to baking sheet.&nbsp; Refrig until choc is firm.&nbsp; Store in tightly covered containter in the fridge.</p>\r\n<p>Note you can also decorate with nuts, sprinkles, etc. As well you can add1 to 2 tsp of an extract ie peppermint to chocolate or 1/4 cu of fav liqueur ie orange or rasp to choc mix before shaping.</p>', '<p>This is Erika\'s recipe.&nbsp; Delicious.&nbsp; 2 tsp is pretty big.&nbsp; you could always make them smaller.</p>', 2),
(4, 'Pork Lo Mein', '<p>260 g whole wheat spagetti, uncooked.&nbsp; 1/2 cu Kraft signature Asian Sesame Dressing.&nbsp; 1 lb of pork tenderloin or chicken cut into strips.&nbsp; 2 cloves garlic minced.&nbsp; 3 cups frozen stir-fry veggies, thawed and drained.&nbsp;1/2 cup beef broth.&nbsp; 1 tbsp smooth peanut butter.&nbsp; 1/4 cup soy sauce.&nbsp; 1 tbsp chopped cilantro (optional)</p>\r\n<p>&nbsp;</p>', '<p>Cook spag. as directed.&nbsp; Meanwhile heat dressing in large non stick skillet on medium-high heat.&nbsp; Add meat and garlic.&nbsp; Stir fry 3 minuts.&nbsp; Add veggies, broth and peanut butter.&nbsp; Stir fry additional 3 to 4 minutes until meat is cooked.&nbsp; Drain spaghetti and return to pan.&nbsp; Add meat mixture and soy sauce.&nbsp; Mix well.&nbsp; Do a taste test before serving.&nbsp; Depending&nbsp; I often add more sesame dressing and soy sauce.&nbsp; Of course, I always add more veggies, so more seasoning makes sense.&nbsp; I have found that honsin sauce gives it a nice kick as well.&nbsp; Spoon onto serving platter and sprinkle with cilantro - or thinly sliced green onions.</p>', '<p>The flavouring, depending on the soy sauce can vary widely.&nbsp; This is a great healthy meal.&nbsp; Makes 4 servings.&nbsp; 2 1/4 cups each.</p>', 4),
(5, 'Country French Leek and Chicken Soup', '<p>3 to 4 Leeks.; 1 tbsp butter; 4 carrots, 4 cups of chicken broth.&nbsp; 1 cup white wine or apple juice.&nbsp; 1 tbsp Dijon mustard; 1/2 tsp each of ground nutmeg, white pepper and salt; 3 pounds of chicken pieces with the bones; 4 potatoes peeled.&nbsp; 3 apples, peeled and cored; 2 stalks of celery, sliced.', '<p>Clean leeks by cutting in half lengthwise; Remove and discard the tough parts of the green leaves; Wash under running water.; Lots of sand inside ; Slice into 1/2 in slices.\r\n<p>Melt butter in large wide saucepan.&nbsp; Add leeks and saute over medium heat until softened; Stir often; Peel and finely chop the carrots; When leeks are soft, add carrots, broth, wine, Dijon and seasonings; Bring to a boil.\r\n<p>Meanwhile, remove skin and clinging fat from chicken; Submerge chicken pieces as much as possible in the soup; Cover, reduce hat to low and simmer 20 minutes.\r\n<p>Cut potatoes and apples into cubes; Turn chicken and add potatoes, apples and celery.&nbsp; Simmer covered anther 15 to 20 minutes until vegs are cooked; Remove chicken.&nbsp; Take out the bones, slice into bite size pieces; Add back in; Simmer until soup is hot; Taste, add more salt if required; Sprinkle with fresh nutmeg just before serving.', 'I like a thicker soup, so I take out some; (say 1/3) of the veggies when done and puree them; Then add back into the pot; The nutmeg just makes it smell wonderful!!', 5),
(6, 'Wine Country Inn Granola', '<p>2 cups quaker old fashio oats, 1 cup slivered almonds, 1/4 cup brown sugar, 1/4 cup liquid honey, 1/4 cup butter, 1 cup flaked coconut, sprinkle of cinnamon and salt, 1 cup raisins</p>', '<p>Mix together oats and almonds in large roasting pan.&nbsp; In small bowl, stir together melted butter and honey.&nbsp; Pour over oats and mix well.&nbsp; Sprinkle with brown sugar and cinnamon and salt.&nbsp; Stir.&nbsp;</p>\r\n<p>Bake at 350 until golden brown, stirring regularly.&nbsp; Then add coconut and bake until medium brown.&nbsp; Remove from oven and add raisins.&nbsp; Stir frequently while cooling to avoid clumping.</p>', '<p>Al and I love this granola.&nbsp; Got&nbsp;the recipe&nbsp;from the Wine Country Inn in Napa Valley.&nbsp; I usually double it.&nbsp; It is reasonably sweet, so I will cut a bit of the sugar back.&nbsp; Not much.&nbsp;</p>', 6),
(7, 'Gramma Mary\'s Cinnamon Buns', '<p>1/4 cup granulated sugar, 1/2 cup warm water, 1 pkg yeast, 1/2 cup milk, 1/4 cup butter, 1 tsp salt, 2 eggs - beaten, 4 cup regular flour.</p>\r\n<p>Filling: part one:  ; 3/4 cup butter, 3/4 cup packed brown sugar, \r\n\r\nFilling part 2:  1/2 cup brown sugar, 1 tbsp cinnamon, 1 cup chopped walnuts (optional)\r\n<p>&nbsp;</p>', '<p>Dissolve 1 tsp sugar in warm water.&nbsp; Sprinkle in yeast.&nbsp; Let stand 10 minutes or until frothy.&nbsp; Meanwhile in a small pan, heat the milk, remaining sugar, butter and salt until butter melts.&nbsp; Let cool to luke warm.&nbsp;</p>\r\n<p>In large bowl, combine eggs, milk mixture, and yeast mixture.&nbsp; Gradually add flour until ready to be turned out of the bowl onto a floured surface.&nbsp; Knead 10 minutes until smooth and elastic.&nbsp; Place in large greased bowl. Turn and cover with saran wrap or tea towel - keep away from cool drafts.&nbsp; Let rest 1 to 1.5 hours.&nbsp;</p>\r\n\r\nOr put it all into the bread machine, liquids then sugar then flour then the yeast top.   Set it to\" dough\" and turn it on. \r\n\r\n<p>Meanwhile, prepare the filling.&nbsp; Melt 3/4 cup butter with 3/4 cup brown sugar.&nbsp; Stir and cook until they are truly combined, otherwise it turns crystally when baked.&nbsp; Can take 10 to 15 minutes.&nbsp; When ready, pour into a greased 11 x 15 pan, spread.&nbsp; Sprinkle with half the nuts or raisins (optional)</p>\r\n<p>Melt remaining butter.&nbsp; Set aside.&nbsp; Combine remaining sugar, nuts and cinnamon.</p>\r\n<p>When dough has finished rising, punch it down and roll out of the bowl.&nbsp; Then roll out out flat to approx. 18 x 14 inches.&nbsp; Then pour the melted butter all over the dough - full size.&nbsp; Then sprinkle with the sugar/nut/cinnamon combo.&nbsp; Leave 1/2 inch clean all around, butter yes, but not the sweet combo.&nbsp; This is where you will be pinching to keep the bun roll together.&nbsp; Roll the dough up lengthwise - pinch edges to keep it from&nbsp;from unrolling&nbsp;and cut into approx. 15 buns.&nbsp; Cover again and let rise 1 hour.</p>\r\n<p>Bake at 375 for 25 to 30 minutes, until golden brown on top.</p>\r\n<p>&nbsp;</p>', '<p>This is Gramma Mary\'s recipe.&nbsp; She used to say that I cut corners by using the microwave.&nbsp; I often make more filling as well as more of the buttery topping.&nbsp; I have tried using different flours - ie pastry or whole wheat.&nbsp; Always have been disappointed.&nbsp; So, I stick to the tried and true general purpose.</p>', 7),
(8, 'Babushka\'s Perohe', '<p>Dough - note this does not double well.&nbsp; Best to make 2 seperate bowls.</p>\r\n<p>3 cup flour, 1/2 tsp salt, 2 tbsp oil, 1 cup water, 1 egg.</p>\r\n<p>Filling - sufficient for double recipe of dough</p>\r\n<p>9 white potatoes.&nbsp; 1/2 kg velveeta cheese, 1/4 cup butter. Diced cooked bacon (optional)</p>\r\n<p>&nbsp;</p>', '<p>Combine ingred. for dough.&nbsp; Knead 10 minutes until smooth and elastic.</p>\r\n<p>Boil the potatoes until soft.&nbsp; Mash then add the velveeta, butter and bacon if using.&nbsp;</p>\r\n<p>Roll out the dough to 1/4 inch.&nbsp; Cut using a 3 inch glass cut into circles.&nbsp; Put 1 tsp filling into each circle and pinch all the edges together.</p>\r\n<p>Make the filling first so it has time to cool.&nbsp; When done making dumplings, lay out on trays and put into the freezer until firm.&nbsp; Then put into bags - divided into dinner size portions.&nbsp; Take out as needed.&nbsp; When want to eat, boil pot of water and drop frozen perohe into the water.&nbsp; Boil gently.&nbsp; they are done when they float to the top.&nbsp; Treat gently!!&nbsp; Serve with melted butter and sour cream.</p>', '<p>Gramma/ Babushka&nbsp;always made the best Perohe (pronounced &quot;ped-a-he&quot;) but better known as perogies.&nbsp; I think perogies is polish and perohe is ukranian.</p>', 7),
(9, 'Gramma Mary\'s Almond Buns', '<p>Dough:</p>\r\n<p>4 1/2 to 5 cups flour, 1/2 cup white sugar, 1/2 tsp grated cardamon, 1/4 tsp salt, 1 pkg yeast or 1 TBSP instant yeast, 1 1/4 cup milk, 1/4 cup water, 1/2 cup butter, 1 egg</p>\r\n<p>Filling:</p>\r\n<p>2 cup icing sugar, 2 tbsp butter, 2 tbsp ground almonds, 2 tbsp milk, 1/2 tsp almond extract</p>', '<p>Combine 1 cup flour, sugar, cardamon, salt and yeast.&nbsp; Over low heat, heat milk, butter and 1/4 cup water until very warm - not boiling.&nbsp; With mixer on low, gradually pour liquid into dry ingredients and beat until just mixed.&nbsp; Then at medium speed for 2 minutes.&nbsp; Yeast should be totally dissolved.&nbsp; Beat in egg and 1 cup flour or enough to make a thick batter.&nbsp; Stir in enough flour to ake a soft dough (approx&nbsp; cups)</p>\r\n<p>On well floured surface, knead until smooth and elastic, adding more flour if needed - ie sticky.&nbsp; Knead 10 minutes.&nbsp; Shape into a ball, put into greased bowl. Turn, cover and let rise in warm place until doubled - 1.5 hours.</p>\r\n<p>Punch down dough.&nbsp; Turn onto lightly floured surface.&nbsp; Cover with town and let rest 15 minutes.</p>\r\n<p>Grease 2 large cookie sheets.&nbsp; Roll dough to 1 inch thickness.&nbsp; Cut into squares - approx 3 x 3 inches - make into balls, pinching corners on bottom.&nbsp; Cvoer and let rise AGAIN until doubled - 30 to 40 minutes.&nbsp; Bake at 350 for 15 minutes.</p>\r\n<p>Make the filling.</p>', '<p>Needless to say, the filling recipe usually has to be doubled or a new batch made after the first batch disappears.</p>', 7),
(10, 'Debbie\'s Banana Bread', '<p>1 1/2 cup flour, 1 1/2 tsp baking powder, 1/4 tsp baking soda, 1/4 tsp salt, 1 tsp cinnamon, 1 cup white sugar.</p>\r\n<p>2 eggs, 1/3 cup butter, 1 tsp vanilla, 1/4 cup milk, 1 cup mashed bananas - takes&nbsp;2 or 3 bananas, depending on size&nbsp;- room temperature.</p>\r\n<p>&nbsp;</p>', '<p>Mix dry ingredients together.&nbsp; Mix wet together - I like to use the Braun hand held to get it really smooth.&nbsp; Mix both together and pour into one buttered and floured loaf pan.&nbsp; Sprinkle with brown sugar.&nbsp; Bake 350 for 40 minutes or so.</p>', '<p>I usually triple the recipe and put 2 loaves in the freezer.&nbsp; Scott likes milk chocolate chips added to the dough.&nbsp;</p>\r\n<p>When the bananas in the house get too brown for eating, I just throw them into the freezer and when I have&nbsp;6 or 8&nbsp;frozen, I make this triple recipe.&nbsp;</p>', 7),
(11, 'Cindy\'s Spicy Lousiana Shrimp', '<p>1 1/2 lb large shrimp, 6 tbsp unsalted butter, 2 tsp chili powder, 2 tsp black pepper, 1/4 tsp cyenne pepper, 2 tsp minced garlic, 4 tsp worchestershire sauce, 4 tbsp red wine, 1/2 tsp salt.</p>', '<p>arrange shrimp in baking dish in one layer.&nbsp; In small saucepan, combine all other ingredients and bring to a boil.&nbsp; Pour over the shrimp.&nbsp; Bake in preheated oven - 350 - for 8 to 10 minutes.</p>', '<p>Doubles very well.&nbsp; very easy and very good.&nbsp; Spicy tho.&nbsp; You could leave out some of the black pepper.</p>', 9),
(12, 'Veggie Garen Pizza Squares', '<p>1 package refrigerated crescent roll dough, 1 package brick crean cheese -&nbsp;softened, Ranch salad dressing, 2 carrots, shredded, 1/2 cup chopped red peppers, 1/2 cup chopped green peppers, 1/2 cup chopped fresh broccoli, 1/2 cup chopped green onions.</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>', '<p>Roll out crescent rolls onto a large non-stick baking sheet. Stretch and flatten to form a single rectangular shape on the sheet.&nbsp; Bake 11 to 13 minutes in a preheated oven at 350 until golden.&nbsp; Allow to cool.</p>\r\n<p>Place cream cheese in a medium bowl and add enough ranch dressing to taste - make sure it is not too runny.&nbsp; Spread over the cooled crust.&nbsp; Arrange veggies on top.&nbsp; Chill in fridge for one hour then cut into bite sized pieces.</p>', NULL, 9),
(13, 'Mexican Antipasto', '<p>1 8 oz brick of softened cream cheese, dash of garlic, 1/2 cup sour cream. 1 large avocado mashed, 1/4 tsp lemon juice, 1 tomato finely diced, 1 4oz can of green chilies, 5 slices of bacon, cooked crisp and diced, 4 green onions, chopped, 1/4 stuffed green olives sliced,1 8oz bottle of old el paso taco sauce, 1 cup grated cheddar cheese.</p>', '<p>Combine first 3 ingredients anduse as first layer in 9 inch pie plate.&nbsp; Combine next 4 for the next layer, sprinkle on bacon, onions and olives,&nbsp; Spread taco sauce all over and sprinkle with grated cheese.&nbsp;&nbsp; Refrigerate until ready to use.</p>\r\n<p>Serve with taco chips or crackers</p>', 'good for a large group - but goes quickly.  Needless to say - you can make it even easier if you skip the bacon.  Just smooth store bought guacamole on the bottom, pour salsa over the top and smooth over, then put sour cream on top of that.  Then sprinkle grated cheddar cheese over for a pretty presentation.  Everyone loves this!!', 9),
(14, 'Goat cheese Balsamic Dip', '<p>8 oz soft creamy Woolwich goat cheese, broken up, 1/4 up sour cream, 1 to 2 tbsp balsamic vinegar, 1 clove of minced garlic, 1/2 tsp each - chopped fresh rosemary and thyme.</p>', '<p>In a food processor or blender, puree all ingredients.&nbsp; Adjust seasoning to taste.&nbsp; Makes approx 1 cup.</p>', 'great with veggies', 9),
(15, 'Roasted Feta Loaf', '<p>1/4 lb firm feta, 1 baguette halved, 1 tbsp good olive oil, 1/2 tsp red pepper flakes, pepper.</p>', '<p>Preheat oven to 400.&nbsp; slice some feta onto the bread.&nbsp; Drizzle with 1/2 of the olive oil and sprinkle with the red pepper flakes and pepper.&nbsp; Repeat with remaining feta.&nbsp; Bake until just melted - about 10 minutes.&nbsp; Serve with remaining oil drizzled over top.</p>', 'Very popular with guests not adverse to a bread based app.  The cooking time can be a bit less depending on your oven.  Also, I like to drizzle with a bit of honey on some and balsamic glaze on others.', 9),
(16, 'Baked Peanut Butter and Banana French Toast', '<p>1 wide supermarket - style baguette, 2 large bananas, 1/2 cup peanut butter, 1 cup milk, 3 eggs, 2 tbsp brown sugar, 2 tsp vanilla, 1/2 tsp each cinnamon and nutmeg, 1/4 tsp salt, 1 to 2 tbsp butter - melted, maple syrup or chocolate syrup.</p>\r\n<p>&nbsp;</p>', '<p>Slice baguette into 10 1.5 inch pieces.&nbsp; Using a knife, slice through the bottom crust of each piece, nearly right to the other side, to form a pocket.&nbsp; Thinly slice 1 banana.&nbsp; Spread about 2 tsp of PB into each pocket and then stuff in a few banana slices.&nbsp; Squish bread back together again and don\'t worry if it tears a bit and you can see the filling.</p>\r\n<p>Whisk milk, sugar, vanilla, spices and salt until blended.&nbsp; Pour into large flat baking dish.&nbsp; Place stuffed bread in the milk mixture and turn once.&nbsp; Refrigerate, covered at least 2 hours or overnight, turning a couple of times.</p>\r\n<p>When ready to bake, preheat oven to 450.&nbsp; Brush baking sheet with half the butter.&nbsp; Place bread on top, spacing evenly.&nbsp; Brush tops with remaining butter.&nbsp; Bake in centre of oven for 6 minutes. Turn and continue to bake until golden - 5 minutes.&nbsp; Slice remaining banana.&nbsp; Serve scattered with bananas and drizzled with maple syrup or chocolate sauce.</p>', NULL, 6),
(17, 'Roasted Tomato toasts', '<p>12 Roma tomatoes, olive oil, salt and pepper.&nbsp; 1 long baguette.&nbsp; Tube of Woolrich soft goat cheese, brick of softened cream cheese.</p>', '<p>Cut the tomatoes in half and scoop out the seeds.&nbsp; Place cut side up on a covered baking sheet.&nbsp; Drizzle with olive oil and sprinkle with salt and pepper.&nbsp; Roast in low oven - 200 - for 6 hours or until dried.</p>\r\n<p>When they are dried - cut the baguette into 24 thin slices -&nbsp;1/2 inch thick&nbsp; Drizzle with with olive oil and put under broiler to lightly toast.&nbsp;</p>\r\n<p>Mix cream cheese and goat cheese - 2 to 1 ratio.&nbsp; Spread over each baguette.&nbsp; Top with a tomato slice.&nbsp; Sprinkle with olive oil and more black pepper.&nbsp;</p>\r\n<p>Serve warm or room temperature.</p>', '<p>This is always very popular. Just need to do the prep work with the tomatoes the evening or day before.&nbsp; You could put into low oven over nite if you lower the oven temp just a bit.&nbsp; Got this recipe from Gail Desjardins</p>', 9),
(18, 'Bacon wrapped Water Chestnuts', '<p>1 lb bacon, 2 or 3 cans of water chestnuts, 1 cup ketchup, 2/3 cup brown sugar.</p>', '<p>Cut the bacon slices in half.&nbsp; Wrap each water chestnut with a slice of bacon.&nbsp; Push a toothpick thru each one to hold the bacon on.&nbsp; Bake in oven at 375 for 20 minutes or so until the bacon is crisp.&nbsp; Pour sauce over top, coating each piece, Bake again until the sauce has thickened.</p>', '<p>Another real winner.&nbsp; These disappear very quickly.&nbsp; Fast and easy to prepare.&nbsp; Serve warm.&nbsp; I think this is an Auntie Dora recipe.</p>', 9),
(19, 'Gramma Mary\'s Oven Apple Pancake', '<p>2 cups thinly sliced, peeled and cored apple, 1 tbsp butter - melted.&nbsp; 1/2 tsp cinnamon, 1 tbsp gran. sugar, 3 eggs, 1/3 cup flour, 1/4 tsp baking powder, 1/8 tsp salt, 1/2 cup milk.</p>', '<p>Place apple slices and butter in a&nbsp;8 inch square baking pan or a cast iron frying pan.&nbsp; Toss to coat, Combine the sugar and cinnamon.&nbsp; Sprinkle apples with half the cinnamon and sugar mixture.&nbsp; Bake in 425 oven for 8 minutes.&nbsp; Meanwhile in small bowl, whisk eggs, flour, baking powder and salt until smooth.&nbsp; Gradually blend in milk.&nbsp; Pour mixture over the cooked apples and sprinkle with the rest of the sugar and cinnamon mixture. Bake 15 to 20 minutes or until the batter is firm and golden brown.&nbsp; Serve immediately with maple syrup or fruit preserves.&nbsp; Serves 2.</p>', '<p>Gramma used to love to eat this for a light lunch with Grampa.</p>', 6),
(20, 'Babushka\'s Paska (egg bread)', '<p>Makes 6 loaves</p>\r\n<p>Combine and leave in bowl to rise for 20 minutes:&nbsp; 5 cups luke warm water, 3 tbsp sugar, 2 1/2 tsp yeast.</p>\r\n<p>Add 5 cups of flour.&nbsp; Mix.&nbsp; Cover.&nbsp; Let it rise 1.5 hours.</p>\r\n<p>Add 1/3 lb melted tenderflake, 6 eggs, 3/4 cup sugar,&nbsp; 10 to 12 cups of flour.&nbsp; Adjust amount of flour so dough is not sticky.&nbsp; Add 1 tbsp salt dissolved in 1/4 cup water.&nbsp; Knead 1/2 hour to 3/4 hour until dough is light and fluffy.</p>\r\n<p>Leave to rise again to triple its size.&nbsp; Butter 6 bread pans.&nbsp; Divide dough between.&nbsp; Brush with 1 egg mixed with some water.&nbsp; Bake 300 for 20 minutes</p>', NULL, '<p>Gramma made the best bread ever.&nbsp; The kneading is long, but very important.</p>', 7),
(21, 'Cinnabon Clone - made in bread machine', '<p>1 cup warm milk, 2 eggs room temp, 1/3 cup&nbsp; butter melted, 4 1/2 cups bread flour, 1 tsp salt, 1/2 cup granulated sugar, 2 1/2 tsp bread machine yeast, \r\n\r\n\r\n2 1/2 tbsp ground cinnamon, 1/3 cup butter softened.</p>\r\n\r\n\r\n<p>Icing:&nbsp; 3 oz cream cheese - little less tastes better.&nbsp; 1/4 cup butter softened, 1 1/2 cups icing sugar, 1/2 tsp vanilla, 1/8 tsp salt.</p>', '<p>Place ingredients in the machine.&nbsp; Wet in the bottom.&nbsp; Yeast in last.&nbsp; Select dough cycle and press start.</p>\r\n<p>After dough has doubled in size, turn out onto lightly floured surface, cover and let rest 10 minutes.&nbsp; In small bowl combine brown sugar and cinnamon.</p>\r\n<p>Roll dough into a 16 x 21 inch rectangle.&nbsp; Spread dough with 1/3 cup butter and&nbsp; sprinkle evnly with sugar/cin mixture.&nbsp; Roll up and cut into 12 rolls.&nbsp; lace in lightly greased 9 x 13 inch pan.&nbsp; Cover and let rise until doubled.&nbsp; Bake rolls in 400 oven until golden brown.&nbsp; When they come out spread with the icing.</p>', '<p>You don\'t need to use a bread machine.&nbsp; You could just mix it all together yourself.</p>', 7),
(22, 'super easy caesar chicken', '<p>6 boneless, skinless chicken breasts - preferably fresh.&nbsp;&nbsp;8 tbsp thick caesar salad dressing.&nbsp; 1 cup garlic croutons - crushed.</p>', '<p>Spread the caesar dressing evenly over the top of each breast.&nbsp; Sprinkle with the crushed croutons.&nbsp; Bake in 325 oven for 20 minutes or until cooked thru.</p>', '<p>I love this.&nbsp; It is garlicy tho and very tender and juicy.&nbsp; If you have less than wonderful chicken breasts, lightly coat them with corn starch - this, for some reason, results in juicier chicken without altering taste.&nbsp; Serve with some chicken flavoured and wild rice - green beans.&nbsp; The chicken has so much flavour, other things need to be simple.</p>', 10),
(23, 'Gramma Mary\'s Baked Beans', '<p>6 slices of bacon, 2 cups chopped onion, 1/2 lb of ground beef, black pepper, 1 tsp salt, 2 tbsp molasses, 3 tbsp brown sugar***********, 1 tsp dry mustard, 2 cups canned tomoatoes***** - drained, 56 oz Libby\'s pork and molasses beans.</p>', '<p>Cut into 2 inch pieces and brown the bacon.&nbsp;remove bacon and discard grease.   Saute onions in  the beef; continue to brown till cooked.&nbsp; Put everything else into a big pot and simmer for an hour.&nbsp; Add bacon and simmer for 15 minutes.&nbsp; Serve with soft buns.</p>', '****  The recipe calls for brown sugar, but I suggest that you taste it witout and then decide.  Some Libby is sweeter than Heinz.  Plus I add approx 1tsp of the chinese hot chili sauce - obviously optional.  For tomatoes, I just pu in one large can of drained diced tomatoes.  28 fl oz.  These are the best beans!!&nbsp; So easy.&nbsp; Serve with a green salad and you are good to go!!</p>', 21),
(24, 'Roasted Summer Vegetables', '<p>8 zucchini, 8 nice carrots, 8 smal new potatoes, 1/2 cup olive oil, 2 tbsp coarse salt</p>\r\n<p>&nbsp;</p>', '<p>Wash all veggies, leaving stems and skins intact.&nbsp; Dry well.&nbsp; Arrange in shallow baking dish.&nbsp; Brush with olive oil and sprinkle with salt.&nbsp; Bake in 375 oven until they are slightly browned and shrivelled - about 30 minutes.&nbsp; Makes 6 to 8 servings.</p>', '<p>You can always cut the veggies up if you like.&nbsp; Everyone loves roasted veggies and this is such an easy way to have several types of veggies all prepared in one easy go.&nbsp; Roasting veggies makes them sweet.</p>', 8),
(25, 'Gramma Virginia\'s 10 day sweet pickles', '<p>6 quarts of whole baby cucumbers - soak in coarse salt water for 3 days.&nbsp; Enough salt to float an egg.</p>\r\n<p>&nbsp;</p>', '<p>4th day - drain and add fresh water - soak and repeat this for 2 more days.&nbsp; On the seven day - drain and rinse.&nbsp; Simmer in weak white wine solution ( 1 part vinegar to 1 part water) and 3 tbsp of alum.&nbsp; Must cover the pickles.</p>\r\n<p>Drain, rinse and add syrup:&nbsp; 7 lbs white sugar, 1 oz allspice, 1 oz cinnamon sticks, 1 qt white vinegar, 1 pint of water, 4 to 5 drops of green food coloring.&nbsp; Boil the syrup and pour over the sliced pickles.&nbsp; Leave to soak for one day.&nbsp; Next day drain syrup, reheat it and pour it over the pickels. Repeat the next day.&nbsp; On the 10th day - last day.&nbsp; Put pickles into jars, pour syrup over and seal.</p>', '<p>Personally have not tried making this - but I love to eat them.&nbsp; Thought it would be good to save family recipe.</p>', 8),
(26, 'Vegetable-Fusilli Bake with Ricotta Topping', '<p>2 tbsp olive oil, 1 large onion, 1 yellow sweet pepper, diced, 1 zucchini chopped, 1 medium carrot, chopped, 4 cloves of minced garlic, 1/2 tsp each salt, black pepper and gran. sugar, 1/4 tsp hot pepper flakes, 1 can 796 diced tomatoes, 1/4 cup tomato paste, 1 cup drained and rinsed canned romano beans, 1/4 cup each chopped fresh parsley and basil leaves, 3 cups uncooked fusilli pasta</p>\r\n<p>Topping:&nbsp; 2 eggs, 454 grams of regular ricotta cheese, 1/4 tsp each, salt, pepper and nutmeg, 1/2 cup fresh parmesan cheese</p>', '<p>In large deep skillet heat oil over medium heat and add onion, pepper, zucchini and carrot.&nbsp; Cook until just tender.&nbsp; Stin in garlic, salt, pepper, sugar and hot pepper flakes.&nbsp; Cook one minute.&nbsp;</p>\r\n<p>Stir in tomatoes and their juices and tomatoe paste.&nbsp; Bring to boil then reduce heat to medium low.&nbsp; Simmer uncovered for 10 minutes untile slightly thickened.&nbsp; Stir in beans, parsley and pasil.&nbsp; Season with salt and pepper to taste.</p>\r\n<p>Preheat oven to 350 and cook the pasta until al dente.&nbsp; Drain but do not rinse.</p>\r\n<p>Spoon half the fusilli into a lightly oiled 10 cup baking dish.&nbsp; Spoon all the veggies over the fusilli then top with the rest of the patsa.&nbsp;</p>\r\n<p>For topping combine all ingredients and then spread it completely over the fusilli.&nbsp; Bake uncovered for 35 to 40 minutes until bubbly and golden brown. Let stand 10 minutes before serving.</p>\r\n<p>Serves 6</p>', '<p>Erika and I quite liked this recipe.&nbsp; Erika said it could have more veggies, so I think I will try that next time.&nbsp; Also, I found the ricotta topping to be a bit stiff upon eating.&nbsp; Perhaps will try leaving out one egg so it is softer.</p>', 11),
(27, 'Marinated Pork Tenderloin', '<p>2 lbs of pork tenderloin, 2 tbsp soya sauce, 2 tbsp white sugar, 1 tbsp sherry, 1/2 tsp cinnamon.&nbsp;</p>', '<p>Blend all seasonings and then rub all over the pork tenderloin.&nbsp; Let stand for 2 hours or leave in the fridge over nite - turning over occassionally to ensure even marinating.&nbsp;</p>\r\n<p>Cook meat slowly under the broiler by putting it on the lowest rack and leaving the door open slightly.&nbsp; Turn over frequently as it cooks.&nbsp; Should take approx 1/2 hour or less.&nbsp;</p>', '<p>Mom always used cooking sherry, but you could always use a dry white wine instead.</p>', 12),
(28, 'Fresh Thai Salad Rolls', '<p>1 pkgrice paper wraps (circles, large size), 1 pkg vermicelli noodles, 4 cloves minced garlic, 2 tbsp veg oil, 1 bunch fresh cilantro, 1 bunch fresh basil, 1 head green leaf lettuce, 2 red peppers, 1 yellow pepper, 1 mango, 1 english cucumber, 1 cup cashews - chopped.&nbsp;</p>\r\n<p>1 cup prepared sweet chili sauce for dipping</p>\r\n<p>2 white dish towels, dampened</p>', '<p>In small fry pan, saute the garlic with veg oil.&nbsp;</p>\r\n<p>Prepare the vermicelli noodles by boiling salted water for 2 to 4 minutes.&nbsp; Strain and place in bowl.&nbsp; Pour fried garlic into the noodles and toss to combine.&nbsp; Set aside.</p>\r\n<p>Julienne (thinly slice) peppers, mango and cucumber and place in seperate bowls to create an assembly line.&nbsp; All should be the length of the peppers - 4 or 5 inches.</p>\r\n<p>Wash and dry all herbs and lettuce, trim stems and seperate leaves of lettuce.&nbsp; Place into seperate bowls.&nbsp;</p>\r\n<p>Set bowl of warm water onto work surface. Lay dampened towel out flat beside the bowl. Lay everything else out to form the assembly line.</p>', '<p>Assembly:&nbsp; immerse a 2 rice paper wraps into the warm water for approx. 1 minute until soft and pliable.&nbsp; Remove fromwater and carefully lay it onto the damp towel.&nbsp;</p>\r\n<p>Starting near the bottom of the soaked wrap, placeone piece of leaf lettuc.&nbsp; Add about 2 tbsp of noodles and desired herbs and veggies.&nbsp; Begin to form wap by rolling up from the bottom, tucking in to form a cylinder, fold in both ends, and continue to roll until sealed.&nbsp; Remove from towel and place onto cutting board.&nbsp; Repeat until the wraps are gone.</p>\r\n<p>Slice diagonally in half and serve on a platter with the chili sauce for dipping.</p>\r\n<p>These are SO good!!&nbsp; I could easily make a meal out of these.&nbsp; They are fairly filling.</p>', 9),
(29, 'Roasted Asparagus Bundles', '<p>1 lb thin sparagus, ends trimmed, 6 slices prosciutto, 2 tbsp xtra virgin olive oil, 1 tsp lemon juice, coarse salt and fresh pepper</p>  Note, you can add halved tomatoes (the ones larger than cherry - but not roma)  lay them on top of the asparagus and wrap it all up with the ham.', '<p>cut proscuitto slices in half lengthwise.&nbsp; Gather 3 asparagus spears and wrap tighty in one half slice of the prosciutto.&nbsp; Continue until you run out.&nbsp; Place bundles on a baking sheet&nbsp; lined with foil.</p>\r\n<p>In a small bowl, whisk together the olive oil and lemon juice.&nbsp; Drizzle over asparagus.&nbsp; Sprinkle with salt and pepper.</p>\r\n<p>Roast in a 400 degree preheated oven for 8 to 10 minutes until prosciutto is crisp and asparagus is tender</p>', '<p>These are very easy and look very elegant on the plate</p>', 8),
(30, 'Chocolate Carmel and Cream Dessert Cake', '<p>1 Duncan Hines Devils Food Cake Mix, 1 can 300 ml condensed milk, 1 pkg 225 g Chipits Skor toffee bits, 1 1/2 cups caramel sundae sauce, 2 cups whipping cream, 1 square sweet chocolate</p>', '<p>Prepare and bake the cake in either a 9 x 13 pan for more casual, or 2 round 8 inch pans for a more formal cake. Cool completely.&nbsp; If using the long pan, cool in the pan.&nbsp; If using the round tins, remove onto rack, then place onto waxed paper when they are cool.&nbsp; Using a wooden spoon handle, poke holes all over - almost going thru.&nbsp; Pour sweetened condensed milk all over&nbsp; slowly and allow to seep thru.&nbsp; Sprinkle with half the skor bits and then pour the carmel sauce all over - again slowly to allow it to seep into the holes.&nbsp; Add more holes if needed.</p>\r\n<p>Whip the cream and either assemble the 2 layer cake using the cream as icing, or just ice the long pan as is.&nbsp; Sprinkle with remaining skor.&nbsp; Grate the chocolate over for a nice finish.&nbsp; Chill until ready to serve.</p>\r\n<p>This tastes better the 2nd day - so make ahead to really get the gooey goodness.</p>', '<p>One of my all time favorites.&nbsp; It can be a bit tricky to get the cake to line up properly if using the 2 layers.&nbsp; Just be careful and use long toothpicks to hold in place if required.&nbsp; Then remove them before cutting and serving. The fridge will make the cake stick together.&nbsp; Another reason to make it one day in advance.</p>', 3),
(31, 'Virginia\'s Truffle', '<p>1 can eagle brand condensed milk, 1 1/2 cup cold water, 1 pkg of 4 serving instant vanilla pudding, 2 cup whipping cream - whipped.&nbsp; 1 pkg pound cake - cubed, 4 cup fruit ( strawberries, blueberries, peaches, raspberries, etc) Keep some for the garnish. 1/2 cup fruit jam any variety but strawberry is good as it has no seeds.&nbsp; Peach or appricot would be nice too - depends on the fruit used., slivered, toasted almonds.</p>', '<p>Combine milk and water.&nbsp; Add pudding.&nbsp; Mix well and chill until set.&nbsp; Fold in whipped cream.</p>\r\n<p>Spoon 2 cups of cream mixture into the bottom of a large pretty clear glass bowl.&nbsp; Top with half the cake, then half the fruit and half the jam then half of the remaining cream.</p>\r\n<p>Repeat ending with cream.&nbsp; Garnish with fruit and almonds.</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>', '<p>This is better if it sits for a while.&nbsp; Good to make the day before.&nbsp; If you like you could always drizzle a tiny bit of your favorite liqueur over the fruit before you add it to the triffle.</p>\r\n<p>A fast and easy dessert.&nbsp; You can buy the frozen pound cakes and that makes it even more simple.</p>', 3),
(32, 'Wacky Cake', '<p>1 1/2 cup of flour, 1 cup gran sugar, 1 tbsp cocoa, 1 tsp baking soda, 1/2 salt, 1 tbsp vinegar, 1 tsp vanilla, 6 tbsp veg oil, 1 cup water.</p>\r\n<p>Frosting:</p>\r\n<p>2 cup icing sugar, 4 tbsp butter, 1 tsp vanilla, 2 tbsp milk</p>', '<p>Preheat oven to 350.&nbsp; Grease a 8 x 8 pan.</p>\r\n<p>Sift dry ingredients into a bowl.&nbsp; This is important to get the lumps out of the cocoa.&nbsp; Then add the wet ingredients.&nbsp; Mix well and pour into the prepared pan.</p>\r\n<p>Bake for 25 to30 minutes.</p>\r\n<p>When cool - apply icing.</p>\r\n<p>This doubles well to make a double layer cake - only the icing recipe will change to 6 cups icing sugar, 1/2 cup butter, 3 tsp vanilla and 6 tbsp milk.</p>', '<p>Great and easy cake for kids to make.&nbsp; No eggs either for those with allergies.</p>', 3),
(33, 'Virginia\'s Apple Pie', '<p>Crumbles for 4 pie crust:&nbsp; Keep in a sealed container in the fridge.&nbsp; 1 lb of Crisco Vegetable Shortening, 7 cups of RobinHood Cake and Pastry Flour, 2 tsps salt.&nbsp; Combine in a large bowl and cut with a knife until crumbly.&nbsp; Or put into a food processor on chop.</p>\r\n<p>3 to 5 large apples - granny smith are our preferred.&nbsp; 1 tsp tapioca, 1 tbsp corn starch, 3/4 cup gran sugar, nutmeg and/or cinnamon to taste</p>\r\n<p>4&nbsp;tsp vinegar, 2 tsp water.&nbsp; These the proportions, may require more for dampening the crumbles for each pie.</p>', '<p>Put approx.&nbsp;4 cups of the crumbles into a bowl.&nbsp; Pour in a bit of the cold water and vinegar mixture.&nbsp; Mix with hand to create a ball - not too wet and not too dry!!&nbsp; Add more water if needed.&nbsp; If it gets too wet, just add more crumbles.&nbsp; Divide into 2 balls.</p>\r\n<p>Put flour on a piece of waxed paper and roll out the dough into circle - large enough to fit the 9 inch pie plate, plus to go up the edges.&nbsp; Carefully roll the dough onto the rolling pin and transfer into the place.&nbsp; Smooth.</p>\r\n<p>Roll out the second ball and place both into the fridge to keep cool while peeling apples, etc.</p>\r\n<p>Peel, core and slice apples thinly.&nbsp; Arrange in pie plate evenly.&nbsp; Sprinkle the tapioca over the fruit.&nbsp; Combine the sugar and corn starch and pour that over the fruit as well.&nbsp; If the apples are very tart - increase the sugar by 1/4 cup.&nbsp; Put pie together.&nbsp; Crimp edges.&nbsp; Cut vents into the top.&nbsp; Put in fridge while you preheat the oven to 450.&nbsp;</p>\r\n<p>Bake pie on mid or just lower rack for 15 minutes.&nbsp; then turn town to 350 for 35 minutes.&nbsp; Check to see if it is brown - could insert a knife into the slit to check tenderness of fruit. If ready - take out and put onto a cooling rack.</p>\r\n<p>&nbsp;</p>', '<p>Gramma makes one of the best pies!!&nbsp; I am not all that fond of the tapioca, so often leave it out. Dislike running into the little balls whilst eating the pie.&nbsp; Really only need it if the fruit is really juicy.&nbsp; Erika not overly fond of cinnamon, so we use combination of nutmeg and cinnamon to flavour.&nbsp; If you have less flavourful apples - ie making pie in the summer -&nbsp;toss the apples with a bit of lemon juice before putting into the crust.&nbsp; Increases the tartness.</p>', 3),
(34, 'Virginia\'s Chocolate Chip Cookies', '<p>1/2 cup butter, 1/4 cup gran sugar, 1/2 cup brown sugar firmly packed, 1/2 tsp vanilla, 1 well beaten egg, 1/2 tsp baking soda, 1/2 tsp salt, 1 1/4 cup pastry flour - sifted, 1/2 cup milk chocolate chippits</p>', '<p>Cream butter, sugars and vanilla.&nbsp; Beat in the egg.&nbsp;</p>\r\n<p>Sift together the flour, soda and salt, add to the dry ingredients.&nbsp; Then add the chippits.</p>\r\n<p>Drop by tsp onto 2 greased baking sheets.&nbsp; Bake at 370 for 8 to 10 minutes.&nbsp; Makes approx 40 cookies</p>', '<p>These are Virg\'s famed cookies that even Erika likes.&nbsp; Although she would prefer them without the chocolate chips.&nbsp; I am sure we could just add white chocolate and macadamian nuts to make her happier.</p>', 13),
(35, 'Gramma Mary\'s Butter Tarts', '<p>1 cup brown sugar, 1 tbsp butter, 1 tsp vanilla, 2 tbsp corn syrup, 2 eggs, raisins enough for 5 raisins per tart.</p>\r\n<p>Makes 12 tarts</p>\r\n<p>Use the crumbles from Virginia\'s pie recipe to make the dough.&nbsp; Enough for a 2 crust pie.</p>', NULL, NULL, 13),
(36, 'Lemon Garlic Tilapia', '<p>8 Tilapia Fillets, 1/4 cup and 2 tbsp fresh lemon juice, 2 tbsp butter - melted, 2 cloved minced garlic,&nbsp; 2 tsp dried parsley.&nbsp; Pepper to taste</p>', '<p>Preheat oven to 375.&nbsp; Spray baking sheet with cooking spray.</p>\r\n<p>Rinse tilapia under cool water and pat dry with paper towels.&nbsp; Place in baking dish.&nbsp; Drizzle lemon juice over then drizzle melted butter over that.&nbsp; Sprinkle with garlic, parsley and pepper.&nbsp;</p>\r\n<p>Bake in oven until flesh is white and flakes easily when pulled with a fork.&nbsp; Approx 10 minutes.</p>', '<p>Tilapia is one of my fav fish.&nbsp; Erika and Scott still eat this with ketchup as the flavour is quite delicate</p>', 14),
(37, 'E and S approved - Chicken Fettuccini Alfredo ', '<p>1 pkg (16 oz) fettuccine, 1 1/2 lbs boneless, skinless chicken breasts cut into strips or cubes, 1 tbsp italian seasoning, 6 garlic cloved, minced - divided, 3 tbsp butter, 1/2 lb sliced fresh mushrooms, 1 medium onion, choped, 1/3 cup all purpose flour,&nbsp; 1 1/2 tsp salt, 1/4 tsp pepper, 3 cups skim milk, 1 cup half and half, 1 1/2 cup shredded Colby-Monterey Jack cheese, 3 plum tomatoes, chopped, 1/2 cup fat reduced sour cream, 1/4 cup plus fresh parmesean cheese.</p>', '<p>Cook fettuccini according to package.&nbsp; Meanwhile in a large skillet over medium heat, cook the chicken, italian seasoning and 2 garlic cloves in 1 tbsp of butter until no longer pink.&nbsp; Remove and keep warm.&nbsp; In the same skillet, saute the mushrooms and onion in the remaining butter until tender, then add the remaining garlic, saute 2 minutes.&nbsp; Stir in the flour, salt and pepper until blended.&nbsp; Gradually add the milk and cream.&nbsp; Bring to a boil, cook and stir for 1 or 2 minutes until thickened.&nbsp;</p>\r\n<p>Add Colby cheese, tomatoes, sour cream, 1/4 cup parmesean cheese and the chicken.&nbsp; Stir until heated thru.</p>\r\n<p>Drain fettuccini and serve with sauce. Sprinkle with parmesan cheese.&nbsp;</p>', '<p>I have made with substituting the butter with olive oil, also substituted the half and half with 2% condensed milk.&nbsp; Just have to watch that the canned milk does not curdle while boiling.</p>', 11),
(38, 'Quattro Stagioni Fusilli', '<p>375 grams of fusilli pasta, 2 tbsp butter, 1 tbsp olive oil, 1 small onion chopped, 1 sweet red or green pepper, seeded and chopped, 2 small zucchini diagonally sliced, 2 cups sliced mushrooms, 1 1/2 cup broccoli florets, 1 cup diced and drained, canned tomatoes, 1 cup chicken stock, 1 cup whipping cream, 1/4 to 1/2 tsp hot pepper flakes, nutmeg, salt and pepper, parmesan cheese.</p>\r\n<p>&nbsp;</p>', '<p>Cook fusilli until just tender.&nbsp; Drain, do not rinse.</p>\r\n<p>In a large skillet, medium heat, heat butter and oil, add onions, sweet pepper, cook till soft. Increase heat to medium high and add zucchini.&nbsp; Cook one minute, add mushrooms and broccoli and cook 2 minutes or until broccoli is a bright color.&nbsp; Add tomatoes and cook 30 seconds.</p>\r\n<p>Add chicken broth, whipping cream, hot pepper flakes and generous pinch of nutmeg.&nbsp; Bring to simmer and cook 2 minutes.&nbsp; Season with salt and pepper to taste.&nbsp; check also for hot pepper taste.&nbsp;</p>\r\n<p>Add drained pasta and toss all together.&nbsp; Serve right away with parmesan cheese.</p>', '<p>Another great pasta dish with lots of veggies.&nbsp; You can always add more veggies to this as well.&nbsp;Chop them to the size that you like - always ensure they fit easily into your mouth with a piece of pasta.</p>', 11),
(39, 'Cheddar Bacon Penne', '<p>6 cups uncooked penne, 1 1/2 cup chopped onion, 1 1/2 tsp minced garlic, 4 tbsp butter, approx 1/4 cup flour, 6 cups of 2% milk, 8 cups of shredded cheddar cheese, 6 strips of bacon, cooked and crumbled.</p>', '<p>Cook pasta according to package.&nbsp; Meanwhie saute the onion and garlic. In another small saucepan, melt butter, stir in flour until smooth.&nbsp; Gradually add milk.&nbsp; Bring to boil and cook for 2 minutes or until thickened to a nice texture for a cheese sauce.&nbsp; Add more milk if too thick, more flour if too thin.&nbsp;</p>\r\n<p>Drain pasta and add to the sauce along with the bacon and onions. Stir to coat evenly.&nbsp; Transfer into large, greased baking dish.&nbsp; Sprinkle with remaining cheese.&nbsp; Bake, uncovered at 350 for 20 to 30 minutes until cheese is melted and bubbling.</p>', '<p>Got this recipe from Debbie.&nbsp; It is definitely a FULL FAT meal!!&nbsp; Delicioius though.</p>', 11),
(40, 'Pasta on Duncan', '<p>2 - 600 gram fresh cheese and spinach ravioli, 4 tbsp olive oil, 2 tsp chopped garlic, 3 small leeks, sliced julienne, 4 cup thinly sliced mushrooms, 3 cups cocoanut milk, 2 1/2 tbsp Dijon Mustard, salt and pepper 2 1/2 cups of parmesan cheese</p>', '<p>Cook pasta.&nbsp; Heat butter in large sauce pan and&nbsp;add garlic.&nbsp; Saute 2 mintutes.&nbsp; Add leeks and muchrooms, cook until tender - can take 15 minutes.&nbsp;</p>\r\n<p>Stir in cream, mustard nd 3/4 cup of cheese.&nbsp; Heat to coiling.&nbsp; Stir in cooked tortellini, season with salt and pepper.&nbsp;</p>\r\n<p>Place in shallow baking dish, top with 1 1/2 cups of parm cheese and broil until golden brown.</p>', '<p>This is incredibly rich - filling.&nbsp; Serve with only a green salad to cut the creaminess of the meal.&nbsp; And of course - wine!!</p>', 11),
(41, 'Magic Chocolate Toffee Bars', '<p>1 1/2 cup chipits semi sweet chips, 3/4 cups flaked coconut, 3/4 cup skor toffee bits, 1/2 cup sliverd almonds, 1 1/2 cup all purpose flour, 1/3 cup gan sugar, 3/4 cup butter, 1 can 300 ml eagle brand condensed milk</p>', '<p>Preheat oven to 350.&nbsp; Spreay a 13 x 9 pan.&nbsp; Combine chippits, coconut, Skor and almonds.&nbsp; set aside.</p>\r\n<p>Combine flour and sugar.&nbsp; Cut in butter until mixture is crumbly.&nbsp; Press firmly into greased pan.&nbsp; Bake at 350 for 12 minutes or until light golden.</p>\r\n<p>Pour Eagle Brand milk evenly over the crust - while still warm.&nbsp; Sprinkle with chip mixtrue and press down firmly.&nbsp; Bake 25 to 30 minutes or until lightly browned.&nbsp; Cool and cut into bars.&nbsp;</p>', '<p>One of those recipes that always go over very well at football parties, etc.</p>', 13),
(42, 'Gramma Mary\'s Meatballs', '<p>First - purchase a box of frozen meatballs.&nbsp; You could make them, but why??</p>\r\n<p>Sauce:&nbsp; 1/4 cup brown sugar, 1 tsp dry mustard, 1/2 cup chili sauce (like ketchup but a bit spicier) 1/2 cup grape jelly, 1 tbsp worcestershire sauce, 1/4 tsp tobasco sauce, 1 onion finely chopped, 1/2 cup ketchup, 1/2 cup water, 1/4 cup cider vinegar.</p>', '<p>Combine all of the above.&nbsp; Simmer 10 minutes and then add meatballs.&nbsp; Simmer another 15 minutes.</p>\r\n<p>&nbsp;</p>', '<p>This makes goodly amount of sauce to have over rice.&nbsp; But it doubles very nicely and you can put excess in the freezer for emergencies.&nbsp; If you do double, just take out a bit of the vinegar as it can be too much as a double.</p>\r\n<p>Note, use only cider vinegar or rice vinegar.&nbsp; Anything else is too strong.&nbsp;</p>', 12),
(43, 'Creamy Pork Tenderloin', '<p>1/2 tsp freshly ground black pepper (or steak seasoning), 1.5 lbs pork tenderloin, 4 tbsp butter, 6 tbsp brandy, 1 cup whipping cream (or one can 1% evaporated milk), 2 tbsp Dijon mustard, 1/2 tsp salt (only if not using steak seasoning), double pinch of thyme, rosemary and marjoram</p>', '<p>Press pepper into meat with fingertips. Heat butter in a frying pan just large enough to hold the pork.&nbsp; Medium high heat.&nbsp; Brown pork on all sides. Reduce heat to low.</p>\r\n<p>Pour brandy all over the pork.&nbsp; Stir in the remaining ingredients.&nbsp; Mix well.&nbsp; Cover and cook 20 to 25 minutes(internal temp of 145 or so) .&nbsp; Remove pork.&nbsp; Slice onto a serving platter.&nbsp; Pour sauce over top.&nbsp;</p>\r\n<p>Should serve 6</p>', '<p>This is a great reliable recipe for a simple dinner.&nbsp; Serve with simple vegetables ie sauted mushrooms, roasted asparagus.&nbsp; Sauce is great over small potatoes as well.</p>', 12),
(44, 'Pork Chops with Apples and Raisins', '<p>4 bone-in pork chops ( I use pork loin instead), 1 tsp dried thyme, 1/2 tsp sage, 1/2 tsp salt, 1/4 tsp pepper, 3 tbsp all purpose flour, 2 tbsp olive oil, 2 royal gala apples, cored and sliced.&nbsp; 1 onion thinly sliced. 1 large clove of garlic, minced.&nbsp;&nbsp; 1 1/2 cup apple cider or juice.&nbsp; 1/4 cup raisins (optional), 2 tbsp choped fresh parsley.</p>', '<p>Place pork chops on a plate and sprinkle both sides with half the thyme, sage, salt and pepper.&nbsp; Dredge each chop in flour to coat, shaking to remove excess.&nbsp; Reserve remaining flour.</p>\r\n<p>In a large non-stick fry pan, heat oil over medium high heat and brown pork chops well on both sides.&nbsp; Remove and keep war, Then cook apples, onion and garlic plus remaining thyme for about 8 minutes or until softened..&nbsp; Add cider and bring to a boil - raisins too.&nbsp; stir occassionally. Rturn chops to skillet and turn to coat.&nbsp; Simmer for 5 minutes or until the pork is has just a hint of pink.&nbsp; Sprinkle with parsley and plate.</p>', '<p>I double up on the apples and onions and sauce&nbsp;as everyone likes lots of them.&nbsp; As I use pork loin instead, I just coat the outside and brown as one piece.&nbsp; It is just so much more tender than a pork chop.</p>  I also don\'t use raisins as I dislike them.', 12),
(45, 'Sticky Chicken Wings', '<p>enough chicken wings to feed a family of 4.&nbsp; 1 cup brown sugar, 6 tbsp soya sauce, 1.5 cups water, 3 cloves of garlic, 1/2 tsp dried ginger, salt and pepper.</p>', '<p>Lay wings in strong baking pan.&nbsp; Large enough, ideally so that they lie in single layer.&nbsp; Combine all other ingredients and pour over the chicken.&nbsp;</p>\r\n<p>Bake in 350 oven for 1.5 hours - approx.&nbsp; This seems to always vary.</p>.\r\nKeep stirring to be sure the wings are coated well.  Stop when the sauce is the thickness you like.', '<p>Note, you can never have too much sauce, but the more you make, the longer it will take to get the sauce thickened enough.</p>\r\n<p>If you want to cut the fat, then bake the wings naked, drain the fat and then add the sauce.</p>', 10),
(46, 'Curry Chicken for 6', '6 boneless, skinless single chicken breasts.&nbsp; 1/2 cup flour, 2tbsp curry powder, dash ginger, paprika, salt and pepper, 2 cups of chicken broth, 1 can coconut milk - low fat or otherwise, 3 granny smith (green) apples cut into bite size pieces, 1 large onion, chopped. , 1 cup flaked cocoanut (sweetened)\r\n\r\nAmount of curry is very individual. I like it quite hot (I use probably 3 or 4 more tablespoons), so keep taste testing as you add more than above; Takes about 5 minutes for the curry to release its flavour, so add slowly in batches to not overwhelm.\r\nAlso, curry spice gets old quickly so, buy a little bit at a time ;so you don\'t have to throw stuff out.\r\n\r\nRice to serve with', '<p>Heat large skillet with 2 tsp oil.; Combine flour and spices in a plastic bag.; Toss breasts in to evenly coat - one at a time.; Place in skillet single layer; Cook 3 minutes to brown, then turn over. Cover tightly.  Turn heat down and cook slowly for 10 - 15 minutes until no longer pink; Remove and set aside. Keep warm.\r\nAdd more oil and saute onions for 5 minutes, add apples and cook additional 3 minutes. Stir Add coconut for 2 more minutes.; Add the flour mixtrure and brown 1 minute.  stir; Then add the broth.; Stir to make smooth.; Add cocoanut milk and keep stirring.; Bring to simmer until nicely thickened; Add more curry to increase spicy-ness.</p>\r\n<p>Meanwhile, cut/shred  the chicken and into bite sized pieces. Return to the pan; Stir to coat evenly..\r\nKeep taste testing for spice levels.&nbsp; Serve over rice.</p>', 'peas are traditional as a side dish with curry.', 10);
INSERT INTO `recipe` (`recipeID`, `recipe_title`, `recipe_ingredients`, `recipe_method`, `recipe_note`, `catID`) VALUES
(47, 'Scott\'s fav stir fry', '<p>Sauce:&nbsp; 3/4 cup beef or chicken stock, 1/4 cup packed brown sugar, 2 tbsp low sodium soy sauce, 2 tbsp rice wine vinegar, 2 tsp sesame oil, 1 tbsp cornstarch, 2 tsp minced garlic,&nbsp; 1 1/2 tsp minced gingerroot.</p>\r\n<p>Stir fry:&nbsp; 12 oz boneless grilling steak - whole, uncut!!, 2 tsp veg oil, 1 1/2 cup chopped broccoli, 1 1/2 cup thinly sliced red peppers, 1 1/2 cups snow peas.</p>\r\n<p>Garnish:&nbsp; 1/4 cup fresh chopped corriander or parsley, 1/4 cup chopped fresh onion, 2 tbsp chopped toasted cashews</p>', '<p>Sauce:&nbsp; in a bowl, mix all ingredients until smooth.</p>\r\n<p>Stir fry:&nbsp; in a large non stick sillet sprayed with cooking oil, cook beef on high heat for 3 minutes until browned, ut still rare. Let rest for 5 minutes.&nbsp; Slice thinly.&nbsp; Key to not slice before cooking!!</p>\r\n<p>Respray pan, add oil, broccoli peppers, and snow peas, cook for 2 minutes.&nbsp; Add beef back to pan.&nbsp; After stirring sauce, add to pan and coor for 2 minutes, stirring constantly or until sauce is thickened and bubby and beef is medium or to your liking.&nbsp; Careful - do not over cook.&nbsp; Garnish witih above as you like.</p>\r\n<p>Note:&nbsp; Corriander is not a favorite in our house, so I usually use parsley.</p>', '<p>This is a Rosie Reisman recipe.&nbsp; I think she is a genius.&nbsp; The only thing is that I usually use the regular soy sauce just for the extra taste.</p>\r\n<p>Needless to say, you can switch out the beef for chicken as well as change out any of the veggies.</p>', 4),
(50, 'Creamy Baked Beefaroni', '1 lb rotin\r\nMeat Sauce; 1 tsp veg oil, 1 cup chopped onions, 2 tsp minced garlic, 12oz lean ground beef (or turkey - or ground soy), 1 3/4 cups tomato pasta sauce, 1/2 cup beef or chicken broth.\r\nCheese Sauce: 1/4 cup all purpose flour, 2 cups 2% milk, 1 1/2&nbsp; cups beef or chicken stock, 1 cup shredded Old Cheddar - it is lower fat and sharper taste.\r\nTopping: 1/2 cup shredded low-fat Mozzarella cheese, 2 tbsp parmesan cheese', '1. Preheat oven to 450. Spray a 13 x 9 glass baking dish with cooking spray.\r\n2.Cook noodles as instructed until tender but firm.Drain.\r\n3.Meat Sauce: heat oil over medium hat and cook onions for 4 minutes or until softened.   Add garlic for another minute.  Stir in beef, cook stirring to break up for 4 minutes until no longer pink. Drain any fat.  Stir in tomato sauce and stock. Cover and cook for 10 minutes or until thickened. Set aside.\r\n4.Cheese sauce.In a nonstick pan, whisk together the flour, milk and stock until flour dissolves.  Place over medium heat and simmer until it starts to boil. Reduce hat to low and cook stirring occassionally for 5 minutes or until thickened.  Stir in Cheddar and remove from heat. Add into the meat sauce.\r\n5.Toss pasta with sauce and our into prepared dish.  Sprinkle with topping.\r\n6. Bake in 450 oven for 10 minutes or until bubbly', 'Another Rose Reisman recipe. Kid and Al approved. I find it needs salt after plating.', 11),
(51, 'cauliflour puree with mushroom compote', '1/2 cup peeled, diced yukon gold potatoes, 3 cloves minced garlic, 1/2 cup cream or milk. cups see notes, \r\n1.5 llb cauliflour cut chunked (6 cups) salt, peper,\r\nsour cream/butter/herbs...  as per mashed potatoes\r\n\r\nCompote: 3 tbsp olive oil, 1/4 cup chopped shallots (green onion works as well), 1 tsp chopped garlic, 1 1/2 lbs mixed mushrooms halved or quartered, 2 tsp chopped thyme, salt, pepper, 1/4 cup red wine, 2 cups low sodium beef or chicken stock, 1/4 cup cubed butter, 2 tbsp chopped parsley, 6 slices baked bacon (optional)</p>', '1 place potatoes, cauliflower and garlic in microwaveable dish.  cover.  microwave on high until all is tender.  Drain well then mash.    Add whipping cream/ milk until desired consistency.    .Season with s and p/ sour cream/butter.  Treat like mashed potatoes.\r\n\r\n\r\nPlace oil in large skillet over high heat.&nbsp; Add shallots and garlic and saute 30 seconds.&nbsp; Add mushrooms and thyme and saute for 4 mins or until mushrooms lose their juices.; Season with s and p. Remove from skillet - reserving fluid in the pan.\r\nAd wine to pan and bring to boil. Ad stock and reduce for 5 minutes until thickens slightly; Stir in mushrooms until coated.; Adjust seasoning and add parsley. To serve, place puree in soup bowl, top with mushrooms and if you choose - garnish with bacon.', 'You don\'t have to use a potato.  Just make sure the cauliflower is well drained.  then slowly add some of the reserved milk and garlic to get the consistency you like.\r\nI only use the cream if it is for company.  Otherwise, I skip it and just use skim milk in the post to boil the veg and then that reserved garlic milk and very little of it, to blend, as cauliflower is quite wet.  \r\n', 8),
(53, 'Candied yams', 'Maple-Glazed Yams with Pecan Topping Recipe\r\nINGREDIENTS\r\n4 lbs of yams (red-skinned sweet potatoes), peeled, cut into 1/4 inch rounds\r\n1/2 cup pure maple syrup\r\n8 Tbsp (1 stick) chilled butter, cut into 1/2 inch pieces\r\n1/3 cup all purpose flour\r\n1/3 cup packed brown sugar\r\n1/2 cup coarsely chopped pecans\r\n\r\n', '1 Preheat oven to 400°F. Butter a 13x9x2 inch glass baking dish. Bring a large pot of salted water to boil. Add yams. Cook until water returns to a simmer, about 4 minutes. Drain; rinse in cold water.\r\n2 Arrange yams in baking dish, overlapping pieces. Sprinkle with salt. Pour maple syrup over yams. Dot with 3 Tbsp of butter. Cover with aluminum foil and bake until yams are almost tender, about 25 minutes.\r\n3 Mix flour and brown sugar in a medium bowl. Add remaining 5 Tbsp of butter. Rub in with fingers until mixture resembles a coarse meal. Mix in pecans.\r\n4 Sprinkle pecan mixture over yams. Bake yams until tender, about 20 minutes.\r\nServes 12.\r\n', NULL, 8),
(54, 'Baklava', '1 (16 ounce) package phyllo dough\r\n1 lb chopped pistachios or walnuts or almonds whatever you prefer.  Toast if you are not sure they are fresh.\r\n1 cup butter melted - for brushing or spraying onto phylo\r\n1 teaspoon ground cinnamon\r\n\r\nSauce - make this first so you can put it into the fridge to cool\r\n2 cups water\r\n2 cups white sugar\r\n2 teaspoon vanilla extract\r\n1 cup honey\r\n', 'Preheat oven to 325 degrees F(175 degrees C). Butter the bottoms and sides of a 9x13 inch pan.\r\nChop nuts and toss with cinnamon. Set aside. Unroll phyllo dough. Cut whole stack in half to fit pan. Cover phyllo with a dampened cloth to keep from drying out as you work. Place two sheets of dough in pan, spray or brush lightly with melted butter. Repeat until you have 8 sheets layered. Sprinkle 2 - 3 tablespoons of nut mixture on top. Top with two sheets of dough, butter, nuts, layering as you go. The top layer should be about 6 - 8 sheets deep.\r\nUsing a sharp knife cut into diamond or square shapes almost - leave 1/4 inch uncut so the sauce does not pool in the bottom. Bake for about 50 minutes until baklava is golden and crisp.\r\nMake sauce while baklava is baking. Boil sugar and water until sugar is melted. Add vanilla and honey. Simmer for about 20 minutes then put into the fridge to cool\r\nRemove baklava from oven and immediately spoon sauce over it. Let cool. Serve in cupcake papers. This freezes well. Leave it uncovered as it gets soggy if it is wrapped up.', 'Make sure the sauce is cooled before pouring over so it crisps up the baklava.  I got this recipe from the Allrecipes website.  Delicious!!  Best if you let it sit overnight.', 13),
(55, 'Baked Coconut Shrimp', '1 pound large shrimp, peeled and deveined\r\n1/3 cup cornstarch\r\n1 teaspoon salt\r\n3/4 teaspoon cayenne pepper\r\n2 cups flaked sweetened coconut\r\n3 egg whites, beaten until foamy\r\nDirections\r\n\r\n', 'Preheat an oven to 400 degrees F (200 degrees C). Lightly coat a baking sheet with cooking spray.\r\nRinse and dry shrimp with paper towels. Mix cornstarch, salt, and cayenne pepper in a shallow bow; pour coconut flakes in a separate shallow bowl. Working with one shrimp at a time, dredge it in the cornstarch mixture, then dip it in the egg white, and roll it in the coconut, making sure to coat the shrimp well. Place on the prepared baking sheet, and repeat with the remaining shrimp.\r\nBake the shrimp until they are bright pink on the outside and the meat is no longer transparent in the center and the coconut is browned, 15 to 20 minutes, flipping the shrimp halfway through.\r\n', 'I found a copy-cat recipe on-line for Outback\'s sauce that they serve with these - 1/2 cup orange marmalade, 2 dijon mustard, 1 teaspoon prepared horseradish and a dash of salt', 14),
(56, 'Home make baking powder', '1/4 cup cream of tarter\r\n\r\n2 tablespoons baking soda\r\n\r\nSift all of the ingredients together 3 times, and transfer to a clean, tight-sealing jar. Store at room temperature, away from sunlight, for up to 6 weeks.\r\nUse the same amount of this recipe in place of commercial baking powder.', NULL, NULL, 15),
(57, 'Krispy Kreme Doughnut Bread Pudding', '2 1/2 cups half & half cream\r\n3 large eggs\r\n1/3 cup white sugar***. MAYBE use less so it is not as sweet?\r\n1/4 cup Jack Daniels, optional\r\n3/4  teaspoon ground cinnamon\r\n1/4 teaspoon freshly ground nutmeg\r\n8 Krispy Kreme honey glazed donuts cut into 1 inch pieces\r\n\r\n', 'Preheat oven to 350 degrees.\r\nButter/spray oil a 2 1/2 quart souffle dish. - large corning ware dish\r\nWhisk eggs, half & half, sugar, J Daniels, cinnamon, nutmeg & salt until mixed well.\r\nAdd the donuts and press down so that it absorbs the liquid, let sit for about 5 minutes.\r\nPour the mixture into the prepared dish and bake for 40-50 minutes. It will be softish in the center.\r\nServe right away, with a side of fresh fruit along with whipped cream, vanilla ice cream or a touch of heavy cream to pour over.', 'I had to try this when I read it in a novel.  Wow.  If you want you can make a easy glaze to drizzle over:  1/2 cup icing sugar and 1 tbsp real maple syrup.  Go easy tho - this pudding is very sweet.', 7),
(58, 'Erika\'s fav peanut butter oat squares', 'Parchment lined 9 x 13 pan - very important\r\n\r\n1/2 cup butter, softened\r\n1 cup brown sugar - packed\r\n1/2 cup corn syrup - or liquid honey\r\n1/2 tsp salt\r\n2 tsp vanilla\r\n3 cups rapid cook oats large or small flake\r\n\r\nTOP\r\n3/4 to 1 cup smooth peanut butter\r\n1 1/2 tsp butter\r\n1/2 cup semi sweet choc chips or 3 baking squares', 'Cream butter and brown sugar.  Add corn syrup, salt, vanilla and oats.  Mix well.  Press mixture evenly into a greased 13 x 9 cake pan.  Bake at 350 for 12 to 15 minutes.  Cool 10 minutes.\r\n\r\nSpread peanut butter evenly on top.\r\n\r\nMelt chocolate and butter together until smooth.  Drizzle and spread over PB.   Cool to set chocolate then cut into squares\r\n', 'Definitely a square that you want to use parchment paper to line the dish - otherwise it is VERY difficult to get it out of the pan.  Spray one side of the paper and press that side into the dish - it holds the paper in place.  \r\nMelt the chocolate on low heat in the microwave for 20 sec. then stir well.  Keep on if required, but keep heating down to the minimum or it will bloom and change taste and texture.  \r\n\r\nImportant to cook the base thoroughly or it is just too sticky on the bottom when cool.  ', 13),
(59, 'Sausage and Swiss Chard Rigatoni', '4 tsp olive oil\r\n5 smaller italian sausages casings removed ( l use hot)\r\n3 cloves of garlic minced\r\n1/2 tsp hot pepper flakes ( I use less as I used hot sausage)\r\n1.5 cans (28oz/796ml) diced tomatoes\r\n1/4 cup chopped fresh basil - if you use dried - use 1/8 cup\r\n1/4 tsp salt\r\npinch white sugar\r\n1 can rinsed, drained, canned navy beans (just use your favorite variety)\r\n5 cups mezzi rigatoni - I used whole wheat fusilli\r\n8 cups chopped Swiss Chard (generally one bunch) - DO NOT USE SPINACH!!\r\n2/3 cups shredded motzzarella cheese\r\n1/4 cup grated parmesan cheese', '1.  In a large skillet, heat oil over medium high heat.  Saute sausage breaking up with a spoon until browned.  About 8 minutes.  Stir in garlic and hot peppers. Cook 2 minutes\r\n\r\n2.  Add tomatoes, basil, salt and sugar.  Bring to boil.  Reduce heat and simmer for 20 minutes.  Stir in beans.\r\n\r\n3. Meanwhile, in a large pot of boiling water, cook pasta until still slightly firm in the centre - aprox 8 minutes.  Drain and return to the pot, reserving 1/2 cup of the cooking water.  To the noodles, add the sauce, the reserved cooking water and swiss chard.  Toss to coat and transfer to 10 cup glass baking dish ( 13 x 15). \r\n\r\n4.  Sprinkle with mozzarella and parmasan cheese.  Cover with greased foil.  \r\n\r\n5.  Bake in 375 degree oven for 20 minutes.  Uncover and bake until bubbly and browned.  Approx 10 minutes.  ', 'Makes 6 servings.  Very healthy meal with the swiss chard.  Don\'t make the mistake f using spinach.  It has a different taste.  Swiss chard is much more mellow.  Scott quite likes this recipe.  ', 11),
(60, 'Chicken Milano', '1 cup buttermilk (or 1 cup milk and 1 tsp lemon juice or white vinegar - let it sit for 1/2 hour room temperature before using)\r\n1 tablespoon olive oil\r\n1 tsp salt\r\n1 tsp paprika\r\n2 cloves garlic, minced\r\n1 cup sun-dried tomatoes, chopped\r\n1 cup chicken broth\r\n1 cup white wine\r\n1 cup heavy cream\r\n1 pound skinless, boneless chicken breast halves\r\nsalt and pepper to taste\r\n2 tablespoons vegetable oil\r\n4 tablespoons chopped fresh basil - or use 3 tbsp dried\r\n8 ounces dry pasta - I like ww fusilli\r\n', 'Directions\r\n\r\nMarinate the chicken in the buttermilk for 3 to 8 hours.  When ready to begin, drain and pat dry.\r\n\r\nCut the chicken breasts into fingerlings.  Season with salt and sprinkle with paprika.  Set aside.\r\n\r\nIn a large saucepan over medium heat, heat oil; Add the mushrooms and stir for approx 3 minutes. Add garlic and cook for 30 seconds. Add the chicken and turn the pieces to brown on all sides.  No need to cook them - just to get some color (paprinka helps with that).  Remove the chicken and keep warm.\r\n\r\nAdd the tomatoes, wine and chicken broth to mushrooms; bring to a boil. Reduce heat and simmer, uncovered, for about 10 minutes or until the tomatoes are tender. Add the cream and bring to a boil; stirring. Simmer over low to medium heat until the sauce is thick enough to coat the back of a spoon.  If it is not thick enough for you, in a separate cup, mix the corn starch with a spoon of cool milk or cream.  When smooth, add to the cream sauce and let it simmer for a few minutes.  You can add more cool starch if required.  Your choice.\r\n\r\nMeanwhile, bring a large pot of lightly salted water to a boil. Add noodles and cook for 8 to 10 minutes or until al dente; drain, transfer to a bowl and toss with 3 to 4 tablespoons of the sauce.\r\n\r\nTransfer the pasta to serving plates; top with chicken and coat with the cream sauce; serve.  Or keep them separate and plate the food for each.  It is easier to store.  That way the noodles do not soak up the sauce too much while in the fridge.', 'Best to plate the food yourself otherwise when you put the left overs into the fridge, the noodles will soak up all the sauce and it will become dry.  Or to serve for a larger party - spread the noodles on a large platter.  Scatter the chicken over it and then pour the sauce over all of it.  Could sprinkle with extra basil for garnish.  \r\n\r\nScott added some parmesan cheese to his and said it tasted good.  Even liked the left overs!!', 10),
(61, 'Easy Cinnamon Buns from a magazine', 'store bought pizza dough\r\n1/4 cup softened butter\r\n1/2 cup brown sugar\r\n2 tsp cinnamon', 'Roll out the pizza dough to 1/4 inch thickness\r\nspread the butter over the dough leaving 1/2 inch border all around.   Sprinkle with the sugar and the cinnamon.\r\n\r\nGrease a pie pan.  Roll up the dough from the long side.  Cut into 2 inch buns and snuggle into the pan.  Sprinkle with additional sugar if you like', NULL, 7),
(62, 'asparagus wrapped in prosuitto', 'asparasus, proscuitto, very sharp cheddar cheese, oil', 'blanche asparagus until tender.  remove and cool to room temp.  wrap 3  pieces of asparagus with a piece of proscuitto, fry in sauce pan turning until brown all sides.  remove. Plate with other items and sprinkle with a sharp, rich cheddar along with crackers and olives and fruit.   ', 'This looks great on a long white platter.  A beer infused cheddar is fantastic with this with grapes or tart apples.', 9),
(63, 'Individual Beef Wellington - can be made the day before', '6 Beef Tenderloin Steaks\r\nDuck Liver Pate\r\nMushroom Compote (from cauliflour recipe in Veg section)\r\n1 large pkg of puff pastry\r\n1 egg', 'Make the Mushroom compote - ahead of time - reheat when needed\r\nRoast or BBQ the steaks to rare and let sit.  Cool 1 hour or longer.  \r\nRoll out the puff pastry and make 6 squares large enough to wrap completely around each steak.\r\nFor each serving - place a couple table spoons of the mushroom compote in the middle of the square.  Add a steak on top of that and then a table spoon or so of the pate.  Spread over the steak.\r\nFold up 2 corners of the pastry over each steak.  Brush with beat egg wash to seal.  Then pull up the other 2 corners and seal again with egg wash.  Put in fridge for up to one day.  1 hour before ready to serve...  Put sealed steaks on a baking sheet (parchment paper on it) Warm to room temperature.   Brush with more egg wash to get the nice gold color.  Roast for 10 or so minutes until the pastry is nice and golden.\r\nServe with veggies of choice.  If there is extra compote, serve in a dish alongside.  \r\n', 'the cauliflour recipe goes great with this and with roasted carrots (leave a bit of the stem on)  roasted with Balsamic vinegar and olive oil sprinkled on ( 20 - 25 minutes)  So easy and guests are blown away by it.  Most people can\'t get over the cauliflour!!', 12),
(64, 'Ravioli Lasagna with Sausage and Mushrooms', '1 tbsp olive oil\r\n1 medium onion - diced\r\n2 cloves garlic - minced\r\n500 g turkey sausage (or italian whatever you like) - thinly sliced on a diagonal (casings on or off)\r\n796 ml can crushed tomatoes\r\n1 tsp dried oregano leaves\r\n1 can 2% carnation evaporated milk - or 1 cup homo milk\r\n220 g sliced mushrooms\r\n700 g pkg fresh ravioli - preferably spinach and cheese - preferably whole wheat pasta\r\n1 cup grated mozzarella cheese', 'Preheat oven to 350\r\nHeat large pot over medium heat.  Add oil, then onion and garlic.  Cook until onion is soft - about 3 minutes.  Add slices of sausage and cook till no longer pink.  Add tomatoes and oregano.  Season with freshpepper.  Stir in the milk until combined.   Set aside 1 cup of the sauce.  Add mushrooms and ravioli to pot.  Stir to coat.  Pour into a 9 x 13 in baking dish.  Push ravioli down evenly.  Pour reserved sauce over top then sprinkle with mozz.  Bake uncovered until raviloi are cooked through and cheese is melted - approx 20.', 'From Chatelaine Feb. 2011.  Note that the original recipe calls for 1/2 cup whipping cream and 1/2 cup milk.....  but I prefer this lighter recipe for health reasons. Also calls for the sausage to be removed from the casings and mashed and cooked like ground beef.  I prefer the meat sliced as it gives it a different texture.\r\n\r\nI think I like this better than regular lasagna and it is a lot less time consuming and lighter tasting.', 11),
(65, 'Lentil, Kale and Sausage Soup', '2 tbsp olive oil\r\n2 turkey sausages thinly sliced on diagonal - not too big- easy to fit into your mouth - but not diced - too rubbery that way.\r\n1 large onion - finely chopped\r\n1 leek (white part only) sliced\r\n2 carrots, diced\r\n2 garlic cloves - minced\r\n156 ml can tomato paste\r\n1 tsp ground coriander ( I prefer parsley)\r\n1 tsp salt\r\n8 cups chopped kale leaves (about 1 small bunch) - or swiss chard is good too\r\n540 ml can lentils, rinsed and drained\r\ngrated parmesan cheese (optional)\r\n\r\n', 'Heat large, wide sauce pan over medium.  Add oil then sausages.  Cook fully. Remove to plate.  Add onion, leek, carrots and garlic to pan.  Cook about 3 minutes.  Stir in tomato paste, coriander (parsley),salt, sausages and any juices from sausages.  Continue to cook, stirring frequently until flavour develops - approx 5 minutes.  Pour in 4 cups water.  Bring to a boil. Stir in Kale.  Stir 2 to 3 minutes until Kale is tender.  Stir in lentils and heat 1 minute.  If soup is too thick, add more water.  Ladle into bowls and sprinkle with cheese.  Serve immed.', 'A very healthy soup and filling with the sausage and lentils.  The dark green kale/swiss chard is filled with vitamins.', 5),
(66, '5 spice stir fry', '\r\n1/4 cup dry sherry or rice wine\r\n1/4 cup soy sauce - divided\r\n1 teaspoon packed dark brown sugar\r\n2 tablespoons cornstarch - divided\r\n1 pound pork tenderloin or 3 chicken breasts\r\n1/2 teaspoon five-spice powder\r\n3 tablespoons veg oil - divided\r\n4  cups chopped fresh veggies - your choice\r\n1 tablespoon minced garlic\r\n1 tablespoon grated ginger\r\n\r\nSteamed white rice, for serving (optional)', 'TIME/SERVINGS\r\nTotal Time: 25 mins\r\nMakes: 4 servings\r\n\r\nINSTRUCTIONS\r\n\r\nPlace the sherry or rice wine, 3 tablespoons of the soy sauce, the brown sugar, and 1 tablespoon of the cornstarch in a small bowl and whisk to combine; set aside.\r\nSlice the pork against the grain into even, paper-thin pieces and place in a large bowl. (It doesn’t matter how wide the slices are as long as they are even in thickness.) Add the remaining 1 tablespoon soy sauce, the remaining 1 tablespoon cornstarch, the five-spice powder, and 1 tablespoon of the oil and toss to evenly coat the pork. Set aside to marinate for 5 to 10 minutes.\r\n\r\nIn a large frying pan with a tightfitting lid, heat the remaining 2 tablespoons oil over medium-high heat. When the oil just begins to smoke, add the pork and cook, stirring rarely, until browned and almost completely cooked through, about 2 minutes. Don\'t worry if the meat sticks to the pan.  When you do the veggies all the crispy stuff comes up and is part of the dinner.  Remove to a plate and set aside.\r\n\r\nReduce the heat to medium and add the veggies.  Stir fry until tender crisp.\r\n\r\nWhisk the reserved soy sauce mixture again until evenly combined and add it to the pan along with the reserved pork and any accumulated juices. Cook, stirring continuously, until the sauce has thickened and the pork is cooked through, about 30 seconds. ', 'This is very tasty - healthy alternative to terriyaki - very little sugar.  Note I used the regular - not lite - soya - so more salt.', 4),
(67, 'Sweet and Spicy Cashew Chicken', '1/2 cup chicken broth\r\n3 tbsp oyster sauce\r\n1 tbsp white sugar\r\n1 tbsp cornstarch\r\n1 tbsp white vinegar\r\n2 tbsp vegetable oil\r\n1 lb boneless chicken breast - cut into chunks\r\n1/4 each salt and pepper\r\n2 sweet red peppers - chopped\r\n2 onions, chopped\r\n1 tsp thai chili paste - hard to find****\r\n1/2 cup roasted unsalted cashews\r\n3 green onions - chopped\r\n', 'Whisk first 5 ingredients.  Set aside\r\nIn wok heat half the oil over med/high heat.  Stir fry chicken, salt and pepper until golden - approx 4 minutes.  It will still be a pink inside.  Remove and save.\r\nAdd remaining oil to wok.  Stir fry next 3 ingredients for 3 minutes.  Return chicken and any juices.  Stir fry until chicken is no longer pink inside\r\nAdd cornstarch mixture and move around for 1 minute.\r\nAdd cashews and green onions, stir for 1 minute.\r\n\r\nServe with rice.', 'Thai Chili paste adds heat and garlic.  So you could just use garlic sauted earlier and add a few red pepper flakes.\r\n\r\nThis is supposed to serve 4 - but serves 3 Donalds!!', 10),
(68, 'Sweet and Spicy Scallops and Bok Choy', '8 baby bok choy - quartered\r\n16 sea scallops\r\n1/8 tsp salt\r\n4 tsp butter\r\n1/2 Thai sweet chili sauce\r\n1 tbsp rice-wine vinegar', 'Heat large frying pan  over medium high heat.  When hot spray with oil.  Add bok choy. The pan will be full, but it will cook down.  Cook until tender crisp...3 minutes or so.  Remove to platter and foil up to keep warm.  Meanwhile, pat scallops dry and sprinkle with salt and pepper.\r\nMelt butter over medium.  Add scallops, cooking in 2 batches if necessary.  Cook 2 minutes and flip. Cook 2 more minutes. If the butter darkens turn heat down a bit.  \r\nRemove scallops to seperate plate and keep warm\r\nAdd chili sauce, 1/4 water and vinegar to pan.  Boil, stirring until slightly thickened - 2 minutes.  P\r\nPut scallops onto boy choy then pour sauce over all.  \r\n\r\nServe with rice\r\n', 'A bit bland, so could do with a bit of red pepper flakes', 14),
(69, 'Tomato, Sausage and Bean Soup', '4 tsp veg oil\r\n1 onion, finely chopped\r\n1 each carrot and rib celery, finely chopped\r\n2 cloves garlic, minced\r\n1/4 tsp each salt and pepper\r\n2 hot italian sausages - casings removed**\r\n2 cans (28 oz each) whole tomatoes\r\n1 can navy beans drained and rinsed ***\r\n1 cup chicken broth\r\n1 cup water\r\n1/3 chopped fresh oregano\r\n1 tsp granulated sugar\r\n', 'In a large pot, heat oil over medium heat, cook first first 5 items - stirring until softened - 6 minutes\r\nIncrease heat to medium heat.  Add sausages and saute for 5 minutes, breaking up with a spoon to bites.\r\nStir in tomatoes, breaking up with a spoon.  Add next 5 ingredients.  Bring to boil then reduce heat and simmer until thickened... 15 or so minutes. ', 'Serves 6\r\nIf you prefer - use sweet sausages and add a bit of red pepper flakes -to taste.\r\nBeans - you can use anything you have on hand including lentils.', 5),
(70, 'Green Bean Casserole', '1 1/2 tbsp butter\r\n3 tbsp all purpose flour\r\n1 1/2 cup milk\r\n3 to 4 tsps dry ranch style salad dressing mix\r\n1/4 to 1/2 tsp pepper\r\n1 cup chopped onion\r\n2 cloves garlic, minced\r\n1 1/2 cup sliced fresh mushrooms\r\n1 1/4 pounds fresh green beans COOKED TENDER CRISP\r\n1 cup fresh bread crumbs, toasted\r\n', 'to make the white sauce: melt butter in small pan over low/medium heat.  Stir in flour and cook 3 minutes cooking constantly.  Using a whisk stir in milk.  Then bring to a boil. cook for 1 to 2 minutes.  Stir in dressing mix and pepper.  Set aside.\r\n\r\nPreheat oven to 350.  \r\n\r\nSaute onion and garlic for 3 minutes.  Remove half and set aside.\r\nAdd mushrooms to remaining mixture in skillet and cook 5 minutes.  \r\nCombine mushroom mixture, green beans and white sauce in 1.5 quart casserole.  Combine bread crumbs with reserved onion mixture and sprinkle over beans.  Bake, uncovered 20 to 30 minutes.', NULL, 8),
(71, 'Almond Crusted Chicken Dijon', '4 chicken breasts\r\n2 tbsp Miracle Whip \r\n2 tbsp Dijon Mustard\r\n6 heatlhy crackers average size\r\n1/4 cup silvered almonds - coarsely chopped', 'Preheat oven to 375.  Place chicken in lightly greased 13 x9 inch baking dish.  Mix dressing and mustard until well blended.  Spread on top of each breast with the mixed dressing.  Mix crackers and almonds and sprinkle evenly over each breast.\r\nBake 20 to 25 minutes.  \r\n', 'Serve with salad and a starch of some variety', 10),
(72, 'Pumpkin Pie Squares', '1 1/2 cup all purpose flour\r\n1 1/2 cup quick cooking oats\r\n1 1/2 cup packed brown sugar\r\n1/2 tsp salt\r\n3/4 cup butter\r\n1 egg\r\n\r\nFilling:\r\n3.4 packed brown sugar\r\n3 eggs\r\n3 cups canned pumpin puree\r\n1 1/2 tsp cinnamon\r\n3/4 tsp each ginger and nutmet\r\n1 cup evaporated milk\r\n\r\nTopping\r\n1 1/2 cup reserved oatmeal mixture\r\n3/4 cup chopped pegans', 'Base:\r\nIn food processor, combine flour, oatmeal, salt and sugar.  Add butter and process until mixture resembles coarse crumbs.  Transfer to medium, add egg.  Measure 1 1/2 of this mixture and set it aside for the topping.\r\nGently pat remaining mixture into 13 x 9 pan and bake in 350 oven for 20 minutes or until golden and firm.\r\n\r\nFilling:\r\nIn a medium bowl, beat together sugar and eggs. Beat in pumpkin, Cinnamon, ginger nd nutmeg until smoth.  Beat in milk.  Pour over cooked base.\r\nTopping:\r\nIn a small bowl, combine reserved oatmeal mixture and nuts.  Sprinkle ovr pumpkin silling.  Bake in 30 oven approx 30 minutes or until centre is set.  Leave to cool in pan over night before cutting into squares.', 'Just a nice change for pie.  Good as a take along for fall dinners - before Thanksgiving!!', 13),
(73, 'Hello Dolly\'s', '1/2 cup butter\r\n1 cup graham crumbs\r\n1 cup flaked cocoanut\r\n1 cup semi-sweet choc chip\r\n1 cups walnuts ***  optional\r\n1/2 cup dried red cherries\r\n1 tin sweetened condensed milk\r\n', 'melt butter and add crumbs. Press into 8 x 8 glass pan.  Then pile on the other ingredients as listed - ending with milk poured over.  Bake 350 for 30 minutes.', 'You can add whatever you like on top of the crumb base.  ie Carmel chips, white chocolate...  etc.', 13),
(74, 'chewy healthy cereal bars', '3/4 cup light corn syrup\r\n3/4 cup smooth light peanut butter\r\n3 cups post shreddies cereal\r\n1/2 cup chopped dried apricots\r\n1/4 cup unsweetened flaked cocoanut\r\n1/4 cup dried cranberries\r\n', 'Spray 8x8 pan with pam.\r\nMicrowave corn syrup and peanut butter in large microwaveable dish on high 1 1/2 minutes or until peanut butter is almost melted.  Stir until it is well blended.\r\nAdd remaining ingred. Mix well and press into pan\r\n\r\nRefigerate 1 hour or until firm.', '20 servings.  130 calories.  3 gm fat.', 13),
(75, 'Moroccan Lamb Dinner', '1 butternut squash - peeled, seeded and cut into chunks*****\r\n1 tbsp olive oil\r\n1 red  peppers cut into chunks  *****\r\n1 green pepper\r\n1 medium onions cut into chunks  ****\r\n2 tsp minced garlic\r\n1 Tbsp garam masala spice blend\r\n1/2 tsp salt\r\n2 tbsp olive oil\r\n1 3/4 boneless leg of lamb cut into 1 to 2 inch pieces\r\n1 tbsp chopped cilantro or parsley******\r\n', 'Heat oven to 500.  Position racks to divide oven in thirds.  You will need 2 rimmed baking sheets lined with foil or parchment paper\r\nMix squash, oil, peppers and onion in lare bowl.  Combine the spices.  Add 1 TBSP of it to the veggies.  Toss and spread onto a baking sheet.\r\nMeanwhile, put lamb into large bowl.  Add remaining spice mixture and toss to coat.  Spread onto other cooking sheet.  Put veggies on low rack, meat on high rack.\r\nRoast 10 to 20  minutes until lamb is cooked and veggies are tender.  Toss together and sprinkle with cilantro.', 'Serves 6 - but really 4 Donalds - nice alternative to a chicken bake with veggies.  Serve with seasoned white rice and some garlicy sour cream or greek yogurt - thick variety. \r\nSquash - Pierce squash many times and put into microwave.  Watch and when it is a bit softer, then peel and cut - otherwise - almost impossible.\r\nNote:  you can use any veggie you like here.  I am not overly fond of peppers, so lots of onion and maybe broccol instead??  Just use what you like.  Also, we hate cilantro - so I just use parsley. ', 22),
(76, 'slow cooker chicken wings', '3 lbs chicken wings\r\n1/2 tsp salt\r\ndash peppr\r\n1/2 cups ketchup\r\n1/4 cup packed brown sugar\r\n1/4 cup red wine vinegar\r\n2 tbsp worchester sauce\r\n1 tbsp dijon mustard\r\n1 tsp minced garlic**\r\n', 'sprinkle wings with salt and pepper.  Broil 4 to 6 inches from heat for 5 to 10 minutes, turning until golden brown.  transfer to 5 quart slow cooker\r\n\r\nCombine all the rest of the ingredients and pour over the wings.  Toss to coat.  Cook on low for 3 to 4 hours.', 'Easy way to make wings as horses do overs.  No work and men love these things!!', 9),
(77, 'zucchini fritters', '1/4 cup buttermilk\r\n1/4 cup egg substitute\r\n\r\n1/2 cup panko\r\n1/2 cup seasoned bread crumbs\r\n1/2 cup grated parm cheese\r\n1 1/2 tsp taco seasoning\r\n1/4 tsp garlic salt\r\n\r\n3 medium zuccihini sliced into 1/4 inch slices\r\n\r\nDip sauce\r\n1/4 cup low fat sour cream or greek yogurt\r\n1/4 cup low fat ranch dressing\r\n1/4 cup salsa', 'In a shallow bowl comine milk and eggs.  Seperate bowl combine seasonings and crumbs.\r\nDredge slices in milk then  crumb mixture. \r\nPlace onto cookie sheet covered with parchment paper.  Bake at 400 for  20 to 25 minutes - turning once until golden.\r\n\r\nSauce: combine and serve along side.', 'Great on a buffet table or passed for cocktail hour for large groups. Goes down very well with men and ladies as it is low fat and a veggie', 9),
(78, 'Black Forest Brownies', '1 pkg fudge browne mix to fit into 13 x 9 pan\r\noil and water and eggs as per the boxed brownies require\r\n1 8oz package cream cheese - softened\r\n1/3 cup sugar\r\n1/2 tsp vanilla\r\n1/3 cup whipping cream\r\n1 20 oz can cherry pie filling*** \r\n2 oz semi sweet choc baking sqares or chips', 'Prepare and bake brownies as per instructed.  Cook on rack.\r\nIn a large bowl combine cheese, sugar, vanilla until smooth.\r\nIn a small bowl, beat cream until stiff peaks form,  Fold into cheese mixture.\r\n\r\nCover brownies with cream mixture. Top with pie filling.\r\n\r\nIn a microwave bowl - melt chocolate until soft.  Remove and stir until melted.  Drizzle over brownies.  \r\nRefrigerate for 10 minutes and serve.  ', 'You can use any fruit on top of the brownies.  Fresh fruit, or any pie filling.  ', 3),
(79, 'Sweet and Sour Chicken - like sticky chicken wings', '1/2 cup peach or apricot jam\r\n4 tbsp balsamic vinegar\r\n2 tbsp soy sauce\r\n1 tsp dried hot chili flakes\r\n12 boneless, skinless chicken thighs', 'Preheat oven to 425.  \r\nPlace all but chicken in a bowl. Mix.\r\nSpread over chicken in dollops.  Cover dish with foil.  roast for 20 minutes.  remove foil and baste chicken then continue to cook uncovered. until well glazed.', 'Not bad.  More healthy than sticky chicken wings.  ', 10),
(80, 'Cold Paella Salad', '1 cup frozen peas\r\n20 oz chicken broth\r\n240 clam juice\r\n1 cup dry whie wine\r\n1 tsp saffron threads\r\n1 large spanish onion\r\n2 garlic cloves minced\r\n2 jalapeno pepprs or 1/2 tsp red pepper flakes***\r\n2 each red and green peppers\r\n2  italian or chorizo sausages\r\n1 tbsp olive oil\r\n2 cups uncooked basmatti rice\r\n1/2 tsp each paprika, dried thyme, oregano\r\n4 plum tomatoes\r\n4 green onions\r\n3/4 cup chopped fresh basil\r\n1/2 cup bottled sundried tomato salad dressing\r\n\r\nShrimp and sausage kebabs \r\nshrimp and sausage on skewers brushed with oil, salt and pepper\r\n\r\n40 large shrimp \r\n6 italien sausages\r\n', 'In a bowl.  measure out peas and leave to thaw.  Seperate bowl.. Pour broth, clam juce and wine. Stir in saffronon Counter top to steep.\r\nFinely chop onion, mince garlic and jalapenos.  Seed and coarsely chop peppers.  Slice sausages into thick slices.\r\n\r\nHeat oi in large pan over medium heat.  Add onion, garlicjalapaneos, peppers and sausages.  Stir ofetn until sausages ae lightly browned until lightly browned.  Stir in rice, paprika, thyme and oregano.  Pour  in saffron mixture.  Increase heat to high and bring to boil stirring often.  Cover and reduce heat to medium low.  Simmer, stirring occassionally until rice is tender and liquid is absorbed.  Approx 25 minutes.  \r\nSpread out on a large cookie sheet and refigerate until cooled.\r\nMeanwhile coarsely chop tomates and thinly slice onions.  \r\nMix all together for the salad.  Serve in large shallow bowl with grilled shrimp and sausage kebabs.', NULL, 17),
(81, 'Easy Chicken Broccoli Divan with Fusili', '3 cups hot cooked broccoli florets\r\n2 cups cubed, cooked skinless chicken breast\r\n1 can broccoli soup\r\n1/2 cup milk\r\n1/2 shredded cheddar cheese\r\n2 tbsp dry bread crumbs\r\n1 tsp butter - melted\r\n3 cups fusilli', 'Arrange broccoli and chicken in 1.5 quart baking dish\r\nPour in mixture of sop and milk.  Sprinkle with cheese and top with bread crumbs and butter.\r\nBake at 425 until heated through - about 25 minutes\r\nCook fusili seperately and serve with divan', 'Use light cheese and 1 % milk to lower fat', 10),
(82, 'Raspberry Swirl Dessert', '1 Angel food cake\r\n4 cups fresh raspberries\r\n1 1/4 cups granulated sugar\r\n2 pkgs (7g each) unflavoured gelatin\r\n1 package (8oz) light cream cheese softened\r\n2 cups whipping cream\r\n1 tbsp vanilla extract\r\n', 'Line a 9 inch spring form pan with plactic wrap.  Slice cake into thin strips (1.5 inches) and line sides of the pan decoratively.  Use the rest of the cake for the bottom\r\n\r\nIn a blender, puree raspberries until smooth. Press puree through fine mesh sieve to remove seeds.  Discard seeds.  Place puree in a pan with 3/4 cup of sugar and cook over low heat for approx 5 minutes or until sugar is melted.  Whisk in gelatin until smooth and let cook slightly.\r\n\r\nIn another bowl, beat cream cheese with remaining sugar until combined.  Add 1/2 cup of the whipping cream and vanilla.  Beat until fluffy.  \r\n\r\nBeat remaining cream in another bowl until stiff peaks form.  Fold into cream cheese mixture and pour into the prepared pan\r\n\r\nSpoon 1/2 cup of the raspberry mixture on top and swirl into cream cheese mixture.  Smooth top.  \r\n\r\nPour remaining raspberry mixtrure into and around the edges of the of the cake pan and top of cream cheese mixture  to cover.  Use spatula to smooth top layer of raspberry.  Cover and refrigerate for at least 4 hours or until set.', NULL, 3),
(83, 'Korean Steak', '2 lbs flank steak\r\n4 tbsp soya sauce\r\n2 tbsp sugar\r\n1 tsp pepper\r\n1 tsp salt\r\n4 tsp sesame seeds\r\n2 tbsp oil\r\n2 tsp chopped onion\r\n tsp chopped garlic', 'Score meat on both sides.\r\nMarinate in the above mixture for 24 hours.  Remove from marinate and pat dry.  Pour marinate into a pot and bring to a boil.  Simmer while steak cooks.  Broil approx 2 minutes each side.  Pour marinade over broiled steak and slice across the grain.  Serve with rice and a veggie - broccoli.', NULL, 12),
(84, 'Sweet and Sour chicken balls - healthy', 'Chicken Balls:\r\nmix 500 grams ground chicken with 1 beaten egg, 3 thinly sliced green onions, 1/2 tsp salt and 1/4 tsp cayenne pepper.  Stir in 2 cups soft bread crumbs (4 slices).  Shape mixture into 1 inch balls.    \r\nLine a cookie sheet with parchment paper.  Bake balls until no longer pink.  Approx 10 minutes.\r\n\r\nSauce:\r\n1/3 cup cornstarch\r\n1/2 cup gran sugar\r\n1/4 cup rice wine vinegar\r\n2 tbsp soy sauce\r\n2 cups chicken stock\r\n1/2 tsp garlic powder (or 2 fresh cloves minced)\r\n1/4 tsp crushed red pepper\r\n1/2 tsp ground ginger (or 1 tbsp fresh)', 'After cooking the meat balls, put into a pot with a cup of sauce for 4 minutes.  Serve over rice.', 'Or you can buy frozen chicken meat balls!!!', 10),
(85, 'Garlic Chinese Ribs', '2 racks pork back ribs each about 1.5 lbs\r\n6 garlic cloves minced\r\n2 tbsp grated fresh ginger\r\n3/4 cup gran sugar or 1 cup brown\r\n1/2 cup soya sauce\r\n1/4 cup hoisin sauce\r\n1/4 cup dry sherry', 'Cut ribs into 2 or 3 rib servings.  Place in 2 large plastic bags.  In medium bowl whisk remaining ingred.  Pour into the 2 bags. Marinate for 24 hours or up to 2 days.\r\n\r\nBring meat to room temperature before grilling.  Heat BBQ to medium heat and grill with lid closed, turning occassionally and basting with marinade.  Cook 10 minutes.  Then toss the marinade.  Continue cooking until richly glazed - approx 10 minutes more.  ', 'Serves 4.  Serve with rice and salad - maybe smashed red potatoes with butter and salt/pepper', 12),
(86, 'Barely Jerked BBQ Pork', '2 large cloves minced garlic\r\n1 minced jalapeno - cored and seeded.  \r\n1 green onion - sliced\r\n2 tbsp chopped parsley\r\n1 tbsp lime juice\r\n1 tbsp paprinka\r\n2 tsp brown sugar\r\n2 tsp ground ginger\r\n2 tsp cinnamon\r\n1 tsp each salt and pepper\r\n1/4 tsp corriander\r\n1/4 tsp all spice\r\n1/4 tsp nutmeg\r\n2 tenderloins (each 3/4 lbs)', 'Process all ingredients in blender and pulse until paste forms.  Rob evenly over pork.  Cover and marinate in fridge for 8 to 24 hours.\r\n\r\nGrill  and serve with rice cooked with cocoanut milk.  Grilled tomatoes and pineapple pieces.', 'Serves 4 to 6', 12),
(87, 'Coconut Rice', '5 green onions\r\n2 garlic cloves minced\r\n1 cup fresh parsley\r\n1/2 cup fresh mint\r\n1 398 ml can coconut milk - preferably light\r\n1 tbsp olive oil\r\n1 1/2 cups basmati rice', 'Puree first 4 ingredients.  Pour in coconut milk then add enough water to make 3 1/2 cups.  Microwave.', NULL, 18),
(88, 'Easy Molten Chocolate cakes - serves 12', '12 chocolate chip cookies\r\n4 squares Semi- sweet chocolate\r\n1/2  cup butter\r\n2 whole eggs\r\n2 egg yolks\r\n1 cup icing sugar\r\n1/3 cup flour\r\n\r\nWhipped cream to serve with\r\n', 'Preheat oven to 425.  Microwave chocolate and butter on low until almost melted.  Then remove and stir until chocolate is melted.  Beat whole eggs and the egg yolks, sugar and flour with whisk until well blended.  Gradually add to chocolate mixture, beating constantly until well blended.\r\nLine 12 muffin cups with paper liners.  Place one cookie upside down in the cup and cover with batter.\r\nBake 8 minutes or until cakes are firm around the edges but still soft in centre.  Let stand 1 minute.  Carefully remove the cakes from the pan.  Invert onto dessert dishes, remove liners and serve with whipped cream.', 'Prepare batter early and refrigerate.  Prepare pan with cookies in it.   Remove batter from fridge before guests arrive - to allow to come to room temperature.  After dinner is cleared away from the table.  Pour batter into the cups and put into oven to cook.  Have cream already whipped.', 3),
(89, 'Herbed Chicken with Warm Tomato and Balsamic Vinegrette', '4 chicken breasts\r\n1 tbsp olive oil - for sauteing\r\n1 tbsp dry basil\r\n1 tbsp dry thyme\r\nzest and juice of one lemon\r\n1 tbsp olive oil\r\nsalt and pepper to taste\r\n\r\nWarm Balsamic Sauce\r\n1/3 cup onion finely choped\r\npinch or chili flakes\r\n2 cloves garlic minced\r\n1/3 cup olive oil\r\n1/2 tsp dry thyme\r\n1/2 cup sundried tomatoes, soaked, drained and julienned\r\n1/4 cup black olives chopped\r\n2 cups cherry tomatoes - halved\r\n1 tsp basil\r\n1/4 cup balsamic vinegar\r\n', 'Season chicken with salt and pepper.\r\nIn medium bowl combine rest of ingredients and coat chicken.  Allow to marinate while you create the vinegrette.\r\nTo cook the chicken - saute in large pan over medium heat.  Cook 6 minutes per side or until golden.\r\n\r\nVinaigrette\r\nIn medium pan over medium low saute onions, chili and garlic in half the olive oil for 5 minutes.\r\nAdd thyme, olives, sundried tomatoes, cherry tomatoes.  Cook 5 minutes until slightly softened.\r\nAdd vinegar and let reduce 3 minutes.  Turn off heat and stir in the rest of the olive oil.  \r\n\r\nSeason to taste and serve warm with chicken.', 'Serves 4', 10),
(90, 'Deb Steven\'s chocolate strawberry cake', '1 cup vanilla wafer cookie crumbs (24 wafers)\r\n1/2 cup toasted almost finely processed\r\n1/4 cup melted butter\r\n4 cups fresh strawberries\r\n12 oz white chocolate (squares)\r\n4 oz cream cheese\r\n1/4 cup sugar\r\n1/4 cup orange liquor or frozen orange juice concentrate\r\n1 tsp vanilla\r\n2 cups whipping cream\r\nCocoa powder for garnish', 'Combine crumbs, almonds and butter and press into the bottom of a 9 inch spring form pan.  Put aside.\r\nWash, dry and hull berries.  Reserve a few for garnish.  Cut enough of berries in half, lengthwise and press flat sides all around side of pan.  Arrange whole berries points up on crust.  \r\nChop chocolate and melt in microwave on low.  Cool slightly.  Beat cream cheese until smooth then beat in sugar.  Mix in liquor or juice and vanilla.  Slowly beat in the chocolate.  Whip the cream.  Stir about 1/3 of the whipped cream into the chocolate mixture and fold in the reminder.  Pour over the berries.  Shake pan gently to fill between the berries.  \r\n\r\nRefrigerate at least 3 hours - over night is fine.  Remove sides and bottom of the pan.  Dust with cocoa power and garnish with reserved strawberries.', 'I haven\'t actually made this dessert  but Deb says it is one of her fav\'s and she is a great baker.', 3),
(91, 'Red Cake', '1/2 cup butter\r\n1 1/2 cup sugar\r\n2 eggs\r\n1 cup buttermilk\r\n2 1/2 cup flour\r\n1 tsp salt\r\n2 oz red food coloring\r\n2 tsp cocoa\r\n1 tsp vanilla\r\n1 tsp soda\r\n1 tsp vinegar\r\n\r\nFrosting:\r\n1 cup 2% milk\r\n3 tsp flour\r\n1 cup icing sugar\r\n1/2 cup butter\r\n1/2 cup butter\r\n1 tsp vanilla', 'Cream butter and sugar. Then add eggs.   In separate bowl make paste of food coloring and cocoa then add to the butter and sugar.\r\n\r\nAdd buttermilk alternatively with flour and salt.  Add vanilla.  \r\nIn seperate bowl add soda to vinegar.  Fold into batter and blend without beating.\r\n\r\nPour into 2 - 8 inch layer pans.  Bake at 350 until firm.\r\n\r\nFrosting:\r\n\r\nCook the milk and flour until thick.  Stir constantly and then allow to cool.\r\n\r\nCream the rest of the ingredients then add to the milk/flour mixture\r\n', NULL, 3),
(92, 'Thai Spicy Noodles - main meal', '1/2 pkg of 450 g package spaghetti noodles\r\n1 tbsp cornstarch\r\n1 tbsp fish sauce\r\n1 tbsp lime juice\r\n1 1/2 tsp granulated sugar\r\n2 chicken breasts\r\n1 jalapeno or 2 tsp chopped pickled jalapeno\r\n1 red peppers\r\n1/2 cup baby carrots or 2 small carrots\r\n1 1/2 cup snow peas\r\nVegetable oil\r\n2 tsp minced garlic\r\n2 tsp minced garlic\r\n284 ml can chicken broth\r\n2 to 3 tsp curry powder\r\n2 green onions - sliced\r\n\r\n1 lime to serve with', 'Cook pasta until al dente.  Drain but do not rinse.\r\nMeanwhile in a small bowl, stir cornstarch with fish sauce, lime juice and sugar until dissolved. \r\nSlice chicken into thin strips.  Core and seed jalapeno then finely chop.  Core and seed red pepper.  Slice thinly.  Julienne carrots.  Prepare peas.\r\n\r\nLightly coat a large, wide saucepan with oil and heat over medium high heat.  Add chicken, jalapeno, garlic and ginger.  Stir often until chicken is light gold.  3 to 4 minutes.  Pour in chicken broth, stir up bits.  Stir in cornstarch mixture then pour into the pan.  Stir until well blended.  Add red pepper, carrots and snow peas.  Sprinkle with curry.  Stir often until peas are bright greenand sauce bubbles.  3 minutes.  Add noodles and stir until hot.  Remove from heat and stir in onions.  Serve with lime wedges', 'healthy low fat version as served in restaurants', 11),
(93, 'Chocolate chip cake - fav from my childhood', '1 cup dates - chopped\r\n1 tsp soda\r\n1 cup hot water\r\n1 cup white sugar\r\n1 cup butter\r\n2 eggs\r\n1/2 cup walnuts**  optional\r\n1 3/4 cup flour\r\n1 tbsp cocoa\r\n1 tsp vanilla\r\n6 oz milk choc chips\r\n', 'Stir dates, soda, hot water together - cool.  Cream butter and sugar.  Add eggs and dry ingedients.  Add date mixture and 1/2 of the nuts and chips.  Pour into 9 x 13 greased pan.  sprinkle rest of nuts and chips on top.  Bake at 350 for 35 to 40 minutes.', 'I loved this cake when I was a kid.', 3),
(94, 'Lemon Garlic Tilapia', '8 tilapia fillets\r\n1/4 cup and 2 tbsp fresh lemon juice\r\n2 tbsp butter - melted\r\n2 cloves garlic minced\r\n2 tsp dried parsley flakes\r\npepper to taste', 'Preheat oven to 375.  Line cookie sheet with parchment paper.  Rinse Tilapia with cool water and pat dry.  \r\nPlace filets on the paper.  sprinkle lemon juice over the fillets then drizzle butter on top.   Sprinkle with garlic, parsley and pepper.\r\nBake 5 or 10 minutes until flakey.', 'Pretty good.  Could also use the pre-mixed lemon herb shake. Good with asparagus and wild rice', 14),
(95, 'Pan Seared Salon with Lemon Dill Cream Sauce', '1 tbsp butter\r\n6 salmon fillets (2 lbs)\r\n1 onion minced\r\n1/2 tsp each salt and pepper\r\n1/4 white wine\r\n1 1/2 cups whipping cream\r\n1 tbsp fresh chopped dill\r\n1/2 tsp grated lemon rind\r\n1 tbsp lemon juice', 'In a large skillet, melt butter over medium high heat.  Cook salmon until bottom is golden - approx. 5 minutes. Using a wide spatula, turn and cook until salmon flakes.  5 to 7 minutes.  Transfer to plate and keep warm.\r\nIn the same skillet, cook the onion, salt and pepper over medium heat until softened.  Pour wine over and cook for one minute.  Scraping up brown bits.\r\nAdd cream and bring to mixture.  Reduce heat and simmer for 10 minutes.  Stir in dill, lemon rind and lemon juice.  Spoon over fish and sprinkle with dill.', 'For the less than healthy crowd.', 14),
(96, 'Quick Salmon Risotto', '1 284 ml can of chicken broth\r\n1 cup white wine or apple juice if you don\'t have\r\n1 garlic clove\r\n1 onion\r\n1 cup arborio rice\r\n1 tsp dried oregano\r\n2 cups frozen peas - thawed\r\n1/4 cup grated parmesan\r\n1/4 cup chopped fresh dill\r\n1 213 g can salmon - preferably sockeye***\r\n1/4 cup regular sour cream\r\n', 'Pour chicken broth into a large measuring cup.  Add enough water to measure 3 cups.  Pour into a large saucepan.  Add wine.  Minced garlic and finely chopped onion.  Stir in rice and oregano.  Brng to a boil over high heat, stirring often.  Then reduce heat to low.  Cover and simmer until rice is tender - 18 to 20 minutes.   Do not stir.\r\n\r\nMeanwhile, measure peas and parmesan.  Coarsely chop dill.  Drain salmon  and remove bones and skin.  When rice is tender turn off the heat.  Leave pan on the burner.  Stir in peas, parmesan, dill and sour cream.  Crumble in salmon. Stir gently.  Taste and add more cheese if needed.', 'fresh salmon is better - precooked. ', 14),
(97, 'April\'s Brownies with Caramel Sauce', '2 oz unsweetened choc\r\n1/2 cup butter\r\n3/4 cup flour\r\n1 cup sugar\r\n2 eggs\r\n1/2 tsp baking powder\r\n1/2 tsp salt\r\n1 tsp vanilla\r\n\r\nSauce\r\n20 Caramels\r\n2 tbsp whipping cream\r\n', 'Melt butter and chc together.  Blend in all other ingredients using a whisk.  Cook at 350 for 20 to 25 minutes.\r\n\r\nCararmel Sauce\r\nMelt the 2 together.', NULL, 13);
INSERT INTO `recipe` (`recipeID`, `recipe_title`, `recipe_ingredients`, `recipe_method`, `recipe_note`, `catID`) VALUES
(98, 'Jello shortbread cookies', '1 3/4 cups flour\r\n1/2 tsp baking powder\r\n3/4 cup butter, softened\r\n1/2 cup sugar\r\n2 pkg strawberry jello powder - divided\r\n1 egg\r\n1 tsp vanilla\r\n', 'Preheat oven to 400.  Mix flour and baking powder.  Put aside.  Beat butter in large bowl until creamy.  Gradually add sugar and 1 pkg of the jello powder, beating until fluffy and light.  Add egg and vanilla.  Mix well.  Gradually add flour mixture beating well until well blended.\r\n\r\nShape dough into 1 inch balls.  Place cookie 2 inches apart on parchment paper.  Flatten with bottom of clean glass.  Lightly sprinkle with remaining jello powder.\r\n\r\nBake 6 to 8 minutes or until edges ae lightly browned. Remove to wire racks to cool.  ', 'Makes 3 dozen cookies.  You can make other colours by using different jellos.', 13),
(99, 'Virginia\'s easy chocolate coconut macaroons', '1 1/2 cup gran sugar\r\n5 tbsp cocoa\r\n1/2 cup 2 % mik\r\n1/2 cup butter\r\n3 cups oats\r\n1 cup sweetened coconut\r\n1 tsp vanilla\r\n1/4 tsp salt\r\n', 'Combine sugar and cocoa in pan.  Add milk slowly.  Stir over low heat until sugar dissolves.  Bring to a boil.  Add butter and oats stirring briskly.\r\nCook for 1 or 2 minutes stirring constantly as it thickens.  Remove from heat.\r\nAdd coconut, vanilla and salt.  Drop by spoonful onto parchment paper.  Do not bake.  As they cook they will harden.', '3 1/2 dozen', 13),
(100, 'Olive Garden\'s Tiramisu', '1 sponge cake (10 to 12 in diameter - 3  inches deep)\r\n4 tbsp strong black coffee or instant espresso\r\n4 tbsp brandy or run\r\n1 1/2 lb mascarpone cream cheese\r\n1 1/2 cups fine granulated sugar\r\nunsweetened cocoa powder', 'Cut across middle of sponge cake forming 2 layers about 1.2 inches high.  \r\nBlend coffee and brandy.  Sprinkle enough of mixture over bottom half of the cake to flavour it strongly.  Don\'t moisten cake too much or it may collapse on serving.\r\nBeat room temperature cheese and 1 cup of sugar until sugar is totally dissolved and cheese s light and spreadable.  Taste test for sweetness add more sugar if necessary.\r\nSpread  cut surface of bottom layer with half the cheese mixture.  Put second layer on and top with remaining cheese mixure.  Sprinkle top liberally with sifted cocoa.  Refrigrate for at least 2 hours before serving.', 'Serves 6.  If using a square cake then start building on a square cake platter.', 3),
(101, 'Gramma\'s Cherry Squares', '2 cups crushed graham crackers\r\n1/2 cup melted butter\r\n1/2 tsp vanilla\r\n8 oz pkg cream cheese\r\n1 cup icing sugar\r\n2 tbsp milk\r\n1/2 tsp vanilla\r\n1 cup walnuts\r\n1 tsp vanilla\r\n2 tbsp white sugar\r\n1 cup whipping cream\r\n1 cup cherry pie filling', 'Base:\r\ncombine first 3 ingredients and press into 9 x 13 pan.  Bake at 325 for 10 minutes.  Cool.\r\nMiddle\r\nBeat the next 4 ingredients together until smooth and spread over cool baked base.\r\nSpread the walnuts over the cheese\r\nSpread pie filling over the cream.\r\nChill over night', 'Buy the best pie filling you can find.  Makes all the difference.  ED Smith was what my mom used.', 13),
(102, 'Healthy Farmer Cookies ', '1 cup butter, room temp\r\n3/4 cup granulated sugar\r\n3/4 cup brown sugar\r\n2 eggs\r\n1 tsp vanilla\r\n2 cup whole wheat flour\r\n1 tsp baking powder\r\n1 tsp baking soda\r\npinch salt\r\n1 cup rolled oats\r\n2 cup rice crispies\r\n1/2 cup chopped walnuts\r\n1/2 cup sunflower seeds\r\n1/4 cup flax seeds\r\n1/4 cup sesame seeds\r\n1/4 cup wheat germ', 'Cream butter in large bowl.  Gradually add granulated sugar then brown.  Mix well.  Beat in eggs and vanilla.  Do not over mix.\r\nMix baking powder, soda and salt into another small bowl.  Blend then stir into butter mixture. Add all other remaining ingredients.\r\nRoll into 1 inch balls.  Put on parchment paper. Flatten slightly.  Bake until edges ae golden.  6 to 8 minutes.', 'Recipe from Auntie Dora.  Very healthy and the Erika quite like these as a little girl.  Makes 6 dozen.', 13),
(103, 'Ginger Snap Cookies from Gramma Mary', '3/4 cup butter\r\n1 cup granulted sugar\r\n1 egg\r\n1/4 cup molasses\r\n2 cups flour\r\n2 tsp baking soda\r\n1 tsp cinnamon\r\n1 tsp cloves\r\n1 tsp ground ginger', 'Cream butter and sugar.  Add next 2 ingredients.  Beat well. Combine the rest and blend well.  Roll into 1 inch balls and dip into white sugar.\r\nPlace on parchment paper, flatten slightly.\r\nBake at 350 for 8 m', 'Cookies are very crispy and perfect for dunking into milk!!', 13),
(104, 'Ginger Bread Cookie Dough - from Kim Inouye', '1 cup crisco ***\r\n1 cup granulated sugar\r\n2 eggs\r\n3/4 cup fancy molasses\r\n1/2 cup blackstrap molasses\r\n5 1/2 cups all purpose flour\r\n2 tsp ground ginger\r\n1 tsp baking soda\r\n1 tsp salt\r\n1 tsp cloves\r\n1 tsp cinnamon', 'Cream first 2 ingredients.  Then beat in the eggs.  Add the 2 types of molasses.  Beat in.  Combine other ingredients in seperate bowl then stir into the dough.  \r\nChill 2 hours or up to one week.  \r\nRoll into 1/4 inch thick.  \r\n\r\nTo make a house... trim to fit into a cookie sheet.  Put whole onto sheet and then cut into shapes.  Chill until hard then bake 8 to 12 minutes.\r\n\r\nMakes 40 ginger bread men.', 'Not keen on the Crisco -  replace with butter', 13),
(105, 'Gramma Mary\'s Sukiyaki', '1 1/2 pound striploin\r\n1 can condensed beef bouillion\r\n1/4 cup dry sherry or vermouth\r\n2 tbsp brown sugar\r\n2 tbsp soy sauce\r\n1/8 tsp ground ginger\r\n1/4 cup veg oil\r\n6 green onions\r\n1 green pepper julienned\r\n2 celery stalks - cut diagonally into 1/2 inch slices\r\n12 large mushrooms thinly sliced\r\n2 pounds of spinach or swiss chard. Washed and patted dry.', 'Put steak in freezer for 15 minutes to make it easier to cut.  Then put into a large sealable bag.  Combine boullion thru to and including oil.  Pour into the bag.  Marinate 6 hours to over night.\r\nTo cook, remove meat and pat dry.  Heat 2 tbsp oil and add half the meat.  Brown slightly.  Remove and do the next batch.  Remove and keep warm.\r\nSaute onions, peppers, celery and mushrooms for 2 minutes.  Remove.\r\nPut the greens in the pan and the marinade.  Boil until softened.\r\nAdd all ingredients back into the pan and toss to coat.\r\nServe over white rice', '4 to 6 servings.  I loved this as a kid!!!', 12),
(106, 'Chinese BBQ Pork', '3 pork tenderloins - 1 1/2 lbs total\r\n2 tbsp soy sauce\r\n2 tbsp hoisin sauce\r\n1 tbsp sherry\r\n1 tbsp black bean sauce\r\n1 1/2 tsp minced ginger\r\n1 1/2 tsp packed brown sugar\r\n1 clove garlic\r\n1/2 tsp sesame oil\r\npinch 5 spice powder', 'Trim fat or silver tendons from tenderloins.  Put into large bag along with the marinade.  Marinade over night.  \r\nLet stand for 30 minutes to warm before grilling.\r\nPlace tenderloins on rack in roasting pan, reserving marinade.  Pour 1 cup of water into the bottom of the pan.  Bake, basting generously 4 times for 30 minutes or until temp is 160 and still has a hint of pink.\r\nRemve to cutting board and allow to rest for 10 minutes.  ', NULL, 12),
(107, 'Pulled Pork Sandwiches - slow cooker', '4 lb pork roast\r\n1 cup water\r\n1 tsp salt\r\n\r\nSauce\r\n2 cups finely chopped celery\r\n1/3 cup steak sauce\r\n1/4 cup cider vinegar\r\n1/4 cup packed brown sugar\r\n2 tsp lemon juice\r\n2 tsp chili sauce\r\n1 tsp ketchup\r\n\r\n2 medium onions\r\n1 tbsp veg oil\r\n1 tbsp butter\r\n16 hoagie buns', 'Put pork, water and salt into slow cooker.  Leave for 4 hours on high heat.\r\n\r\nWhen tender enough to shred with 2 forks, remove and do so removing bones and fat.\r\n\r\nPut all the rest f the ingredients into the cooker and mix thoroughly.  Put shredded pork back in and stir.  Cook for another hour or so.\r\n\r\nSaute onions and serve with pork on buns.', 'Scott loves this recipe.', 12),
(108, 'Pork Tenderloin with Shiitake Cream Sauce', '3 pork loins - 2 1/4 lbs total\r\n1 tsp each salt and pepper\r\n1 tbsp veg oil\r\n\r\nSauce\r\n1 tbsp butter\r\n1/4 cup chopped shallots or green onions\r\n2 cups sliced shiitake mushrooms\r\n1/4 cup dry sherry\r\n1 tbsp soy sauce\r\n1/4 cup beef stock\r\n1 1/2 cup whipping cream\r\n1 tsp chopped fresh thyme', 'Preheat overn to 425.  Sprinkle pork with salt and peper.  In large overn proof skillet, heat oil over medium heat.  Brown pork all over.  Transfer meat to oven and cook 15 minutes or until just a hint of pink remains.  Transfer to plate and cover with foil to rest.\r\nMake the sauce:\r\nIn same skillet, melt butter over medium heat.  Cook shallots until tender then add mushrooms and cook until golden.  Add dry sherry and soy sauce.  cook 1 minute while stirring to scrape up brown bits.\r\nStir in stock and cook until reduced b half.  Add whipping cream and boil until reduced to 1 1/2 cups.  Approx 10 minutes.  Add thyme.  \r\nSlice pork and spoon sauce over the pork.', 'Fast and easy to make - should take just over half an hour total.  Serve with rice and a green veggie.', 12),
(109, 'Napa Cabbage Salad', '1 head napa cabbage\r\n1 bunch minced green onions\r\n1/3 cup butter****\r\n1 (3 ounce) package ramen noodles, broken***\r\n2 tablespoons sesame seeds***\r\n1 cup slivered almonds****\r\n1/4 cup cider vinegar\r\n3/4 cup vegetable oil\r\n1/2 cup white sugar\r\n2 tablespoons soy sauce', 'Finely shred the head of cabbage; do not chop. Combine the green onions and cabbage in a large bowl, cover and refrigerate until ready to serve.\r\nPreheat oven to 350 degrees F (175 degrees C).\r\nMake the crunchies: Melt the butter in a pot. Mix the ramen noodles, sesame seeds and almonds into the pot with the melted butter. Spoon the mixture onto a baking sheet and bake the crunchies in the preheated 350 degrees F (175 degrees C) oven, turning often to make sure they do not burn. When they are browned remove them from the oven.******\r\nMake the dressing: In a small saucepan, heat vinegar, oil, sugar, and soy sauce. Bring the mixture to a boil, let boil for 1 minute. Remove the pan from heat and let cool.\r\nCombine dressing, crunchies, and cabbage immediately before serving. Serve right away or the crunchies will get soggy.', 'I just brown the almonds etc in a frying pan and I double the amounts of these ingredients as they make the salad nice and crunchy - except for the butter.  A bit more, but double is too much.\r\nThis always goes over very well at buffet dinners.', 17),
(110, 'Granola from Abbey Cook', '	4 cups old-fashioned rolled oats (the thicker the better)\r\n	½ cup coarsely chopped walnuts\r\n	½ cup coarsely chopped almonds\r\n	½ cup coarsely chopped pecans\r\n	½ cup raw hulled green pumpkin seeds\r\n	½ cup raw flax seeds golden and/or brown\r\n	optional:  ½ cup sesame seeds (black, brown or white)\r\n	½ cup shredded sweetened coconut\r\n	½ cup large coconut flakes (unsweetened)\r\n	 \r\n	2 T.  canola oil\r\n	3 T. honey\r\n	2 tsp. ground cinnamon (or more)\r\n	\r\n	½ - 1 cup raisins (Thompson and/or yellow), dried cherries, blueberries, etc.\r\n', 'Preheat oven to 350. \r\nBake oats on a large rimmed baking sheet for 40 minutes, stirring occasionally to toast evenly.  In a large bowl, combine the nuts, flax, pumpkin and sesame seeds. Spread the mixture on another rimmed baking sheet.  Bake for 20 minutes.  Mix two types of coconut in a small baking dish, place in the oven and toast until very light brown, should take 6 - 8 minutes.  Watch carefully to prevent burning.  Transfer oats, nut mixture and coconut to a large bowl.  Gently mix.\r\n\r\nIn a small saucepan over low heat, combine the oil, honey and cinnamon and heat until warm, about 2 minutes. Add half of the honey mixture to the granola and toss thoroughly to combine. Add just enough of the remaining honey mixture so that the granola clumps slightly but is not soupy. Stir in the raisins and dried fruit. \r\n\r\nVariations:  any coarsely chopped dried fruit is wonderful in this granola.  \r\nGinger granola:  add 2 tsp. ginger to the honey mixture and crystallized ginger to the dried fruit mix. \r\nPumpkin granola:  Use pumpkin pie spices in the honey/oil mixture:\r\n	1 T. ground cinnamon\r\n	1 t. each: ground nutmeg or cloves, ground ginger, ground allspice \r\nTropical granola:  use Macadamia and cashew nuts instead of the walnuts and almonds.  Use additional coconut (and coconut syrup if available, instead of the honey/oil mixture).  Use dried mango and pineapple instead of raisins.  Banana chips for crunch?\r\nSugarfree:  use only unsweetened coconut. For the coating mixture, use no honey, but double the oil and spices. \r\n	\r\n', 'Delicious - higher in fat due to all the nuts but you need very little for a full meal!!', 6),
(111, 'Sweet and Tangy BBQ Sauce - Scott\'s fav for pulled pork', '1 tsp vegetable oil\r\n1/4 cup pureed onion, about 1/2 small onion\r\n1 cup ketchup\r\n1 cup tomato sauce\r\n3 tbsp brown sugar\r\n1 1/2 tsp hoisin sauce\r\n1/2 tsp garlic powder\r\n1/2 tsp Worchestershire sauce\r\n1/4 tsp smoked paprika\r\n1/4 tsp hot-red-pepper flakes', 'Heat a large saucepan over medium. Add oil, then onion. Cook, stirring constantly, until fragrant, about 1 min. Add ketchup, tomato sauce, brown sugar, hoisin, garlic powder, Worcestershire, paprika and pepper flakes. Continue stirring frequently, to keep sauce from splattering, until flavours develop, 5 to 8 min.\r\nLadle into 2 clean 250-mL Mason jars. Let cool to room temperature, about 30 min. Wipe rims clean, then twist lids on tightly. Keep refrigerated.', 'I double this recipe when I am making pulled pork.  Scott loves it', 12),
(112, 'Marghurite Pizza', '12 inches thin pizza crust	 (I like to use a square shape flat bread/naan bread wholw wheat)			 			 			 			 			\r\n1 tablespoon extra virgin olive oil\r\n2 garlic cloves, finely chopped\r\n3 -4 large basil leaves, cut into strips\r\n2 small tomatoes, cut thinly\r\n4 ounces mozzarella cheese, shredded\r\n2 tablespoons parmesan cheese\r\nsalt and pepper, to taste\r\n\r\nOptional\r\ncrushed red pepper flakes, to taste\r\n', '1Preheat the oven to 450°F.2Drizzle the olive oil over the pizza shell. Use a brush to spread it around and make sure to get the crust!3Next, disperse the finely chopped garlic evenly.4Spread the mozzarella cheese throughout the top, but keep it thin.5Place the thinly sliced tomatoes across the entire pizza.6Lightly salt and pepper the tomatoes with the kosher salt.7Spread the fresh basil leaves, making sure to get some on tomatoes and on just the cheese itself.8Cook the pizza in the oven for about 9-10 minutes, or until sufficiently crispy and melted to your liking.9Add a little Parmesan cheese and (optional) crushed red pepper and enjoy!', 'This is a great appetizer.  Just arrange tomatoes in straight lines and then cut into bite size pieces - as best you can.  ', 9),
(113, 'Easy Monkey Bread - like Cinnamon Rolls', '3 (12 ounce) packages refrigerated biscuit dough\r\n1 cup white sugar\r\n2 teaspoons ground cinnamon\r\n1/2 cup margarine\r\n1 cup packed brown sugar\r\n1/2 cup chopped walnuts (optional)\r\n1/2 cup raisins', NULL, 'Hardly healthy, but great for a buffet breakfast or for Christmas maybe', 7),
(114, 'Sesame Chicken', '1 cup milk - make your own...  1 cup milk (skim fine) add 1 tbsp white vinegar and let it sit for 10 minutes.  Stir\r\n1/2 cup all-purpose flour\r\n1 teaspoon black pepper\r\n1 teaspoon Chinese five-spice powder\r\n1 teaspoon crushed red pepper flakes\r\n5 (6 ounce) skinless, boneless chicken breast halves - cut into chunks\r\n5 tablespoons vegetable oil\r\n1 yellow onion, cut into thin wedges\r\n1 green bell pepper, seeded and thinly sliced\r\n6 tablespoons teriyaki sauce\r\n5 tablespoons honey****\r\n1/2 cup toasted sesame seeds, divided', '6 to 24 hours earlier, put chicken and buttermilk in to a bag.  Seal and refrigerate  until ready to cook.  Longer the better. Makes all chicken soooo  tender.  Remove and pat dry..  continue...\r\nIn a large resealable plastic bag, combine flour, 1/4 cup sesame seeds, black pepper, five-spice powder, and red pepper flakes. Place a few pieces of chicken at a time into the bag, and shake to coat. Remove to a platter.\r\n\r\nHeat oil in a large skillet or wok over medium-high heat. Place chicken into skillet, and brown on both sides, about 5 minutes. Remove chicken, and set aside. Stir onion wedges and bell pepper slices into skillet; cook until slightly browned, about 2 minutes. Remove, and set aside.\r\n\r\nReturn chicken to skillet, and reduce heat to low. Mix teriyaki marinade and honey in bowl - then pour into skillet; stir until sauce thickens. Return Chicken to finish cooking then add onion and bell pepper to the skillet. Warm through, and serve with sesame seeds sprinkled on top.', 'Recommend steamed broccoli and rice as sides.\r\n***  re the honey.. taste test the sauce before using.  If too sweet add some soya sauce.  Not sweet enough - add some more honey or brown sugar.', 10),
(115, 'Individual Chocolate fondue dessert', 'ï¿½ cup (125 mL) whipping cream\r\nï¿½ cup (125 mL) milk\r\n2 sprigs rosemary\r\n1/3 lb (170 g) bittersweet chocolate, finely chopped', '1. In a pan over medium heat, bring cream and milk to a boil. Add rosemary and remove from heat. Cover and let infuse 30 minutes.\r\n\r\n2. Remove rosemary and add chocolate. Place over low heat and stir until chocolate melts. Keep refrigerated.\r\n\r\n3. Bring to room temperature and serve with various fruits to dip. Can be placed into individual dishes such as egg cups or small coffee cups.\r\n\r\nMakes 1 1/2 cups (375 mL)', 'Very pretty served in tiny tea cups on saucers - raspberries and small pieces of pineapple to be picked up in fingers and dipped.', 2),
(116, 'Herb and Grilled Eggplant', '2 medium egg plants, sliced vertically into 1/4 inch slices\r\nabout 2/3 cup extra virgin olive oil\r\n4 cloves garlic - large and minced.\r\n3/4 cup minced italian parsley and same of basil\r\n1/8 tsp fresh ground peppper\r\nsalt to taste', 'Lightly brush both sides of each eggplant slice with oil.  Blend together everything else and spread a little on both sides of each slice.  lay slices side by side on large platter, stacking if necessary.  Lightly cover with platstic wrap and let stand at room temperature for 2 to 4 hours.  \r\nLightly sprinkle with salt. Grill over medium heat for 10 minutes turning once until golden brown on each side.  spoon any leftover seasonlngs over when turning.', 'Serves 6 to 8.  Best served warm or at room temperature.  Do not refrigerate as it gets bitter.  Cook no more than 4 hours before eating and keep at room temp.  You can serve as a side or on its own served with an aoil sauce or even tomato sauce drzzled on top for a first course.  Shaved parm cheese on top.  Plated.  You can also use zucchini - but cook it at a higher heat for only 2 minutes per side.', 8),
(117, 'green beans bolognese', '2 to 3 tbsp olive oil\r\n1 small onion thinly sliced\r\n1 pound green beans trimmed and halved\r\n2 ounces mortadella (italian sausage) minced\r\n1 cup chicken or beef stock\r\npinch ground cloves\r\nsalt and pepper to taste', 'heat oil in large skillet over medium het.  Add oninand saute until wilted.  Add beans and cook over high heat for 8 minutes or until the onions are deep golden brown.  Stir frequently.  Stir in the mortadella, stock and cloves and bring to gentle bubble over medium low heat. Cover and cook 15 minutes (checking for sticking) or until the beans are tender.  Concentrate the flavours by uncovering and boiing off al the liquid until just a thick sauce covers them.  Serve in a warm bowl.  ', 'Can be cooked ahead and reheated.  Keep at room temp, lightly covered.  Works best with balsamic or lemon flavoured grilled meats\r\nServes 6 or 8 as a side dish', 8),
(119, 'Thai Fish Curry - soup or full meal', '500 pkg frozen cod\r\n1 bunch green onions - finely chopped\r\n2 tbsp veg oil\r\n3 garlic cloves - minced\r\n2 tbsp thai green curry paste\r\n3 cups broccoli - bite sized\r\n400 ml can of light cocoanut milk\r\n1 tbsp fish sauce\r\n2 tbsp lime juice**\r\n1 tbsp lime zest***', 'Let fish defrost for 20 mnutes then cut into 1 inch cubes\r\n\r\nHeat a large pot over medium high heat.  Add oil.\r\n\r\nReserve 1/4 cup onions for garnish.  Add rest to the pot and saute with garlic, and curry paste.  Cook for 2 minutes.  Add broccoli, milk, 1/2 cup water and fish sauce.  Bring to boil then reduce to a simmer.  Cok until broccoli is tender.   Add cod and cook unitl cooked - 5 minutes.  Stir in lime juice and zest.  Turn off heat.  Spoon into bowls and then srinkle with saved onion.  ', 'Serves 2 as a main meal.  If you spoon it over jasmine rice - it makes  a great meal!!  \r\n\r\n**  I did not have a lime - so I used 1 tbsp lemon juice and 1 tbsp orange juice and skipped the zest.  I thought it was terrific!!', 5),
(120, 'Lentil, Kale, and Sausage Soup', '5-inch piece smoked kielbasa, sliced thin - bite sized pieces\r\n2 teaspoon vegetable oil if necessary\r\n4 garlic cloves, minced\r\n2 small onion, coarsely chopped - bite sized pieces***\r\n1 can lentils - drained and rinsed\r\n6 cups chicken broth  ***\r\n1 small bunch kale, stems and center ribs discarded and leaves **sliced thin - bite sized is best (about 4 cups)  ***\r\n2 tablespoon balsamic or red-wine vinegar\r\n\r\n\r\n', 'Spray pot with oil and brown kielbasa. Remove to bowl.  Add more oil if required to saute onions and whatever other vegs you want to add***.  Cook 5 minutes. Meanwhile - wash Kale and run hand up, gripping stem to remove centre stalk.  then chop into bite sized pieces. Then add the lentils, broth and Kale to onions.  Simmer 10 minutes.  Turn off heat and add the vinegar.  Season with salt and pepper at the table to taste.  Sausage could be salty so be careful with salt.', 'You can use any kind of sausage you like.  I used turkey kielbassa.  Chicken sausage would be great too ( 2 or 3 would probably be enough - casings removed. Hot or mild italian??   I added 2 ribs of celery and 2 carrots.  I used a mixture of beef and chicken broth as that is what I had on hand.  Makes a great meal with some fresh bread.  I guess some parm cheese on top would be good as well.  Have not tried it though.', 5),
(121, 'Baked Coconut Shrimp', '340 g frozen raw jumbo shrimp, peeled - 15 or 18  ***\r\n1/4 cup cornstarch or all purpose flour\r\n1/4 tsp salt\r\n3/4 cup Thai sweet chili sauce - divided\r\n2 tbsp rice vinegar\r\n1 cup unsweetened medium desiccated coconut, toasted', 'Preheat oven to 400F. Line a large rimmed baking sheet with foil and lightly spray with oil. Thaw shrimp following package directions. Pat dry with paper towels.  Butterfly but keep the tails on - cut almost through from the underside so they are flat. Stir cornstarch with salt and pepper in a shallow dish. In a small bowl, stir 1/2 cup chili sauce with vinegar. In another shallow dish, spread out coconut. Sprinkle and rub the shrimp with cornstarch mixture - just the top is good - takes a bit of time, but worth not getting the extra starch that you don\'t need. Then, shaking off excess starch, dip each in chili-sauce mixture and then coat only the top again with coconut. Place shrimp on foil.\r\nBake in centre of oven until shrimp is cooked through, about 5 or 6 min. If the shrimp are not crispy - put under the broiler for a few seconds.  Serve remaining sweet chili sauce alongside as a dipping sauce.\r\nSubstitution Tip:\r\nCan’t find sweet chili sauce? Stir 1/2 cup honey with 2 tbsp each chili-garlic sauce and rice vinegar.', 'I tried making this with the shrimp not butterflied and the coconut just fell off the bottom of the shrimp  half way through - so no point in turning it.  I think butterflying it you will not need to turn it and the whole top will be crispy.  \r\n\r\nIt tastes great a just a bit sticky as the coconut was soft on on the bottom....  hence now only coating the top then broiling.  \r\n\r\nLater note:  works much better in the air fryer oven!!  Just be sure to not overcook!!\r\n\r\nNeedless to say - if you need more - just up the coating amount.', 9),
(122, 'Domino\'s/ Nanimo Bars', '**Bottom Layer ***\r\n\r\n    * 1/2 cup unsalted butter (European style cultured)\r\n    * 1/4 cup sugar\r\n    * 5 tablespoons cocoa\r\n    * 1 egg beaten\r\n    * 1 1/4 cup graham wafer crumbs - basically 2 sleeve of graham crackers grated\r\n    * 1/2 cup finely chopped almonds\r\n    * 1 cup coconut\r\n\r\n***Second Layer ****\r\n\r\n    * 1/2 cup unsalted butter\r\n    * 2 tablespoons cream PLUS\r\n    * 2 teaspoons cream\r\n    * 2 tablespoons vanilla custard powder\r\n    * 2 cups icing sugar\r\n\r\n***Third Layer ***\r\n\r\n    * 4 squares semi-sweet chocolate (1 oz. each)\r\n    * 2 tablespoons unsalted butter', 'Bottom Layer\r\nOver a double boiler: \r\nMelt first 3 ingredients large glass bow. Add egg and stir.  Cook 30 secs more to cook and thicken. Remove from heat. Stir in crumbs, coconut, and nuts. Press firmly into an ungreased 8\" x 8\" pan. .....  Note - I line the pan with wax or parchment paper.\r\n\r\nNote, if you do use the microwave, bake the bottom layer for 8 minutes in a 350 oven...  due to the egg.\r\n\r\nSecond Layer\r\n\r\nCream butter, cream, custard powder, and icing sugar together well. Beat until light. Spread over bottom layer.\r\n\r\nThird Layer\r\n\r\nMelt chocolate and butter overlow heat. Cool. Once cool, but still liquid, pour over second layer and chill in refrigerator.\r\n\r\nThis recipe for Nanaimo Bar (Official) serves/makes 24 bars.', 'This is pretty well the same as Gramma Mary\'s recipe except she uses vanilla pudding mix instead of custard.  Note - I just use 2% milk and that is perfectly fine or even skim.  Just add more butter to keep the richness there.', 13),
(123, 'Gramma Mary\'s Pork Tenderloin', '2 lb pork tenderloin\r\n2 tbsp soya sauce\r\n2 tbsp white sugar\r\n1 tbsp sherry\r\n1/2 tsp salt\r\n1/2 tsp cinnamon', 'Blend the spices and soya.  Rub all over the pork.  Let Stand at least 2 hours.  Then cook the pork slowly - on the lowest rack in the oven - under the broiler.  Turn frequently and leave the oven door open slightly if possible.', 'You have to keep an eye on it, but it really sets the flavour into the meat!!!\r\n\r\nCanadian Living\'s version includes 2 tbsp honsin sauce, 1 clove garlic and instead of cinnamon it says a pinch of 5 spice powder.  Then you bake it for 1/2 hour.  Less fussing but does not have the same texture or taste.', 12),
(124, 'Babushka\'s refrigerator rolls', '1/3 lb Tenderflake 1 cup boiling water 1 cup cold water 6 cups flour 3/4 cups white sugar 2 tsp yeast + 1/2 cup warm water+1 tsp sugar 2 eggs 1 tsp salt 1 tsp almond flavor (optional) 		', 'Preheat oven 350.  Cream Tenderflake and sugar, add boiling water and cool. Add yeast into 1/2 cup warm water with 1 tsp sugar. Add yeast to tender flake mixture and add cold water. Add eggs and mix well. Add flour and salt. Knead well. Place in refrigerator overnight or until wanted. Roll into desired shapes and let rise for 1 hour. Bake in hot oven for 20 minutes. The dough may be kept for several days. ', 'These are the dinner rolls that Bushka always made into flowers, birds, slip knots and twists. She used to brush them with an egg wash and sometimes put sesame seeds on the top. They are similar to egg bread rolls. ', 7),
(125, 'No-Butter Butter Chicken', '1/4 cup grapeseed oil - not olive as it cannot take the high heat. Reg. veg if no grapeseed.\r\n2 large onions, chopped\r\n2 tbsp finely chopped garlic\r\n2 tbsp finely chopped ginger\r\n2 tbsp tomato paste\r\n1 tbsp cumin seeds\r\n1 tbsp Garam Masala\r\n1 tbsp brown sugar\r\n1 tsp red pepper flakes\r\n1 tsp ground turmeric\r\n1 tsp salt\r\n1 lb boneless, skinless chicken breast, cut into bite-sized pieces\r\n3/4 cup low-fat plain yogurt\r\n1/4 cup water\r\n\r\n', 'Directions\r\n1. Place the oil in a non-stick skillet over high heat, add the onions, and sauté until dark golden brown. Add the garlic and ginger, reduce the heat to medium, and cook for 2 minutes. Add the tomato paste and cumin seeds and cook for 30 seconds.\r\n\r\n2. Reduce the heat to low, add the garam masala, brown sugar, red pepper flakes, turmeric, and salt, and cook for 2 minutes. Mix in the chicken and cook until the chicken is almost done, about 5 to 7 minutes. Add the yogurt and water, and cook until the chicken is fully cooked, about 5 minutes. Serve it with brown rice or plain rotis.\r\n\r\nServe with rice and perhaps flat bread on the side\r\n', 'Serves 4 .  From Everyday Indian by Bal Arneson.   Erika and I like this one a lot.', 10),
(126, 'Inga Garten\'s Hummus', '3 garlic cloves\r\n2 cups canned chickpeas, drained, liquid reserved\r\n1 teaspoons kosher salt - or a bit more to taste\r\n1/3 cup tahini (sesame paste)\r\n3 tablespoons freshly squeezed lemon juice (1 lemon)\r\n2 tablespoons water or liquid from the chickpeas\r\n6 to 8 dashes hot sauce\r\n', 'Directions\r\nTurn on the food processor fitted with the steel blade and drop the garlic down the feed tube; process until it\'s minced. Add the rest of the ingredients to the food processor and process until the hummus is coarsely pureed. Taste, for seasoning, and serve chilled or at room temperature.', 'This is great dip - not sure of the calorie count', 9),
(127, 'Goulash - change up from spaghetti - makes lots', '2 tbsp oil\r\n2 lbs lean ground beef\r\n1 green pepper - seeded and diced\r\n1 onion - diced\r\n2 jalapenos - or 1 - 2 cans of  green chilies ( small in Mexican aisle)\r\nsalt and pepper to taste\r\n2 tbsp chili powder or to taste\r\n1 tsp cinnamon ( optional - but a great taste)\r\n1 tsp ground cumin ( optional - or replace with garlic)\r\n3 cans of stewed or diced tomates  425 grams each) do not drain\r\n1 pound of whole wheat noodles - whatever shape you like (shells or macaroni or fusilli etc\r\n2 cups romano or lima beans (optional - could replace with left over cubed potatoes)\r\nSour cream for putting on top\r\n', 'Heat oil in large pot.  Add beef, onion and chilies or peppers.  Cook stirring often until meat is cooked and veggies are tender.  Season with half tsp each of salt and pepper - can always add more later.  Then chili powder, cinnnamon, cumin etc.  Canned tomatoes.   Bring to a boil then simmer for 15 minutes.  Stir occassionally and taste to determine how spicy you want to go.  \r\nCook pasta seperately as usual.  Drain.  Put some on a plate.  Spoon some goulash on top.  Put a heaping table spoon of sour cream on top of that and stir it all around. Eat and enjoy', 'Good for left overs. ', 12),
(128, 'Fast fix chicken enchilladas - Scott helped make and they are so good', '1.25 to 1.5 pound of boneless skinless chicken breasts (or otion - 1 ground chicken)\r\nsalt and pepper\r\n1 tbsp olive oil\r\n1 cup sliced mushrooms (optional - but great)\r\n1 clove garlic (or 1 tsp minced from a jar)\r\ngrated skin from one lemon plus the juice - note go light on the skin as you only want the yellow part.  White stuff underneath is bitter.\r\n1 tsp ground cumin\r\n1 tsp ground corriander (optional - Al hates it)\r\n3 cups whole baby spinach ( could use 1 package frozen - thawed and squeezed dry)\r\n4 green onions ( or half of regular onion - if using, add to chicken with other veggies)\r\n1 can of diced green chilies ) mexican aisle\r\n1/2 cup sour cream - full fat so it does not seperate\r\n2 cups shredded Monteray cheese ( cheddar works too) extra cheese will not go amiss!!!!!\r\n2 cans of green enchilada sauce - soup can size\r\n1 or 2 cans of the hotter red enchilada sauce (recipe calls for green only, but that is too mild for me so I mixed them together)\r\n8 large whole wheat tortilla could have enough for 1 or 2 more depending on how you stuff\r\nsalsa for the table and sour cream\r\n\r\nCook in 9 x 13 dish or flat lasagna dish type thing.  Shape does not matter as long as you can put 8 rolled tortillas in single layer.  Bigger is better than smaller.', 'Dice the raw chicken or just use ground.  Sprinkle with salt and pepper.  Heat oil in large fry pan.  Add chicken and cook 3 minutes to brown.  Stir.\r\nAdd mushrooms and cook, stirring for 2 minutes. Cover and cook until mushrooms are soft.  Add garlic, lemon zest and juice, spices and spinach.  Stir thoughly and cover with lid.  Cook until spinach is wilted and chicken is cooked all the way through ( no pink!!)\r\nTransfer chicken mixture to a large bowl.  Add green onions, green chilies, sour cream and 1 cup cheese.  Stir and set aside.\r\nHeat enchillada sauce to warm.  Then dip the one tortilla in it to coat and swipe off extra into bowl again.  Lay tortilla in cooking dish.  Put in 1/8 of the mixture and roll up.  Continue until all is used up.  Pour extra enchellada sauce on top and sprinkle with extra cheese.  Cover with foil that has been sprayed with oil.  Bake 20 minutes or so until bubbling.  Uncover and cook for another 10 minutes until lightly brown.  Serve with sour cream and salsa as per taste.', 'You could also skip filling the tortillas and just layer things in a pan and bake.  So.... grease a 9 x 13 pan well, then put a layer of the final chicken mix down.  Then put down a layer of the soaked tortillas - cut into shapes to fit the pan......  then another layer of the chicken and then the soaked tortillas, etc until you are done.  Finish with the extra cheese, cover and bake 20 as per the instructions above.  Then eat like lasagna.  Filling the tortillas gets messy on the hands.', 10),
(129, 'Best boiled eggs', 'eggs\r\nwater', 'Place eggs (older eggs will be easier to peel) in a pot. Add water to cover by 1 1/2\".    Cover with lid.  Bring to a boil; immediately remove from heat. Cover and let stand for 10 minutes. Transfer eggs to a bowl of ice water to cool. Gently crack the eggs and peel under running water for ease.\r\n\r\n', 'East whole or chop up with mayo and some onion - throw between 2 slices of bread.  ', 15),
(130, 'Chicken Pad Thai', '/2 pkg (14 oz/400 g) wide rice stick noodles**\r\n2/3 cup (150 mL) chicken stock\r\n1/2 cup (125 mL) ketchup\r\n1/4 cup (50 mL) fish sauce**\r\n2 tbsp (25 mL) granulated sugar\r\n2 tbsp (25 mL) cornstarch\r\n1 tsp (5 mL) grated lime rind\r\n2 tbsp (25 mL) lime juice\r\n1 tsp (5 mL) hot pepper sauce  **\r\n4 tsp (18 mL) vegetable oil\r\n2 eggs, lightly beaten\r\n1 lb (454 gr) boneless skinless chicken breasts, sliced\r\n4 carrots, thinly sliced\r\n1 sweet red pepper, sliced\r\n2 cloves of garlic, minced\r\n1 tbsp (15 mL) minced gingerroot\r\n2 cups (500 mL) bean sprouts\r\n2 green onions, sliced\r\n1/4 cup (50 mL) chopped unsalted peanuts**', 'In large bowl, soak noodles in warm water for 20 minutes; drain and set aside.\r\n\r\nMeanwhile, in small bowl, whisk together stock, ketchup, fish sauce, sugar, cornstarch, lime rind and juice and hot pepper sauce; set aside.\r\n\r\nIn wok or large skillet, heat 2 tsp (10 mL) of the oil over medium heat; cook eggs, stirring often, for 2 minutes or until scrambled and set. Transfer to plate.\r\n\r\nWipe out wok; add remaining oil. Brown chicken, in batches, over medium-high heat. Transfer to separate plate.\r\n\r\nAdd carrots, red pepper, garlic and ginger to pan; cook, stirring, for about 3 minutes or until slightly tender. At this point, you can sit down....  it now takes less than 5 minutes to pull it together.  Guest arrive...  do the next few steps just before you want to eat.\r\n\r\nAdd noodles; stir gently for 1 minute.\r\n\r\nReturn chicken to pan. Stir sauce and pour into pan; cook, stirring, for 3 minutes or until thickened, noodles are tender and chicken is no longer pink inside.\r\n\r\nReturn egg mixture to wok along with bean sprouts; toss gently for 1 minute or until heated through. Serve sprinkled with green onions and peanuts.\r\n\r\nServings: 4\r\n', '** - I used thin stir fry rice noodles - much easier to eat.I  ** used Oyster sauce - almost the same as fish sauce.  **Hot sauce refers to the hot chinese chili sauce - found everywhere.  I love it.  I doubled the amount and that was enough for me.  Dad added a bit more to his place - as it is served with a small bowl of the hot sauce on the side in restaurants. ** I did not have peanuts, but did have salted, roasted soy nuts.  These are not really essential to the dish if you don\'t have them on hand.  ', 4),
(131, 'whole wheat banana bread', '1 cup (250 mL) quick-cooking rolled oats3/4 cup (175 mL) all-purpose flour3/4 cup (175 mL) whole wheat flour1/2 cup (125 mL) packed brown sugar1-1/2 tsp (7 mL) cinnamon1 tsp (5 mL) baking powder1 tsp (5 mL) baking soda1 egg1-1/2 cups (375 mL) mashed bananas, about 31/3 cup (75 mL) vegetable oil1 tsp (5 mL) vanilla1 cup (250 mL) dried cherries or raisinsTopping2 tbsp (30 mL) quick-cooking rolled oats', 'In large bowl, whisk together rolled oats, all-purpose and whole wheat flours, sugar, cinnamon, baking powder and baking soda.\r\n\r\nIn separate bowl, whisk together egg, bananas, oil and vanilla; pour over dry ingredients. Sprinkle with cherries; stir just until moistened. Scrape into parchment paper-lined 9- x 5-inch (2 L) loaf pan; smooth top.\r\n\r\nTopping: Sprinkle with rolled oats. Bake in centre of 350Â°F (180Â°C) oven until cake tester inserted in centre comes out clean, about 1 hour. Let cool in pan for 10 minutes. Remove from pan; let cool on rack.\r\n\r\nSource : Canadian Living Magazine: November 2003', 'I am not fond of raisins, but they cut down on the sugar needed and Al likes them in the loaf.', 7),
(132, 'Crunch Granola cereal', '1 large beaten egg white\r\n3 cups large flake oats, 1 1/2 cup chopped nuts (almonds, pecans)1 1/2 cups sweetened or plain coconut flakes, 1/2 cup agave syrup, 1/4 olive oil - or warmed coconut oil, 1 cup whatever type of seeds you want, 2 tbsp packed brown sugar, 1 1/2 tsp salt, 1/2 tsp ground cinnamon', 'Preheat oven to 300 degrees.  In a large bowl, toss everything to combine.  spread out on 2 rimmed cookie sheets.  Bake, stirring every 10 minutes, until golden brown and dry - approx 30 minutes.  Stir after removing and let it cool on the sheet.  It will crisp as it cools.  Store for 2 weeks.', 'You can virtually add any type of nut or dried fruit.  I have forgotten the oil on occassion and have never missed it.  The recipe calls for unsweetened cocoanut flakes, but I like the sweetened type.  You can use honey or maple syrup instead of the agave syrup.  ', 6),
(133, 'Blue Cheese Chicken', '4 boneless, skinless chicken breasts.  1 box frozen chopped spinach, 1/3 cup blue cheese salad dressing, 1 cup crumbled blue cheese, 4 to 6 strips smoked proscuitto, salt and pepper', 'Preheat oven to 350.  Butterfly the breasts.  Season with pepper and light salt.  Thaw spinach and squeeze dry.  In a bowl, mix spinach and salad dressing.  Divide evenly between the breasts - running it down the spine of the breast.  Divide blue cheese and place on top of the spinach.  Fold over the breast.  Wrap a piece of proscuitto around each breast and secure with toothpick.  Heat a grill pan with oil then sear the chicken on both sides to get color.  Remove to a baking pan.  Cover with foil and cook approx 20 minutes until no longer pink.  Serve with juices drizzled over.', 'Preferable to have longer strips of proscuitto - easier to wrap and secure.', 10),
(134, 'Creme Brule - from Joy of Baking', '1 1/3 cups (320 ml) heavy \'whipping\' cream (cream with a 35% butterfat content)\r\n\r\n1 vanilla bean, split and seeds removed (or 1 1/2 teaspoons pure vanilla extract)\r\n\r\n4 large (60 grams) egg yolks, room temperature\r\n\r\n1/4 cup (50 grams) granulated white sugar\r\n\r\nabout 4 tablespoons (60 grams) superfine white sugar (caster sugar)\r\n\r\n\r\n\r\nRead more: http://www.joyofbaking.com/puddings/CremeBruleeRecipe.html#ixzz2LpmgimUO', 'Preheat oven to 300 degrees F (150 degrees C) and place rack in center of oven. Place 4 - one cup (240 ml) CrÃ¨me BrÃ»lÃ©e dishes or ramekins in a roasting pan.\r\n\r\nIn a saucepan, over medium-high heat, bring the cream and the vanilla bean and seeds to the scalding point (the cream just begins to bubble around the edges). Remove from heat and remove the vanilla bean.\r\n\r\nMeanwhile in a heatproof bowl beat the egg yolks and sugar until thick and pale (about 1-2 minutes). (You can do this with a wire whisk or hand mixer.) Gradually pour the scalding cream into the egg yolk mixture, making sure you keep whisking constantly so the eggs don\'t curdle. (Stir in vanilla extract, if using.) Strain into a large measuring cup or pitcher and then evenly pour the custard into the ramekins. Prepare a water bath (bain marie) by carefully pouring enough hot or boiling water so that the water comes halfway up the sides of the ramekins. Bake for about 30 - 40 minutes (baking time can vary depending on size of ramekins and temperature of water) or just until the custards are set (a slight wobble is okay).\r\n\r\nImmediately remove the custards from the water bath and cool to room temperature on a wire rack (about one hour). Refrigerate (uncovered) for at least 4 hours or until cold and firm. At this point they can be stored (covered) in the refrigerator for about three days.\r\n\r\nTo serve, remove the custards from the refrigerator. Sprinkle an even, not too thick, layer (about 1 tablespoon (15 grams)) of superfine sugar over the custards. Using a hand held kitchen torch, or under a very hot preheated broiler, caramelize the sugar until it is golden brown and bubbly. If using a torch, place it about 2 inches (5 cm), at an angle, over the custard and move the torch around until the sugar melts and caramelizes. Let sit a few minutes so the sugar can harden then serve.\r\n\r\nServes 4.\r\n\r\n\r\nRead more: http://www.joyofbaking.com/puddings/CremeBruleeRecipe.html#ixzz2LpmuSyem', 'You can make your own superfine sugar by putting regular granulated sugar into a food processor for a couple seconds.', 3),
(135, 'Japanese Goyza or Pot Stickers', '4 cups, loosely packed, minced Napa cabbage (use the frilly leafy half of the cabbage)\r\n1/2 teaspoon table salt\r\n9 ounces ground pork\r\n1/2 tablespoon freshly grated ginger (with a Microplane grater)\r\n2 â€“ 3 cloves garlic, finely minced\r\n1 tablespoon green onion (green part only), minced\r\n2 teaspoon aka miso paste (red/dark miso paste)\r\n1 teaspoon sesame oil\r\n1 teaspoon crushed red chili pepper\r\n1/4 teaspoon sugar\r\n40 dumpling wrappers\r\n\r\nFor cooking the dumplings:\r\n1 tablespoon sesame oil\r\n1/2 cup water\r\n\r\nDipping Sauce:\r\n6 tablespoons soy sauce\r\n3 tablespoons rice vinegar\r\nSeveral drops of chili oil or sesame oil (optional)', '1. Toss the minced cabbage with the salt in a large bowl and let it sit for 10 minutes.  Using both hands, or a cheese cloth, squeeze the cabbage firmly to drain and discard the excess water (prevent your dumplings from becoming mushy) and then transfer the cabbage to a deep bowl.  Add the pork, ginger, garlic, green onion, miso, sesame oil, crushed red pepper, and sugar.  Mix everything together with your hands until all the ingredients are evenly distributed.  Using your hands, scoop the mixture into a ball, lift it, and then throw it back into the bowl.  Repeat several times to tenderize the meat and help the mixture stick together.\r\n\r\n2. Have a small bowl of cold water ready.  Lay a dumpling wrapper on a dry work surface, and place a heaping teaspoon of the meat mixture in the center of the wrapper.  With a fingertip moistened with water, trace a line along half of the edge of the round wrapper.  Fold the wrapper over to enclose the filling, and pinch the wrapper in the center to seal the edges together at that spot.  Holding the filled half-circle in the left hand, pleat the top of the wrapper from the middle out, pressing it to the flat edge of the wrapper at the back.  Set aside the stuffed dumpling with the pleated-wrapper edge up. Repeat to make 40 dumplings in all.\r\n\r\n3. In a large skillet with a tight fitting lid, heat 1 teaspoon of the sesame oil over medium-high heat. Carefully place as many of the dumplings that can fit without touching in the skillet with the pleated-wrapper edge up.  Cook the dumplings for 3 minutes, or until nicely browned on the bottom.  Check the progress by lifting 1 or 2 dumplings by their pleated edge.\r\n\r\n4. Once the bottoms are nicely browned, use the skillet lid to shield yourself and carefully pour in 1/4 cup of the water.  When the hissing and splattering die down, drizzle in 1/2 teaspoon of the sesame oil around the edge of the skillet.  Place the lid on the skillet to trap in the moisture and then quickly lower the heat to keep the liquid at a bare simmer.\r\n\r\n5. Check the dumplings after 2 minutes.  When the wrappers appear slightly translucent and the meat feels firm when pressed lightly with a spoon, remove the lid and raise the heat slightly.  Continue to cook until all the water has evaporated and only the oil remains (about 2 minutes).  Once you hear a sizzling sound, shake the skillet.  The dumplings should slide about.  If they seem to stick to the skillet, move the skillet away from the stove and replace the lid for a moment.  Remove the dumplings from the skillet with a broad flexible spatula. If youâ€™d like, flip them over so that the seared surface faces up.  Cook the remaining dumplings the same way.  Serve the dumplings hot accompanied by the dipping sauce.\r\n\r\n4. While the dumplings are cooking, make the dipping sauce by mixing the soy sauce and rice vinegar together in a small bowl.  Pour the sauce into a small serving pitcher or distribute among individual dipping dishes.', 'This is typically more work than I like.  Tasted good, but just easier to buy frozen and make your own soya dip!!\r\n\r\nhttp://www.steamykitchen.com/5874-gyoza-recipe-japanese-pan-fried-dumplings.html', 9),
(136, 'No Knead Bread', '3 cups bread flour (I like Whole Wheat Best for Bread)\r\n1/2 teaspoon instant yeast\r\n1 teaspoon fine table salt (or 3/4 tablespoon of kosher salt)\r\n1 1/2 cups warm water - may need more for ww flour - should be sloppy dough\r\n1 1/2 tbsp molasses - mix into the warm water\r\nCovered pot (five-quart or larger cast iron, Pyrex, ceramic, enamel...something that can go into a 450F oven.)', '1. Mix dough: The night before, combine all ingredients in a big bowl with a wooden spoon until the dough just comes together. It will be a shaggy, doughy mess. Cover with plastic wrap and let sit 12-20 hours on countertop.\r\n\r\n2. Shape & preheat: The dough will now be wet, sticky and bubbly. With a wet spatula, dump the dough on a floured surface. Fold ends of dough over a few times with the spatula and nudge it into a ball shape. You can use your hands if you like, just keep your hands wet so that the dough does not stick. Place a large sheet of parchment paper on counter. Plop your dough onto parchment paper. Lift parchment paper up with dough and place into a large bowl. Cover bowl with a towel. Let it nap for 2 hours. When you\'ve got about a half hour left, slip your covered pot into the oven and preheat to 450F.\r\n\r\n3. Bake: Your dough should have doubled in size. Remove pot from oven. Grab the ends of the parchment paper and lift entire wobbly dough blob out of bowl into pot. Doesn\'t matter which way it lands. Shake to even dough out. Cover. Bake 30 minutes. Uncover, bake another 15-20 minutes or until the crust is beautifully golden and middle of loaf is 210F. Remove and let cool on wired rack. If not eating right away, you can re-crisp crust in 350F oven for 10 minutes. Best way to eat it? Smear a warm slice with some good butter (Kerrygold and Lurpac are both found in your grocery stores, usually on top shelf)', 'I am going to try cooking it in a usual bread pan and see what happens.\r\n\r\nhttp://www.foodnetwork.ca/recipes/recipe.html?dishid=9530', 7),
(137, 'Fast Easy Healthy Salmon', 'salmon fillet enough for 2 - with skin on\r\n1 tbsp olive oi\r\n1 cup halved cherry tomatoes\r\ncouple handfulls of fresh spinach\r\n2 tbsp balsamic vinegar', 'Heat a cast iron or stainless pan to high.  Drizzle in olive oil.  When it is hot, put the salmon in, skin side down to sear.  When it is cooked half way.... Flip it over, add the tomatoes and the spinach.  Cover and cook until the salmon is done.  Transfer everything to a serving dish.  Then pour 1.5 to 2 tbsp balsamic vinegar into the hot pan.  Cook 30 seconds.  Remove and pour over the damon.  Serve.', 'This is great served over quinoa, rice, couscous....  but quinoa is best as it is a protein source.  This really is so good and so easy!!  And moist if you cover the pan after putting in the veggies.', 14),
(138, 'Fast Easy Healthy Salmon', 'salmon fillet enough for 2 - with skin on\r\n1 tbsp olive oi\r\n1 cup halved cherry tomatoes\r\ncouple handfulls of fresh spinach\r\n2 tbsp balsamic vinegar', 'Heat a cast iron or stainless pan to high.  Drizzle in olive oil.  When it is hot, put the salmon in, skin side down to sear.  When it is cooked half way.... Flip it over, add the tomatoes and the spinach.  Cover and cook until the salmon is done.  Transfer everything to a serving dish.  Then pour 1.5 to 2 tbsp balsamic vinegar into the hot pan.  Cook 30 seconds.  Remove and pour over the damon.  Serve.', 'This is great served over quinoa, rice, couscous....  but quinoa is best as it is a protein source.  This really is so good and so easy!!  And moist if you cover the pan after putting in the veggies.', 14);
INSERT INTO `recipe` (`recipeID`, `recipe_title`, `recipe_ingredients`, `recipe_method`, `recipe_note`, `catID`) VALUES
(139, 'Tomatoe soup', '2 tbsp ripe tomatoes, 1 small onion, 1 tbsp olive oil,  sea salt and pepper, 2 tbsp chopped parsley**** 3 garlic cloves 1.5 cups of veggie broth, 2 tbsp tomato paste, 1/2 cup 2% milk, 4 slices of thick ww bread, shredded motz cheese.', 'Preheat oven to 350.  Cut tomates into wedges... roughy remove major sections of seeds.  Cut onion in to wedges and put into a roasting pan with tomatoes.  Tuck whole garlic cloves into  nooks of tomatoes so they don\'t burn.  Drizzle with olive oil, parsley and then toss.  Roast 30 minutes until half the size.  Remove.\r\n\r\nMeanwhie, heat broth and tomato paste.  When the veggies are done, put into the pot with broth.  Puree until smooth.  Add milk and taste test.\r\n\r\nJust before serving, drizzle bread with olive oil, put cheese on top and broil for 1 minute or so.  When done...  ladle soup into bowls and float a piece of bread on top.  Serve with pepper and salt for taste.', 'This is pretty good and looks good for presentation.', 9),
(140, 'Adult Mac and Cheese - diet right', '1/4 cup unsalted butter\r\n1/3 cup plus 1 1/2 grated parm, divided\r\n1/4 all purpose flour\r\n4 cups 2% milk\r\n1 cup shredded Fontina Cheese\r\n1 large egg\r\nsalt and pepper\r\n1 lb rigatoni or any tube pasta\r\n1 cup frozen peas - thawed.\r\n2 cups coarsely chopped arugula\r\n1 cup plus coarsely choppped parsley\r\n1/2 cup coarsely chopped mint\r\n1 cup ricotta\r\n1/2 tsp finely grated lemon zest\r\n\r\n', '1. Butter 9 in springform pan or 9 x 9 pan.  Dust all over with 1/3 cup park.  Melt 1/4 butter in a large pot.  Add flour and whisk for 2 minutes.  Gradually whisk in milk.  Bring to simmer, whisking often.  Reduce to medium.  cook, whisking until thickened 20 minutes.  Remove from heat and whisk i Fontina and 1 cup Parm.  Add egg.  Whisk to blend.  Season with salt and pepper.  Cover and keep warm.\r\nArrange rack in upper 3rd of oven and preheat to 375.  Cook pasta until almost al dente.  Throw in peas for 1 minute.  Drain all.  Stir in cheese sauce.  Add arugula, 1 cup parsley and 1/2 cup mint.  Stir gently.  \r\nTransfer half to prepared pan.  Mix ricotta and lemon zest .  Dot half over the pasta.  Spoon remaining pasta onto pan and dot with remaining ricotta.  Sprinkle with 1/4 cup parm.  \r\nBake 30 minutes.  Sprinkle with remaining 1/4 park.  Bake till golden.  Remove and rest for 30 minutes.  Remove pan sides.  Sprinkle with some parsley and mint.  Cut into wedges', 'From Bon Apppetite March 2012 - pretty bland.  I would say no mint...  anduse it as a side to a tomato covered chicken dish', 11),
(141, 'Wasabi Salmon with Bok Choy, GreenCabbage and Shitakes', '1/4 cup mayonnaise\r\n1 tsp wasabi paste\r\n1 2 inch piece ginger, peeled and finely grated - divided\r\n2 large garlic cloves, grated - divided\r\n4, 6 oz skinless salmon fillets\r\nsalt and pepper\r\n2 cups packed and finely shredded green cabbage\r\n4 oz scihtakie mushrooms, sliced\r\n1 lb bok choy, halved\r\n2 tbsp olive oil', 'Preheat oven to 450.  Heat a large rimmed baking sheet 15 minutes.\r\nMeanwhile.. mix mayo and wasabi in small serving bowl.  Stir in half the inger and half the garlic.  Set aside.  Season fish all over with salt and pepper.  Place bok chou, cabbage and mushrooms in a large bowl, drizzle with il and add remaining ginger and garlic.  Toss to coat and season with salt and pepper.\r\nScatter veggies on one side of the baking sheet.  Arrange salmon on other.  Stir veggies occasionally until salmon is cooked - approx 15 minutes.  Serve wasabi mayo alongside.', NULL, 20),
(143, 'Cool looking, smashed roasted potatoes', '2 lbs red skinned potatoes - 6 oz each\r\n2 tsp kosher salt\r\n1/4 tsp pepper\r\n1/3 cup olive oil', 'Preheat oven to 350.  Wrap each potato in foil and place on rimmed baking sheet.  Bake till tender - 45 to 60 minutes.  Let cool slightly then unwrap.  Arrange on same sheet.  Set another baking sheet on top, press gently to smash without breaking them apart.  Season with salt and pepper.  Drizzle with half the oil.  Carefully turn the potatoes to coat.  \r\nPreheat oven to 500.  Roast potatoes for 15 minutes.  Drizzle with remaining oil, turn to coat and continue roasting until crispy and golden brown 25 minutes.', 'I imagine it to be almost like a french fire - crispy and golden', 20),
(144, 'spring vegetable and goat cheese dip', '1 cup of 3/4 inch pieces asparagus.\r\n2 tbsp unsalted butter\r\n1 cup chopped leeks\r\n2 tbsp flour\r\n1 1/4 cup 2% milk\r\n1 cup grated, mild, white cheddar\r\nsalt and pepper\r\n1 14 oz jar drained artichoke hearts in water\r\n1/4 cup thawed peas\r\n2 tbsp each chopped chives, mint, parsley\r\n1/2 tsp finely grated lemon zest\r\n4 oz crumbled fresh goat cheese\r\n', 'Preheat oven to 45o.  Cook asparagus until crisp tender (2 minutes)  Drain and let cool.  Melt butter in med saucepan over medium heat.  Add chopped leeks and cook, stirring often until soft ( 10 minutes).  Whisk in flour and gradually add 1 1/4 cup milk.  Bring to simmer whisking constantly.  Cook until thickened.  Remove from heat and add cheddar, whick till melted and smooth.  Season to taste with s and p.  Fold in asparagus (reserve the tips for decoration). Fold in chopped artichokes, peas and herbs, lemon and 2 oz goat cheese.  Transfer to 4 to 5 cup baking dish.  Arrange asparagus tips on top and dot with the other 2 oz goat cheese.  Bake until brown and bubbling. 15 to 20 minutes.  Serve with crackers or baguette.', 'Looks yummy and healthy!!', 20),
(145, 'Halibut with lovely squash sautÃ©', '8 large green onions or scallions (greens removed)\r\n4 tbsp olive oil - divided\r\n1 1/2 pound small squashes\r\n1 tbsp thyme leaves plus some for garnish\r\nsalt and pepper\r\n4 - 6oz skinless halibut fillets', 'Cut onion bulbs in half lengthwise.  Cut enough onion tops into 2 inch pieces to make up 1 cup.  Heat 1 tbsp oil in large skillet over med high until almost smoking.  Add bulbs, cut side down until golden.  3 minutes.  Transfer to plate.\r\nHeat 1 tbsp oil in same skillet.  Add squash, cook stirring until goldenand just tender, 5 minutes.  Stir in onions, and tops and 1 tbsp thyme leaves.  Season and cook until green tops wilt.  1 minute.  Remove aside.\r\nHeat remaining 2 tbsp oil in large non stick pan over med high heat.  Season fish with s and p.  Add fish and thyme sprigs to skillet and cook until it is golden brown.  5 mintues.  Turn and cook until jut cooked through and opaque in the centre.  2 minutes.  Divide squash mixture amongst 4 plates and top with Halibut', NULL, 20),
(146, 'healthy strawberry tarts - easy too', '2 tsp coconut oil, melted, plus more for pan\r\n2 cups pecans, walnuts or almonds\r\n5 tbsp agave syrup, divided\r\n2 tbsp ww flour\r\n1 tsp ground ginger\r\n1/2 tsp fine sea salt\r\n1 lb fresh strawberries - sliced\r\n1 tsp fresh lemon juice\r\n1 vanilla bean, split lengthwise ...  look up alternative\r\n', 'Lightly brush muffin cups with olive oil.  Set aside.  Pulse nuts in processor until coarsely ground.  Add 3 tbsp agave syrup, flour, ginger, salt and 2 tsp cocoanut oil.  Process until coasrse doogh forms.  Garther into a ball.  Press 1 heaping tbsp dough firmly into bottom and up sides of each muffin cup.  Chill for 1 hour.\r\nPreheat oven 350.  Bake crusts until firm and golden around edges 8 to 10 minutes.  Let cook in pan on a wire rack for at least 10 minutes before removing.\r\nPlace strawberries, lemon juice and 2 tbsp agave syrup in a bowl, scrape in vanilla seeds.  Stir well, crushing some of the strawberries to release juices.  \r\nUsing spatula or butter knife, remove tart shells and fill with strawberrie mixture.  Serve immediately.', 'You can make the shells a day ahead and store at room temp.', 20),
(147, 'quick whole wheat biscuits', '1/2 cup ww flour\r\n1/2 cup all purpose flour\r\n1/2 tbsp baking powder\r\n1/4 tsp baking soda\r\n1 tsp sugar\r\n1/4 tsp salt\r\n1/2 stick butter, cold cut into pieces\r\n1/2 cup cold buttermilk', 'Preheat oven to 450\r\nPut all but buttermilk into the processor until looks like coarse meal.  Add buttermilk and stir until all dry is moist.  \r\nTurn dough onto floured surface and lightly knead 4 or 5 times.  Pat out to 1 inch thick and cut into into biscuits.  \r\nPlace on ungreased sheet and bake 12 to 14 minutes.\r\n', 'This enough biscuits for 2 people - 5 or 6 total.  Easy to double', 7),
(148, 'Whole wheat bread machine bread', 'LARGE LOAF (1 1/2 lb/3 cup or 2 lb/4 cup machine)\r\n1 cup (250 mL) water\r\n1 (1) egg, beaten\r\n2 tbsp (30 mL) butter or margarine\r\n2 tbsp (30 mL) honey\r\n2.5 cups (750 mL) ROBIN HOOD Best For Bread Whole Wheat Flour\r\n1/2 cup regular white flour - just to make it a bit lighter\r\n1 1/2 tsp (7 mL) salt\r\n1 1/4 tsp (6 mL) bread machine yeast', 'Directions:\r\n1. SELECT loaf size 2.5 lbs\r\n2. ADD ingredients to machine according to manufacturerâ€™s directions - dry on top, yeast last.\r\n3. SELECT Whole Wheat ', 'You can replace the honey with molasses', 7),
(149, 'best ww bread dough - made in regular pan', 'Using a bread machine to make the dough only, then transfer to a pan to bake...\r\n1 3/4 cup water (I use skim milk)\r\n2 tbsp honey or molasses\r\n2 tbsp olive oil\r\n2.5 cups ww flour\r\n.5 cup white flour - just lightens it up a bit - could go all ww\r\n1 tsp salt\r\n2 tsp yeast', 'Put the first 3 ingredients into the bread machine.  Then flours (blended together), salt and yeast on top.  Do not mix.  Select the dough option.  Turn on and walk away for about 3 hours.\r\nWhen it is finally done - it has already risen once in the pan.  Pour it out into a prepared bread pan (oiled and dusted with flour)  It will be very wet and messy.  Not to despair.  Put the pan in a warm place (I use the warming drawer at proof temp - 85), cover loosely with saran wrap and then a clean towel.  Let it rise 45 minutes.  Then bake in a 350 oven for 25 to 30 minutes.  Put it into the bottom third of the oven.  Once the bottom - when tapped - sounds hollow - remove and put on a cooking rack.  After 10 minutes , remove from the pan and continue cooling on the rack.  Voila.  Little clean up and no work time.', 'This is kinda a mix of the no knead bread.  I prefer it baked in the oven as the bread maker always seems to bake it too hard for my taste.  And making it as a no knead bread is very messy and tend to bake with too thick of a crust and a shape difficult to make sandwiches out of.', 7),
(150, 'Gramma Virg Apple Pie ', 'Crumble Recipe - makes enough for 2 double pies or 4 crusts??\r\n1lb 		package of Crisco vegetable shortening / butter\r\n7 cups		Robin Hood Cake and Pastry Flour\r\n2 tsp		salt\r\nCombine in a large bowl and cut with a knife until crumbly.\r\n\r\nFilling for one pie:\r\n3 or 4 granny smith apples - peeled and thinly sliced\r\n1 tsp tapioca\r\nheaping tbsp cornstarch\r\n3/4 cup sugar\r\ndash nutmeg or cinnamon or a combo of both - I like both\r\n', 'Pie Prep\r\nMaterials\r\n- pie plate (9â€)\r\n- rolling pin\r\n- cold water\r\n- vinegar\r\n- wax paper\r\n- mixing bowl\r\nStep 1 Put about two cups of the crumbles into your mixing bowl.  Pour in a little of the cold water/vinegar mix, and moisten the crubles enough that they donâ€™t stick together in a ball.\r\nDonâ€™t make too wet or it will stick to the rolling pin.  If it gets too moist just add more crumbles.\r\nStep 2 Put flour on your piece of waxed paper and rolling pin, and proceed to roll the ball into a round shape to fit the pie plate.  Carefully roll the pie shell partially onto the rolling pin so that you can slide it into the pie plate.\r\nStep 3 Put in your filling.  We used about three fair-sized apples, sliced.  I like Granny Smith or Northern Spy apples, but there are lots of other varieties that bake up nicely.  Sprinkle about a teaspoon of tapioca over the apples (or other fruit) to take up the juice.  Then add a heaping tablespoon of cornstarch to Â¾ cup of sugar with a dash of nutmeg and pour it over the apples.\r\nStep 4 Go back to your crumbles and go through the same procedure of rolling to make a top crust for your pie.  Crimp the edges to keep in the juices.  Gently cut slits in the top of your pie to vent steam.  If you like, you can put a piece of a drinking straw in one or more of the vents to help steam escape.  Set pie in the fridge or freezer to chill it.\r\nStep 5 Preheat oven to 450ÂºF (230ÂºC).  Put pie on a mid or lower rack for 15 minutes.  Then turn the oven down to 350ÂºF (180ÂºC) for about 35 minutes.  Check to see if it is bubbling inside and getting browned enough to be done.\r\nStep 6 Remove from the oven and let sit on a cooling rack.\r\n', 'Best apple pie ever.  And the extra crumble needs to be refrigerated in a sealed container', 3),
(151, 'Easy, Boneless Buffalo chicken \"wings\"', '1 cup flour\r\n2 teaspoons salt\r\n 1/2 teaspoon ground black pepper\r\n 1/2 teaspoon cayenne pepper\r\n 1/4 teaspoon garlic powder\r\n 1/2 teaspoon paprika\r\n 1 egg\r\n 1 cup milk\r\n 3 skinless, boneless chicken breasts, cut into 1/2-inch strips - or at least all the same size for best cooking.\r\n 1/2 cup hot pepper sauce (Franks Red Hot)\r\n 2 tablespoon butter\r\n', 'combine flour and spices on a dish.  Combine milk and egg in a medium bowl.\r\nDip chicken pieces in milk mixture, then in to the flour mixture.  Back into the milk mixture and then back into the flour mixture.  Put on a parchment lined cookie sheet bake for approx 15 minutes at 350 degrees.  \r\nMeanwhile melt the the hot sauce and butter in a deep bowl.  When the chicken pieces are cooked, dip and swirl 2 pieces at a time in the sauce and put onto serving plate.  Serve with blue cheese or ranch dressing.  Carrots on the side or easy nachos', 'Personally, I am not fond of these, but Al loves them and thinks Scott will as well.', 10),
(152, 'Vegetable Pie', '1 pkg Stove Top Stuffing, 1 egg lightly beaten, 1 med onion chopped, 1 tbsp oil or butter, 1 pkg frozen chopped spinach thawed and well drained**, 1 - 227 g package grated motz cheese***, 1/2 sweet red pepper cut into strips, 4 eggs lightly beaten, 2 tomatoes thinly sliced.', 'Preheat oven to 375.  Prepare stuffing as per the package.  Stir in one egg then press into bottom of a 9 inch pie plate.  Saute onion in oil until tender.  Remove from heat and then stir in spinach.  Sprinkle half the cheese over the crust.  Top with half the spinach mixture, then all the peppers.  Sprinkle remaining cheese and then spinach mixture.  Pour the 4 remaining eggs over top evenly.  Top with tomatoes so that they cover the pie with one layer.  Bake until set - approx 35 minutes.', 'This is great as a main meal or as a side with meat. ** fresh spinach cooks down very quickly as well.  ***  I use chèvre cheese (soft goat cheese).  Needless to say, any vegetables would work.', 8),
(153, 'Lentil curry with Squash and spinach', '1 tbsp (15 mL) vegetable oil\r\n1 onion, chopped\r\n2 cloves garlic, minced\r\n2 tbsp (30 mL) all-purpose flour\r\n1 tbsp (15 mL) curry powder\r\n1 tbsp (15 mL) grated gingerroot\r\n1 tsp (5 mL) ground cumin\r\n1 tsp (5 mL) ground fennel\r\n2-1/2 cups (625 mL) vegetable stock or chicken stock\r\n1-1/2 cups (375 mL) water\r\n1 cup (250 mL) green lentils\r\n1/2 butternut squash, (1 lb/500 g)\r\n1 large potato\r\n6 cups (1.5 L) fresh spinach', 'In Dutch oven, heat oil over medium heat; cook onion and garlic, stirring occasionally, for about 5 minutes or until softened. Add flour, curry, ginger, cumin and fennel; cook, stirring, for 1 minute. Add stock, water and lentils. Bring to boil; cover, reduce heat and simmer for 30 minutes.\r\n\r\nMeanwhile, peel and seed squash; cut into 3/4-inch (2 cm) cubes. Set aside. Peel and cut potato into 3/4 inch (2 cm) cubes; add to pot. Cover and cook for 10 minutes. Add squash; cook, uncovered, for about 15 minutes or until tender and liquid is thickened.\r\n\r\nThin and coarsely chop spinach; stir into pot until wilted.\r\n\r\nServings: 6\r\n', 'We found it mild with 1 tbsp of curry - I will go up to 1.5 next time.  I served it over quinoa with Naan besides.\r\n\r\nI quite liked it.  Not Al\'s favourite.', 8),
(154, 'Chicken Pad Thai', '1/2 pkg (14 oz/400 g) wide rice stick noodles\r\n2/3 cup (150 mL) chicken stock\r\n1/2 cup (125 mL) ketchup\r\n1/4 cup (50 mL) fish sauce\r\n2 tbsp (25 mL) granulated sugar***\r\n2 tbsp (25 mL) cornstarch\r\n1 tsp (5 mL) grated lime rind\r\n2 tbsp (25 mL) lime juice\r\n1 tsp (5 mL) hot pepper sauce (chines chill preferabely)***\r\n4 tsp (18 mL) vegetable oil\r\n2 eggs, lightly beaten\r\n1 lb (454 gr) boneless skinless chicken breasts, sliced\r\n4 carrots, thinly sliced\r\n1 sweet red pepper, sliced\r\n2 cloves of garlic, minced\r\n1 tbsp (15 mL) minced gingerroot\r\n2 cups (500 mL) bean sprouts\r\n2 green onions, sliced\r\n1/4 cup (50 mL) chopped unsalted peanuts\r\n', 'In large bowl, soak noodles in warm water for 20 minutes; drain and set aside.\r\n\r\nMeanwhile, in small bowl, whisk together stock, ketchup, fish sauce, sugar, cornstarch, lime rind and juice and hot pepper sauce; set aside.\r\n\r\nIn wok or large skillet, heat 2 tsp (10 mL) of the oil over medium heat; cook eggs, stirring often, for 2 minutes or until scrambled and set. Transfer to plate.\r\n\r\nWipe out wok; add remaining oil. Brown chicken, in batches, over medium-high heat. Transfer to separate plate.\r\n\r\nAdd carrots, red pepper, garlic and ginger to pan; cook, stirring, for about 3 minutes or until slightly tender. Add noodles; stir gently for 1 minute.\r\n\r\nReturn chicken to pan. Stir sauce and pour into pan; cook, stirring, for 3 minutes or until thickened, noodles are tender and chicken is no longer pink inside.\r\n\r\nReturn egg mixture to wok along with bean sprouts; toss gently for 1 minute or until heated through. Serve sprinkled with green onions and peanuts.\r\n\r\nServings: 4', 'It can be a bit sweet.  Perhaps go with 1 Tbsp of sugar and then add if not sweet enough.  I also add more hot sauce ', 10),
(155, 'Spicy Edamame', 'Â½ pound edamame still in pod\r\n1Â½ quarts water\r\n2 teaspoons salt\r\nSpicy Sauce\r\n2 tablespoons soy sauce\r\n2 tablespoons water\r\n1 tablespoon rice vinegar\r\n1 tablespoon sesame oil\r\nÂ¼ teaspoon red chili flakes\r\n1 to 2 teaspoons Sriracha Sauce (optional)\r\nÂ½ to 1 teaspoon chopped garlic\r\nÂ½ teaspoon sugar\r\n', 'Bring the water to a boil in a large saucepan. Add the raw edamame and the salt. When the water has returned to a boil, lower the flame and simmer for 4-6 minutes. Drain in a colander.\r\nCombine all of the remaining ingredients in a bowl. Mix in the cooked edamame so that they are coated with the sauce. Serve immediately, or store in the fridge for 1-2 days.', 'The spicy sauce in this recipe is delicious with potstickers and dim sum dumplings! For one pound of edamame, increase sauce quantities by 50%.\r\nâ€“ - â€“ - â€“ ', 9),
(156, 'Really good Choc chip cookies - from Martha Stewart', '2 1/4 cups all-purpose flour\r\n1/2 teaspoon baking soda\r\n1 cup (2 sticks) unsalted butter, room temperature\r\n1/2 cup granulated sugar\r\n1 cup packed light-brown sugar\r\n1 teaspoon salt\r\n2 teaspoons pure vanilla extract\r\n2 large eggs\r\n2 cups (about 12 ounces) semisweet and/or milk chocolate chips', 'STEP 1\r\nPreheat oven to 350 degrees. In a small bowl, whisk together the flour and baking soda; set aside. In the bowl of an electric mixer fitted with the paddle attachment, combine the butter with both sugars; beat on medium speed until light and fluffy. Reduce speed to low; add the salt, vanilla, and eggs. Beat until well mixed, about 1 minute. Add flour mixture; mix until just combined. Stir in the chocolate chips.\r\nIN THIS STEP: How to Measure Flour\r\nSTEP 2\r\nDrop heaping tablespoon-size balls of dough about 2 inches apart on baking sheets lined with parchment paper.\r\nSTEP 3\r\nBake until cookies are golden around the edges, but still soft in the center, 8 to 10 minutes. Remove from oven, and let cool on baking sheet 1 to 2 minutes. Transfer to a wire rack, and let cool completely. Store cookies in an airtight container at room temperature up to 1 week.', 'Measure the four by scooping into the measuring cupâ€¦  not scooping directly into the cup!!  that way it does not compact and you end up with too much flour.', 13),
(158, 'Ulimate Eggplant Parmesan', 'Extra virgin olive oil\r\n1 Spanish onion, diced*******\r\n4 garlic cloves, peeled and thinly sliced\r\n3 tablespoons chopped fresh thyme leaves\r\n1/2 medium carrot, finely grated\r\n2 (28-ounce) cans peeled, whole tomatoes, crushed by hand, juices reserved\r\nSalt and pepper\r\n3 large eggplant\r\n1 bunch fresh basil leaves, sliced (optional; I left it out b/c basilâ€™s not in season)\r\n1 pound fresh mozzarella, sliced 1/8-inch thick\r\n1/2 cup (or more) freshly grated Parmesan (for something like this, I use the store-ground stuffâ€”not the kind from a can, but the kind in the refrigerated section; make sure itâ€™s real Parm and it will save you a step)\r\n1/4 cup fresh bread crumbs, lightly toasted under a broiler or in a skillet (see above)\r\n', 'Start by making the tomato sauce. In a large saucepan, heat 1/4 cup olive oil over medium heat. Add the onion (and a pinch of salt) and cook for a few minutes until it softens; then add the garlic and wait for both to turn a light golden brown.\r\nAdd the thyme and carrot and cook five minutes more; then add the tomatoes and juice, a pinch of salt, bring to a boilâ€“stirring oftenâ€“and then lower to a simmer. Cook like this for 30 minutes, stirring occasionally, until the sauce looks thick and tastes terrific (adjust with more salt, as necessary). Set aside.\r\nPreheat the oven to 450 degrees F.\r\nOil a baking sheet with olive oil.\r\nSlice each eggplant into 6 pieces about 1 to 1/2-inches thick; place as many slices as you can on to the baking sheet (youâ€™ll have to do this in batches), drizzle them with a little more olive oil, salt and pepper. Pop into the hot oven and bake until theyâ€™re deep brown on top, about 15 minutes. Remove the eggplant slices to a plate to cool and roast the remaining eggplant.\r\nLower the oven temperature to 350 degrees F. In a large baking pan, begin your layering. Start with the largest pieces of eggplant on the bottom, then a layer of tomato sauce, basil (if using), one slice of mozzarella for each eggplant slice, and a sprinkling of Parmesan. Top with a layer of smaller eggplant slices, more sauce, more basil, more mozzarella and more Parmesan. If you have more eggplant and cheese to work with, you can do another layer, but I stopped here. Finish by topping the whole baking pan with the breadcrumbs.\r\nPlace in the oven and bake until the bread crumbs are golden on top and the cheese is melted, about 20 minutes. Serve it up hot!\r\n', '***** Note, I just use my favourite store bought smooth tomato basil sauce.  Not too chunky.\r\n\r\nPreparation time: 45 minute(s)\r\n\r\nCooking time: 20 minute(s)\r\n\r\nNumber of servings (yield): 6\r\n', 8),
(159, 'Easy Risotto', 'Ingredients:\r\n2 tbsp (30 mL) extra-virgin olive oil\r\n1 onion, chopped\r\n2 cloves of garlic, minced\r\n3 cups (750 mL) sliced mushrooms\r\n1/2 tsp (2 mL) salt\r\n1/2 tsp (2 mL) pepper\r\n2 cups (500 mL) arborio rice or short-grain Italian rice\r\n4 cups (1 L) chicken stock\r\n3/4 cup (175 mL) white wine or chicken stock\r\n1 cup (250 mL) frozen peas\r\n3/4 cup (175 mL) grated Parmesan cheese', 'In large saucepan, heat 1 tbsp (15 mL) of the oil over medium heat; fry onion, garlic, mushrooms and 1/4 tsp (1 mL) each of the salt and pepper, stirring occasionally, until softened and mushroom liquid is evaporated, about 5 minutes.\r\n\r\nAdd rice; stir to coat grains. Add stock and wine; bring to boil. Cover and reduce heat to low; cook, stirring once, until rice is tender, about 10 minutes. Add peas and Parmesan cheese. ', 'This just avoids having to stir and watch.  You can\'t go wrong adding more cheese!!  And serve with balsamic vinegar to drizzle over it at the dining table.   It makes the rice really pop.', 18),
(160, 'Crispy Oven Fried Fish', '4 slices of bread\r\n1 tbsp olive oil\r\nsalt and pepper\r\n1/4 tsp onion powder\r\n1 tbsp dried parsley\r\n1/4 cup flour - plus 5 TBSP additional\r\n2 large eggs\r\n3 TBSPs light mayo\r\n2 tsp prepared horseradish\r\n1/4 tsp paprika\r\n1/4 tsp cayenne powder (optional but good)\r\n4 (6 oz) skinnless cod/haddock or halibut fillets.  1 to 1.5 inches thick\r\nLemon wedges to serve with', 'Adjust oven racks to the middle and preheat oven to 425.  Set a wire rack over a foil-lined cookie.  Lightly spray the rack with oil and then set it aside.\r\nPulse the bread into breadcrumbs.  Transfer to a bowl and drizzle with oil.  Toss then add 1/4 tsp salt and 1/4 tsp pepper. Add parsley and onion powder.    Toss.   Spread the crumbs on a cookie sheet and bake 6 to 10 minutes, stirring occasionally until golden brown.  Remove and let them cool to room temp.\r\nPlace 1/4 Cup flour in a shallow bowl. Set aside.  In another shallow bowl, whip eggs and mayo, horseradish, paprika, cayenne and 1/4 tsp pepper until combined.  Then whisk in the remaining 5 TBSP flour.  \r\nPat the fish fillets dry then season with 1/4 tsp salt and 1/4 tsp pepper.  Dredge in the flour then shake off the excess.  Then coat the fillets with the eft mixture letting excess drip off.  Then put ito the crumbs bowl and pat on a thick layer of the crumbs.  Put onto the prepared wire rack.\r\nBake in the oven for approx 10 minutes or until the fish is 140 degrees using an instant read thermometer into the thickest part of the fish.  ', 'This ensure a nice crispy coating.  Watch the doneness.  If no thermometer, then when you think it should be done, try flaking one piece in the thickest part to see if it flakes easily. \r\nCould serve with tartar sauce, but I like just a touch of ketchup.', 14),
(161, 'Easy Enchiladas with Creamy Tomatillo Sauce', '1 lb. boneless, skinless chicken thighs (to yield about 2 cups shredded cooked meat)*******\r\nSalt to taste\r\n12 whole wheat large tortillas\r\n1 jar of Green Mexican Sauce - 16 fl oz *****\r\n1 Can cocoanut milk\r\n1 1/3 cup motz or mexican mix cheese shredded\r\n', 'Fill a medium saucepan with water and bring it to a boil. Add the chicken thighs and a bit of salt; simmer until cooked through and tender, about 20 minutes. Cool the meat; shred (discarding any fat or gristle), season with salt, and set aside.\r\n\r\nHeat the oven to 400Â°F. With a pastry brush, spread a thin layer of sauce on both sides of each tortilla. Spoon a heaping tablespoon of shredded chicken just off center of each tortilla and roll into loose cylinders. Set the enchiladas side by side in a 9x13 inch baking dish, pour the remaining sauce over them, top with the cheeses, and bake until bublling and browned in spots, 15 to 20 minutes.', '*****  I have used left over turkey or any chicken available including breast\r\n****  I love La Costena brand of Green Mexican Sauce - spicy tamed with the cocoanut milk\r\n', 10),
(162, 'Pork Frajitas with spicy avocado mango salsa', '1 large ripe mango, diced (about 1 cup)\r\n2 cups corn\r\n1 large ripe avocado, diced\r\n1/3 cup red onion, diced\r\n1/4 cup jalapeÃ±o pepper, seeds removed and diced\r\n1/4 cup red pepper, diced\r\n2 tablespoons cilantro, rinsed well and chopped\r\nJuice from ripe lime\r\n1/2 teaspoon salt\r\n\r\n---------------------------\r\n2 tsp. ground cumin\r\n2 tsp. chili powder\r\n1 tsp garlic powder\r\nKosher salt and freshly ground black pepper\r\n2 lb. pork tenderloin, cut in 2-1/2x1/4x1/4-inch strips\r\n3 Tbs. olive oil', 'Cut pork loin in to short thin strips.  Put them into a storage bag.  Combine the spices then pour over the pork strips.  Message into all the strips evenly.  Marinade for 30 to 60 minutes.  Meanwhile, sautÃ© the corn in a frying pan with a bit of oil on med-high heat to get some browning on the kernels.  When lightly charred, remove and place in a medium size bowl.  Then combine all the other salsa ingredients and toss.\r\n\r\nGrill the pork strips in a single layer, taking them off as they cook and covering with foil to keep warm.  Continue to grill the pork until done.   \r\n\r\nServe with smaller tortilla wraps.  ', 'Serves 4 hungry people', 12),
(164, 'Bittersweet Chocolate and Balsamic Pots de Creme', '6 large egg yolks, 1/4 cup sugar - divided, pinch salt, 1 1/2 cup whipping cream, 1/2 cup 2% milk, 5 oz bittersweet chocolate, finely chopped, 1 tbsp high quality balsamic vinegar.\r\n', '1  Preheat oven to 325\r\n2  whisk egg yolks, 1 tbsp sugar and salt in large bowl until smooth.  reserve.\r\n3  combine whipping cream and milk with remaining 3 tbsp sugar in  a medium pot and bring to just simmer.  Remove from heat, add chocolate, let stand 2 minutes to melt then stir until smooth.  Stir in balsamic vinegar.\r\n4 whisking constantly, slowly add chocolate mixture to egg mixture until fully combines.  Deivide between 6 ovenproof baking dishes.  Cover each dish tightly with foil and place in a baking pan.  Pour enough boiling water in the baking pan to come halfway up the sides of the baking dishes.\r\n5.  Bake for 30 minutes or until custard is set but wiggles evenly when bumped.  Serve warm or chill until serving and serve cold.', 'maybe serve with a couple raspberries on the top.', 20),
(165, 'Chimichanga', '2 tablespoons unsalted butter\r\n4 tablespoons vegetable oil\r\n1 white onion, chopped\r\n3 cloves garlic, chopped\r\n1 jalapeno pepper, diced (remove seeds for less heat)\r\n1 1/2 teaspoons chili powder\r\n1/2 teaspoon ground cumin\r\nKosher salt\r\n1 small tomato, chopped, plus more for topping\r\n1 tablespoons chopped fresh cilantro\r\n2 1/2 cups shredded rotisserie chicken - any more and they are too hard to roll\r\n1/4 cup sour cream\r\n1 15 -ounce can refried beans\r\n4 10 -inch flour tortillas\r\n1 cup shredded monterey jack cheese, plus more for topping\r\nMexi-sauce, for topping (see below)\r\nShredded lettuce, for topping\r\n\r\n\r\nMake Chi-Chi\'s Mexi-sauce:\r\n\r\nSaute 1/2 cup chopped onion and 2 chopped garlic cloves in a skillet with vegetable oil. Add a pinch each of chili powder, cumin, sugar and salt; cook 30 seconds. Stir in two 4-ounce cans chopped green chiles (drained and rinsed); cook 2 minutes. Add 1 cup chicken broth and simmer until thickened, then puree. Stir in 1 tbsp chopped cilantro\r\n\r\n', 'Preheat the oven to 450 degrees F. Melt the butter with 2 tablespoons vegetable oil in a skillet; transfer to a bowl. Heat the remaining 2 tablespoons oil in the skillet. Add the onion, garlic and jalapeno and cook until soft, about 3 minutes. Add the chili powder, cumin,  and 1 teaspoon salt; toast 30 seconds. Add the tomato and cilantro and cook until slightly dry, about 2 minutes. Stir in the chicken and sour cream and warm through. Remove from the heat.\r\n\r\nBrush a rimmed baking sheet with some of the butter-oil mixture. Spread 2 tablespoons refried beans down the center of each tortilla, leaving a 2-inch border on both ends. Top with 1 cup chicken mixture and 1/4 cup cheese. Fold in the ends and roll up.\r\n\r\nPut the chimichangas seam-side down on the baking sheet; brush with the butter-oil mixture. Bake 8 to 10 minutes per side, brushing again after you flip. Top with the sauce, more cheese, lettuce and tomato. Serve with rice and the remaining beans.\r\n\r\n', 'It is nice to make a cheese sauce instead of just using shredded cheese at the table.', 10),
(166, 'Barley Risotto with Mushrooms and Spinach - slow cooker', '2 tsp olive oil\r\n8 oz mushrooms sliced\r\n1 onion diced\r\n3 1/2 cups chicken or beef broth (sodium reduced)\r\n1 1/2 cups uncooked perl barley (not quick cooking)\r\n2 medium garlic cloves, minced\r\n1/4 tsp salt\r\n1/4 tsp black pepper\r\n***************\r\n\r\n2 oz fresh chopped spinach (approx 2 cups)\r\n1/2 cup grated parmesan cheese\r\n2 tbsp fresh lemon juice\r\n\r\n1/4 cup broth......  if needed\r\n', 'In a large skillet, heat the oil over medium high heat, swirling to coat the bottom.   Cook the mushrooms and onions until mushrooms are soft.  Stir often.  Transfer to slow cooker.\r\nStir in 3 1/2 cups broth, barley, garlic, salt and pepper.   Cook, covered, on high for 2 hours or until Barley is tender.\r\nWhen ready to eat, stir in spinach and cook on high for 15 minutes or until spinach is wilted.  Stir on parmesan and lemon juice.\r\n\r\nServe', 'From American Heart Association.  1 serving is 1 1/2 cups.  360 calories. 6 g of fat.', 21),
(167, 'Flourless Chocolate  - converted to 9 inch pan', '136 grams fine-quality bittersweet chocolate (not unsweetened)\r\n136 grams unsalted butter (1 stick plus a bit)\r\n202.5 sugar\r\n3.75 large eggs\r\n74.5 grams unsweetened cocoa powder plus additional for sprinkling\r\nAccompaniment if desired: Coconut Lime Sorbet', 'Preheat oven to 375°F and butter an 8-inch round baking pan. Line bottom with a round of wax paper and butter paper.\r\nChop chocolate into small pieces. In a double boiler or metal bowl set over a saucepan of barely simmering water melt chocolate with butter, stirring, until smooth. Remove top of double boiler or bowl from heat and whisk sugar into chocolate mixture. Add eggs and whisk well. Sift 1/2 cup cocoa powder over chocolate mixture and whisk until just combined. Pour batter into pan and bake in middle of oven 25 minutes, or until top has formed a thin crust. Cool cake in pan on a rack 5 minutes and invert onto a serving plate.\r\nDust cake with additional cocoa powder and serve with sorbet if desired. (Cake keeps, after being cooled completely, in an airtight container, 1 week.)\r\n', 'recipe converted from an 8 inch pan recipe - conversion factor of 1.2\r\n\r\nEasy glaze\r\n1 cup choc chips\r\n4 tbsp butter\r\n4 tbs corn syrup\r\n\r\nMicrowave on 5 for 1 minute and stir.', 3),
(168, 'Flourless chocolate cake - 8 inch pan', '4 ounces fine-quality bittersweet chocolate (not unsweetened)\r\n1 stick (1/2 cup) unsalted butter\r\n3/4 cup sugar\r\n3 large eggs\r\n1/2 cup unsweetened cocoa powder plus additional for sprinkling\r\nAccompaniment if desired: Coconut Lime Sorbet', 'Preheat oven to 375°F and butter an 8-inch round baking pan. Line bottom with a round of wax paper and butter paper.\r\nChop chocolate into small pieces. In a double boiler or metal bowl set over a saucepan of barely simmering water melt chocolate with butter, stirring, until smooth. Remove top of double boiler or bowl from heat and whisk sugar into chocolate mixture. Add eggs and whisk well. Sift 1/2 cup cocoa powder over chocolate mixture and whisk until just combined. Pour batter into pan and bake in middle of oven 25 minutes, or until top has formed a thin crust. Cool cake in pan on a rack 5 minutes and invert onto a serving plate.\r\nDust cake with additional cocoa powder and serve with sorbet if desired. (Cake keeps, after being cooled completely, in an airtight container, 1 week.)\r\n', 'very good and Al\'s fav', 3),
(169, 'Chicken Parmesan for a 4', '2 cups fine dry breadcrumbs\r\n1 cup all-purpose flour\r\n4 large eggs\r\n1 cup whole milk\r\n4 skinless, boneless chicken breasts, pounded to 1/2\" thickness\r\nKosher salt, freshly ground pepper\r\nN/A freshly ground pepper\r\n8 tablespoons olive oil\r\n8 tablespoons prepared sun-dried tomato pesto\r\n1 pound fresh mozzarella, cut into 8 slices\r\n1/2 teaspoon crushed red pepper flakes\r\n4 cups prepared marinara sauce, warmed\r\nFinely grated Parmesan (for serving)', 'Place breadcrumbs and flour in 2 separate shallow bowls. Whisk eggs and milk in a medium bowl. Season chicken with salt and pepper. Dredge in flour, shaking off excess. Coat with beaten egg mixture, allowing excess to drip back into bowl. Coat with breadcrumbs, pressing to adhere. Place on a large plate or rimmed baking sheet.\r\nHeat 2 tablespoons oil in a large skillet over medium heat. Working in 4 batches, cook  until chicken is golden brown and cooked through, about 4 minutes per side; transfer to a paper towel-lined plate. Wipe skillet clean and add 2 tablespoons oil between batches.\r\nPreheat broiler. Lay 4 cutlets on a foil-lined baking sheet; spread each with 2 tablespoons pesto, top with a slice of cheese, and sprinkle with red pepper. Top with remaining cutlets and cheese. Broil until cheese browns, about 4 minutes.\r\nDivide sauce and chicken among shallow bowls and top with Parmesan.', 'Note, once pounded the breasts may become quite large.  Just cut in 2 pieces before dredging.  \r\nMake sure to season generously with salt and pepper.', 10),
(170, 'Brown rice Risotto...  company level', '1 cup brown medium-grain rice\r\n3 cans consome (or 3 cups stock)\r\n2 1/2 cup approx. water\r\n2 tbsp butter\r\n1 medium onion, finely chopped\r\n1/2 cup white wine\r\n1/2 small bunch asparagus, trimmed and cut into 1 1/2 inch pieces diagonally*****\r\n1/2 grated parmesan cheese plus more to serve', 'SOAK RICE IN WATER FOR 6 HOURS OR SO. Drain well. It should measure about 1 1/3 cups. PRE-SOAK CUTS COOKING TIME DOWN SIGNIFICANTLY.\r\nCombine broth with enough water to measure 6 cups water in a large saucepan. Cover and bring to a boil. Then reduce heat to low to keep warm.\r\nMelt butter in a medium saucepan over medium. Add onion and cook, stirring frequently, until onion is soft but not browned, 3 to 4 min. Add rice and stir until glossy, about 1 min. Add wine and stir until rice has absorbed all of the liquid, 8 to 9 min. Add 1 cup broth mixture. Stir often until rice has absorbed most of the liquid, 6 to 9 min. Continue adding broth mixture, 1 cup at a time, until absorbed. Keep heat between medium-low and low so mixture is just simmering. Stir often until rice is tender to the bite. Stir in asparagus and cook until tender-crisp, about 4 min. The entire stirring and cooking process will take about 50 to 55 min. Risotto should be slightly saucy but not soupy. Remove from heat. Stir in cheese. Serve immediately with pepper on the table.\r\n', '*****. I used fresh peas (out of the pod)', 18),
(171, 'chicken pot pie with whole wheat crust', 'Pastry\r\n1 cup fine whole-wheat flour\r\n½ cup pastry flour\r\n1/2 teaspoon salt\r\n2 tablespoons shortening (I used Tenderflake)\r\n½ cup butter.\r\nIce cold water [I used 6 tablespoons but that will vary]\r\n------------------------------------------------------\r\nPot Pie Ingredients\r\n½ cup butter, divided\r\n1 medium onion, diced\r\n3 carrots, peeled and diced\r\n1 ½ cups sliced mushrooms\r\n1 celery stalk, diced\r\n2 large garlic cloves, minced\r\n1 cup fresh peas or frozen (thawed and patted dry)\r\n½ cup all-purpose flour\r\n2 cups chicken stock\r\n½ cup white wine \r\n½ cup half-and-half\r\n1 teaspoon dried thyme\r\n1 tsp marjoram\r\n1/2 tsp rosemary\r\n\r\n1 pound cooked chicken (I used 4 skin on bone in chicken breasts roasted with salt and pepper then cubed)', '1. Make sure all your ingredients and mixing bowl are cold! Combine flours and salt.\r\n2. Quickly grate the butter and shortening into the flour bowl\r\n3. Cut the shortening and butter into the flour \r\n4. Once you no longer have pieces of butter or shortening any larger than a pea, you are ready to begin adding water. I like to switch to a fork at this stage. Pour ice water over flour / butter mixture 1 tablespoon at a time. After each addition, gently mix with a fork. Repeat until your dough is no longer crumbly when you press it together and will hold together in a ball.\r\n5. Press into a fat dish, wrap in plastic wrap and put in the refrigerator while you prepare the pot pie. You may roll it out at this stage and keep it cold and covered between wax paper.\r\n----------------------------------------------------------------\r\n1. Melt 2 tablespoons of butter in a medium pot over medium-low heat. Add onions, carrots, mushrooms, celer; sauté on low heat until softened and slightly browned. Season with salt and pepper.  Approximately 15 minutes. add Garlic 2 minutes before others are done.\r\n2. If you are using fresh peas, add them at this point and continue to cook for an additional 5 minutes. If you are using frozen, skip the additional cooking. They will be mush and gross.\r\n3. Remove veggies to a large bowl and set aside.\r\n4. Preheat oven to 375°\r\n5. Melt the remaining 6 tablespoons of butter in the same pot over medium-low heat, and then add the flour. Stir constantly for about 2 minutes until mixture turns a blond color.\r\n6. Slowly add the chicken stock in no more than ¼ cup at a time, whisking after each addition.\r\n7. Whisk in wine, half-and-half, and thyme/sage/rosemary. Cook, stirring frequently, for 10 minutes until the sauce is thickened. Add the veggie mixture back into the pot along with the chicken and stir to cover with the sauce.\r\n8. Pour into pan and cover with the pastry. Fold and crimp the edges decoratively.\r\n9. Whisk 1 egg yolk and 1 tablespoon cold water. Brush over pastry.\r\n******. next very important.  Don\'t cover with pastry until ready to go into the oven.!!!\r\n10. Cut at least 4 slits in the pastry. Make sure they are completely through the pastry or your steam will exit out the sides and your filling will runeth over. Trust me, I know. Whatever you do, just do it quickly because the warm filling will melt the butter in the crust and then it won’t be flakey. Sadness!\r\n11. Set the baking dish on a rimmed baking sheet and bake 30 minutes or until the crust is your version of perfectly brown. The whole-wheat crust definitely took an extra 10 or more  minutes to brown the way I like it.\r\n12. Cool at least 20 minutes before serving. The filling will thicken considerably.\r\n', 'Timing is important here at the end!!  Use whatever spices you have on hand that resonate well with chicken.', 10),
(172, 'Lacotse Intolerant Rich Chocolate cake', 'Cake...  note.. cake flavour improves if made 1 day ahead.\r\n3/4 cup vegetable oil plus more for greasing pans\r\n3/4 cup natural unsweetened cocoa powder (not Dutch-process) plus more for dusting pans - 2 8 inch pans.\r\n1 cup water\r\n3/4 cup well-stirred canned unsweetened coconut milk\r\n3 large eggs, warmed in shell in warm water 5 minutes\r\n1 1/2 teaspoons pure vanilla extract\r\n2 cups all-purpose flour\r\n1 3/4 cups sugar\r\n2 teaspoons baking powder\r\n1/2 teaspoon baking soda\r\n3/4 teaspoon salt\r\n\r\nGanache frosting:\r\n1 1/2 cups well-stirred canned unsweetened coconut milk\r\n24 ounces (4 cups) semisweet chocolate chips (see Cooks\' Notes)\r\n2 teaspoons instant espresso powder\r\n1 1/2 tablespoons light corn syrup\r\n', 'Bake cake layers:\r\nHeat oven to 350°F with rack in middle. Oil pans and line bottoms with rounds of parchment, then dust sides only with cocoa powder, knocking out excess.\r\nWhisk together water, coconut milk, 3/4 cup oil, eggs, and vanilla in a bowl until well blended and smooth.\r\nSift together flour, sugar, 3/4 cup cocoa powder, baking powder and soda, and salt into a large bowl. Add wet ingredients to flour mixture and whisk until smooth.\r\nDivide batter between pans, and bake until a tester comes out clean and layers just begin to pull away from side of pans, 25 to 30 minutes.\r\nCool cake layers in pans on a rack 30 minutes, then run a thin knife around edge of pans and invert cakes onto rack. Remove parchment and cool completely.\r\nMake frosting:\r\nCombine coconut milk, chocolate chips, and espresso powder in a heat-proof bowl. Set bowl over a pan of barely simmering water, and heat, whisking occasionally, until chocolate is melted and smooth.\r\nRemove bowl from pan and whisk in corn syrup and vanilla.\r\nChill frosting, stirring occasionally, until slightly thickened and spreadable, about 2 hours. (To quick-chill, place bowl in the freezer and stir occasionally until chocolate mixture is thickened and spreadable, 20 to 30 minutes.)\r\nAssemble cake:\r\nSpread frosting generously between cake layers and over top and sides.\r\n', 'Serve with lactose free whipping cream and berries.', 3),
(173, 'Cajun Shrimp Guacamole Bites', '1 sweet potatoes, sliced in ¼\" slices\r\n2 tablespoons olive oil\r\nsalt to season\r\nChipotle Shrimp:\r\n1lb. large raw shrimp, peel and deveined\r\n½ teaspoon smoked paprika\r\n½ teaspoon ground cumin\r\n½ teaspoon sea salt\r\n¼ teaspoon chipotle chili powder\r\n1 tablespoon olive oil\r\nGuacamole:\r\n4 small avocados\r\n½ cup cilantro\r\njuice of 1 lime (about 2-3 tablespoons)\r\n1½ tablespoons red wine vinegar\r\n½ teaspoon red pepper flakes\r\nsalt to taste', 'Preheat oven to 425.\r\nCover bottom of baking sheet with tin foil. Add 1 tablespoon of olive to tin foil and using a brush, spread the olive oil over the entire pan so it is coated. Place the sweet potato slices on the prepared baking sheet.\r\nPour remaining tablespoon of olive oil into a small dish, using a brush, brush the tops of the sweet potato slices with olive oil. Lightly season with salt.\r\nBake in oven for 10 minutes.\r\nRemove the baking sheet from the oven and gently flip the sweet potatoes slices over using a pair of tongs. Place back in oven and bake an additional 5-7 minutes. Remove and let sit.\r\nTo prepare the Guacamole: Add avocado, cilantro, lime juice, red wine vinegar, red pepper flakes, and salt to a food processor or blender. Lightly pulse until the mixture is smooth. Set aside.\r\nTo prepare the Chipotle Shrimp: In a small bowl, add shrimp, smoked paprika, ground cumin, sea salt, and chipotle chili powder. Toss the shrimp to coat in the seasoning blend.\r\nHeat a large skillet to medium high heat. Add olive oil to the pan and then place the shrimp. Cook shrimp for 2-3 minutes per side.\r\nAssemble the bites. Top each sweet potato slice with a dollop of guacamole, one shrimp, and garnish with fresh cilantro. Serve', 'choose skinny potatoes. Any extra chips can just be put into a bowl and dusted with a dip.\r\n\r\nIf you are short time, use a thick bought potato chip and dollop with store bought guac then store bought shrimp tossed with a bit of chipotle mayo.  Almost as good.', 9),
(174, 'gueten free zucchini cheesy \"bread\" sticks', '3 cups shredded zucchini (about 3 medium)\r\n3 eggs\r\n1/3 cup flour\r\n1 teaspoon salt\r\n2 cups shredded mozzarella (or any) cheese\r\nItalian seasoning', 'Preheat oven to 450 degrees F.\r\nSprinkle the shredded zucchini with salt to release some of its moisture. Let sit 10-15 minutes, then squeeze zucchini in a clean cheese towel to release most or all of the liquid.\r\nMix zucchini, eggs and flour (gluten free)  in a medium bowl. Spray a baking sheet with cooking spray and spread the zucchini mixture into a large thin rectangle.\r\nBake for about 25 minutes or until the edges are nicely brown. Make sure it\'s nice and golden on the sides and top so the crust isn\'t mushy.\r\nReduce the oven to 350 degrees F, sprinkle the crust with cheese and Italian seasoning, and continue baking until the cheese is just melted.\r\nLet cool a few minutes, then cut into sticks. Serve with marinara or ranch or garlic butter or any sauce your heart desires.', 'to make it guetan free, use appropriate flour.  May require a bit extra flour.  Could add shredded onion for flavour.  If you can flip it after it is golden along the edges, that is great.  Put it under the broiler with the cheese,  Avoids mushy zucchini.\r\nIf you cut it into bite size pieces it makes a nice one-bite app.', 9),
(175, 'Stuffed Mushrooms', '24 ounces , White Button Mushrooms\r\n1/3 pound Hot Pork Sausage\r\n½ whole Medium Onion , Finely Diced\r\n4 cloves Garlic , Finely Minced\r\n8 ounces , Cream Cheese\r\n1 whole Egg Yolk\r\n¾ cups Parmesan Cheese , Grated\r\n1/3 cup Dry White Wine\r\nSalt And Pepper (to Taste)\r\n\r\n', 'Wipe off mushrooms with a damp rag. Pop out stems, reserving both parts.\r\nChop mushroom stems finely and set aside.\r\nBrown and crumble sausage. Set aside on a plate to cool.\r\nAdd onions and garlic to the same skillet; cook for 2 minutes over medium low he at. Pour in wine to deglaze pan, allow liquid to evaporate. Add in chopped mushroom stems, stir to cook for 2 minutes. Add salt and pepper to taste. Set mixture aside on a plate to cool.\r\nIn a bowl, combine cream cheese and egg yolk. Stir together with Parmesan cheese. Add cooled sausage and cooled mushroom stems. Stir mixture together and refrigerate for a short time to firm up.\r\nSmear mixture into the cavity of each mushroom, creating a sizable mound over the top.\r\nBake at 350 degrees for 20 to 25 minutes, or until golden brown. Allow to cool at least ten minutes before serving; the stuffed mushrooms taste better when not piping hot. Garnish with minced parsley if you\'re feeling fancy.\r\n\r\n', 'good to make ahead.  Stuff then refrigerate.  Then heat before guests arrive and keep in a warming drawer.\r\n\r\nOr....  buy pre-made crab salad and stuff with that!!', 9),
(176, 'Asparagus Fries....  Panko/Cheese ', '1/2 cup Panko*\r\n1/2 cup grated Parmesan cheese\r\nKosher salt and freshly ground black pepper, to taste\r\n1 pound asparagus, trimmed\r\n1/4 cup all-purpose flour\r\n2 large eggs, beaten\r\n', 'Preheat oven to 425 degrees F. Lightly oil a baking sheet or coat with nonstick spray.\r\nIn a large bowl, combine Panko and Parmesan; season with salt and pepper, to taste. Set aside.\r\nPut flour and asparagus into a large plastic bag and shake.  Repeat with egg and then again with the panko/cheese combo.\r\nPlace asparagus in a single layer onto the prepared baking sheet. Place into oven and bake for 10-12 minutes, or until golden brown and crisp. Or put under the broiler..... takes less time and gets nice and toasted.\r\nServe immediately.', 'This is a LOT of asparagus...  feeds 12.  \r\nGood as a first course with aioli sauce.  \r\n', 8);
INSERT INTO `recipe` (`recipeID`, `recipe_title`, `recipe_ingredients`, `recipe_method`, `recipe_note`, `catID`) VALUES
(177, 'lemon tarte.', 'Filling:\r\n5 eggs\r\n5 egg yolks\r\n1 cup granulated sugar\r\n2 tsp grated lemon zest\r\n3.4 cup lemon juice\r\npinch salt\r\n2 tbsp cold butter\r\n\r\nPastry\r\n1 cup all purpose flour\r\n2 tbsp granulated sugar\r\n1/2 cup cold butter, cubed\r\n1 egg yolk\r\n2 tbsp ice water\r\n\r\nTopping:\r\n2 tbsp granulated sugar\r\n', 'Filling:\r\nIn top of a double boiler or large heatproof bowl set over saucepan of simmering water, whisk together the eggs, egg yolks, sugar, lemon zest, lemon juice and salt.  cook, stirring until mixture is translucent and thick enough to mound onto a spoon. 10 to 15 minutes.  Strain through a fine mesh sieve into a bowl.  Stir in butter until melted.  Place plastic wrap directly on the surface.  Refrigerate until chilled approx 2 hours ( Make ahead and refrigerate up to 24 hours)\r\n\r\nPastry:\r\nWhile filling is chilling, in a bowl, whisk flour with sugar.  Using pastry blender or 2 knives, cut in butter until mixture resembles fine crumbs with a few larger pieces.  Whisk egg yolk with ice water;  drizzle over flour mixture, tossing with fork to form ragged dough.  Shape into disc;  wrap in plastic wrap and let stand for 15 minutes.\r\n\r\nOn lightly flour surface, roll out dough into 11 inch wide circle;  fit into fluted 9 inch tart pan with removable burrow.  Trim to fit, leaving 1 inch overhang;  fold overhang inside pan and press to see pastry.  Refrigerate until firm, about 45 minutes.  Make ahead. Cover and refrigerate for up to 24 hours\r\n\r\nPrick bottom of the crust at 1/2 inch intervals.  Line with foil;  fill with pie weights or dried beans.  Bake on bottom rack of 400 F oven until edge is golden, 12 to 15 minutes.  Remove pie weights and foil.  Bake until crust is golden, 8 to 10 minutes.  Let cool slightly on the rack.\r\n\r\nSpoon filling into the crust, smoothing top.  Bake on bottom rack of 325 F oven until filling is set yet still slightly jiggly in centre.  12 to 15 minutes.  Let cool on rack for 30 minutes.   Refrigerate until chilled, about 4 hours.\r\n\r\nTopping:  Sprinkle sugar evenly over the filling, living 1/2 border.   Let stand for 5 minutes.  Using blowtorch and holding flame at least 1/2 inch from surface, move flame back and forth over sugar until bubbling and dark amber.  Let stand 5 minutes before serving.', 'Serve possibly whipped cream and berries.\r\n\r\nFrom Canadian Living.  Absolutely delish.  ', 3),
(178, 'Delish cheesy garlic bread - serves 4', '1/4 cup butter, softened\r\n&#8531; cup  fresh parsley, finely chopped (15 g)\r\n&#8531; cup  green onions, sliced (50 g)\r\n&#8531; cup  fresh oregano, minced (15 g)\r\n5 cloves garlic, minced\r\n½ cup  shredded cheddar cheese (50 g)\r\n½ cup  fresh mozzarella cheese, chopped (60 g)\r\n½ cup  shredded parmesan cheese (50 g)\r\n1 baguette, 8-inch', 'Preheat the oven to 400°F (200°C). Line a baking sheet with parchment paper.\r\nIn a medium bowl, combine the butter, herbs, garlic, and cheese and mix until smooth.\r\nSlice the baguette in half lengthwise, then spread the butter mixture to your liking evenly on the cut sides of the baguette (any leftover mix can be frozen for up to 1 month).\r\nPlace the baguette on the prepared baking sheet and bake for 15 minutes, until the cheese is bubbly and starting to brown on the edges.\r\nSlice, cool, and serve!', 'I just used whatever cheese I had on hand and skipped the fresh herbs. Still yummy', 7),
(179, 'Chicken Cordon Bleu with creamy Dijon Sauce', ' 4 boneless, skinless chicken breasts\r\nsalt, to taste\r\npepper, to taste\r\n1 tablespoon  garlic powder\r\n1 tablespoon  onion powder\r\n16 slices swiss/provalone cheese\r\n½ lb  ham/proscuotto, thinly sliced (225 g)\r\n\r\n\r\nCREAMY DIJON SAUCE\r\n\r\n3 tablespoons  butter\r\n2 cloves garlic, minced\r\n3 tablespoons  all-purpose flour\r\n2 cups  milk (480 mL)\r\n¼ cup  dijon mustard (60 g)\r\n1 cup  shredded parmesan cheese (100 g)\r\nsalt, to taste\r\npepper, to taste', 'Preheat oven to 350\r\nSprinkle the chicken breasts with salt, pepper, garlic powder, and onion powder, tossing to coat evenly.\r\nOn a cutting board, place a chicken breast between two sheets of plastic wrap and pound until about ½ inch (1 cm) thick with a meat mallet, rolling pin, or heavy pan.\r\nRemove the plastic wrap and place 2 slices of Swiss cheese, then 2 slices of ham, then another layer of Swiss cheese, and another layer of ham. Evenly roll the chicken and place onto a new sheet of plastic wrap.\r\nWrap the chicken in the plastic wrap tightly and use the excess plastic on the sides to twist, firming up the roll of chicken cordon bleu as you work. Tie the excess plastic. Repeat with the remaining ingredients, then chill the rolls in the fridge to set for 30\r\nUnwrap then place in flat pan and roast for 30 minutes or more.  Temp 165 degrees\r\n\r\nMeanwhile, prepare the sauce. In a 1 ½-quart saucepan over medium heat, melt the butter and cook the garlic until soft. Add the flour and whisk for 1 minute.\r\nAdd the milk and whisk until fully combined with the roux and no lumps remain. Continue whisking until the mixture comes to a simmer and has thickened.\r\nAdd the mustard, Parmesan cheese, salt, and pepper and whisk to combine. Remove the pan from the heat.\r\nSlice the chicken and serve drizzled with Dijon sauce.', 'The sauce makes the chicken.  Would be good with any type of chicken or even over pasta.', 10),
(180, 'crockpot Mexican chili chicken', NULL, 'Put the chicken, soup and chilis into the crockpot on low for 6 to 8 hours.  Remove and shred.  Strain the broth and keep the amount of liquid you want for however you want to serve it.  Then replace the chicken and amount of broth you want to keep with the cheese and let it melt in.  ', 'If you keep all the liquid, you could serve it over pasta.  If you keep only half, then you can use the chicken for enchiladas.  If doing this, put a bit of the left over chilis sauce on the bottom of a 8 x 12 pan.  spoon the dryer version of the chicken in aline down the tortillas.  Wrap up the sides then roll them closed.  Place in the pan with open side down.  Sprinkle cheese and some of the left over creamy chilis sauce over then.  Bake 350 uncovered for 20 to 30 minutes.\r\n\r\nAlso note, if you keep the full original recipe and just add broth to it...  it makes a terrific base for a chicken soup...  just add extra chicken broth separately ', 21),
(181, 'Quick chicken Ficasse', '6 boneless chicken thighs with skin on\r\n2 large leeks sliced\r\npackage sliced muchrooms\r\n2 large carrots thinly sliced\r\n3 tablespoons olive oil - divided\r\n2 table spoons butter - divided\r\n1/2 cup white wine.. or touch more\r\n1 cup chicken broth\r\nherb de Provence\r\nor 1/2 tsp tarragon\r\n1/2 tsp garlic powder\r\n1/2 tsp ground thyme\r\nsalt and pepper to taste\r\n', 'Heat 1 tablespoon oil in hot pan.  Salt and pepper both sides of the chicken breasts.  Place skin side down in the oil and cook until skin is brown...  5 minutes.  Remove from the pan and discard fat.  Pour in wine and stir around to pick up brown bits.  30 seconds.  Add chicken broth.  Stir additional 30 minutes.  Put chicken back in, skin side up.  Simmer 20 to 25 minutes or longer to get more tender chicken. \r\nMeanwhile add 1 tsp oil and touch of butter to new pan and saute sliced leeks till golden.  Salt and pepper to taste.  Remove from pan.  Add 1/4 cup chicken broth to pan with a tsp butter.  Add carrots, cover pan and simmer 5 minutes.  Remove when still have some bite to them.  Add to leeks.  \r\nAdd 1 tbsp olive oil to pan. Heat then add mushrooms, season with salt and pepper, garlic and thyme.  Stir still golden and tender.  Then add the other veggies to the pan and keep it warm.  \r\nWhen chicken is cooked.  Remove from the pan.  Taste the juices left over.  Decide if you want to add some lemon juice to make it pop, or just leave it alone.  You could add some chicken Bisto to it if you want to thick slightly.\r\n\r\nIn wide bowls, laden in some mixed veggies.  Put 2 thighs on top of it then spoon some of the sauce over all. \r\nServe with pepper on the table.', 'Pretty yummy and quick to make.  Could also make it with chicken breasts, but would have to cut it up, and just braise in broth and wine.', 10),
(182, 'Creamy Sun Dried tomatoes sauce on chicken', '4 chicken breasts boneless and skinless\r\n1 package sun-dried tomatoes (4 oz)\r\n3/4 cup water\r\n1 cup cooking cream 35%\r\n1 cup parmesan cheese\r\ndried red pepper\r\nsalt and pepper\r\n', 'Put the tomatoes and water into a blender until smooth\r\nmix it with the cream.  Add some red pepper if you like.\r\nCut breasts in half and put into the cooker.  Pour the sauce over the chicken.  Cook on low 6 hours.  Then add the parmesan and stir until melted.\r\nServe with pasta or salad.', 'Make sure to buy \"cooking\" cream as any other will probably separate with the long cooking time', 21),
(183, 'Buddha Bowl...  delish, dinner salad.  Nothing else required.', 'Dressing\r\n2 1/2 tbsp olive oil\r\n2 cloves garlic, minced\r\n1/ tsp onion powder\r\n1/2 tsp cumin\r\n1/2 tsp cumin\r\n1/2 tsp paprika\r\n\r\n\r\n1 cup butter nut squash peeled and diced\r\n1 cup mushrooms - quartered\r\n1 cup brussel sprouts - halved\r\nsalt to taste\r\npepper to taste\r\n1/3 cup tahini\r\n1 tbsp maple syrup\r\n1 tbsp apple cider\r\n1 tbsp orange juice\r\n2 tbsp water\r\n 1 tsp balsamic vinegar\r\n\r\n3 cups quinoa , cooked***\r\n2 cups kale or spinach\r\n1 cup lentils cooked***\r\n1/2 cup red cabbage, diced\r\n1 can of sliced beets\r\nroasted walnuts or whatever nuts you have', 'Preheat oven to 400.\r\nIn a smal bowl combine the olive oil, garlic, onion powder, cumin, and paprika.  Mix well\r\narrange squash, mushrooms and sprouts, in seperate piles, on a roasting pan\r\nseason with salt and pepper and drizzle with seasoned oil.  Mix well with your hands.\r\nbake for 20 minutes or ....\r\nmake dressing:  combine tahini, maple syrup, apple cider, orange juice, balsamic  water and a pinch of salt and pepper. Mix well.\r\nIn a low wide individual bowl, place 1/2 cup rice/quinoa mix.  then place spinach in the other half of the bowl.  Then place all the various veggies around in a cirlcle.  Top with the nuts.  Drizzle with the dressing.  \r\nYum.  ', '****\r\nI used PC brown rice and lentils in the 2 minute pouch. Not quinoa\r\nI used spinach instead of kale\r\nLentils were in the PC rice mixture\r\nI used a can of sliced beets...  warmed in the oven with the roasted veggies\r\nI had some extra feta, it was nice on top.\r\nCould easily use peptides instead of walnuts or anything crunchy.', 17),
(184, 'Cauliflower Pizza Crust - Epicurious', '1 large head of cauliflower\r\n1/2 cup motz cheese\r\n1 large egg\r\n1 tsp granulated garlic\r\n1 tsp granulated onion\r\n1/2 tsp dried oregano\r\nsalt and pepper\r\n', 'Cut florets and discard the core. coarsely chop florets and transfer to food processor.  Pulse until appears like couches. Spread on a baking sheet and bake for 15 minutes, tossing.\r\nWhen cool enough to handle, transfer to a clean kitchen towels and squeeze until very dry.  should get `1.5 to 2 cups of water.\r\nPut cauliflower into a medium bowl and add all other ingredients and mix well. spread out on a lightly oiled parchment lined baking sheet.  Press into 2 - 7 inch rounds, being sure to press closed any cracks.  Bake until light golden.  approx 22 minutes. turning half way thou.  Remove from the oven and cool slightly.  \r\nCoat another parchment paper, put coated side face down on the crusts then place another baking sheet on top and flip.  peel off the first sheet and return crusts to the oven and bake 1 ro 14 minutes until golden.  \r\nRemove crust.  Move rack up to the top third.  Load crusts as per desire.  Bake until bubbly approx 7 to 10 minutes.', 'Most important to get the cauliflower as dry as possible.  You could also add some parmesan to the crust before forming as a further drying agent.', 8),
(185, 'Creamy dill sauce for salmon or trout', '1/3 cup fat free plain Greek Yogurt\r\n3 Tbsp mayonnaise (full fat)\r\n1 clove garlic , finely minced\r\n1 Tbsp chopped fresh dill\r\n2 - 3 tsp milk\r\n1/2 tsp honey\r\nSalt and freshly ground black pepper', 'In a bowl, mix together Greek yogurt, mayonnaise, garlic, dill, honey, and enough milk to reach desired consistency.\r\nSeason with salt and pepper to taste. Store in refrigerator, allow to rest at room temperature 20 minutes before serving (just so it\'s not ice cold over warm salmon).', 'To season the fish, you can just use bay seasoning or massage the fish with lemon juice and olive oil and season wth salt and pepper.  ', 14),
(186, 'Trout with Old Bay Seasoning w Cream lemon sauce', 'INGREDIENTS\r\n\r\n2 whole butterflied trout (about 12 oz. each), heads removed\r\n2 tsp. Old Bay seasoning\r\n3 Tbsp. unsalted butter, cut into small pieces, divided\r\n1 lemon, thinly sliced\r\n3 medium ears of corn, kernels cut from cobs (about 3 cups)\r\n6 oz. green beans, cut into 1\" pieces\r\n1 large tomato, cut into 1\" pieces\r\n1 tsp. kosher salt\r\n3/4 cup mayonnaise\r\n1/4 cup fresh lemon juice\r\n1/2 tsp. freshly ground black pepper', 'Arrange a rack in top third of oven; preheat to 450°F. Line an 18x13\" rimmed baking sheet with foil. Lay trout open like a book, skin side down and alternating head-to-tail next to each other on one half of pan. Sprinkle flesh with Old Bay, then dot with half of butter. Arrange lemon slices over.\r\n\r\nRoast until trout is opaque and cooked through, about 10 minutes. You want to check the thickest part of the flesh—if you need to lift a lemon to look at it, do so, and continue roasting until it’s totally opaque.\r\nWhile fish is cooking, whisk mayonnaise, lemon juice, and pepper in a small bowl until smooth.\r\nDivide trout and succotash among plates. Serve with mayonnaise sauce alongside.\r\n', 'super yummy with the creamy dill sauce as an alternative', 14),
(187, 'Low fat broccoli and leek soup', '1 tbsp butter\r\n4 leeks chopped\r\n1/4 tsp salt\r\n1/2 tsp pepper\r\n1/4 corriander\r\n2 heads broccoli, chopped\r\n1-32 oz carton low sodium chicken broth\r\n1 - 12 oz can fat free evaporated milk', 'Melt butter in a large pot and cook leaks until soft and translucent.  stir in seasoning.  add broccoli until it is bright green.  Pour in chicken stock and bring to a boil.  Cover and simmer until broccoli is very tender\r\n\r\nPour into a blender or use immersion blender.\r\n\r\nWhen ready to serve, add the condensed milk, stir , warm slightly and serve hot', 'anything with leeks makes me happy!!  can serve with croutons on top or sprinkled with cheddar cheese.', 5),
(188, 'Easy Red Lentil and Tomato Soup', '7 ounces red lentils, washed and grit removed\r\n3 cups chicken stock\r\n1 28 oz can chopped tomatoes\r\nsalt and pepper to taste\r\n1/2 tbsp ground coriander', 'After washing the lentils, bring them to a boil with stock in a large pot for 10 minutes.\r\ncover the pan, lower heat to simmer and cook for a further 15 minutes\r\n\r\nadd tomatoes, including juices and herbs into pit and blend with immersion blender till smooth.\r\nfurther cook until reduced to the thickness you like.\r\nseason with salt and pepper.', 'You could add a bit of cream at the end or a bit of cocoanut milk if you like.  ', 5),
(189, 'keto pizza crust - made with chicken!!', '10 oz Canned Chicken\r\n1 oz grated parmesan cheese\r\n1 large Egg', 'Thoroughly drain the canned chicken, getting as much moisture out as possible.\r\nSpread chicken on a baking sheet lined with a silicon mat. Bake at 350 for 10 minutes to dry out the chicken.\r\nOnce chicken is done baking for 10 minutes remove and place in a mixing bowl. Increase heat of oven to 500 degrees.\r\nAdd cheese and egg to the bowl with chicken and mix.\r\nPour mixture onto baking sheet lined with a silicon mat and spread thin. Placing parchment paper on top and using a rolling pin makes this easier.\r\nOptional: With a spatula press the edges of the crust in to for a ridge for the crust. This is beneficial is you\'re using topping that may slide off(i.e. eggs).\r\nBake the crust for 8-10 minutes at 500 degrees.\r\nRemove crust from oven. Add desired toppings and bake for another 6-10 minutes at 500 degrees. Toppings will dictate final cook time.\r\n', 'Al really liked this.  I think the next time I make this, I will rinse the chicken to be sure to release some of the sodium', 15),
(190, 'Loaded Caullflour Casserole - serves 6', '1 cauliflower\r\n1/2 cup 2% milk or cream... fat preference****see notes\r\n1/2 cup bacon bits - maybe 4 slices?***. see notes\r\n1/4 butter or more to taste\r\n1/4 tsp garlic powder (to taste)*** see notes\r\n1/2 cup sour cream\r\n3/4 cup shredded cheddar cheese or more to taste - divided\r\n3 green onions - chopped and divided\r\nsalt and pepper to taste\r\n\r\n', '1 Cut cauliflower into flowerlets and microwave (covered) with 1/8 of water until very tender.  When done, drain well and allow steam to dissipate. You want a dry cauliflower.  \r\n2.  Transfer to a large bowl and add butter, milk, garlic powder.  Hand blend (or use stand up blender) into smooth consistency.... like mashed potatoes.   Add sour cream, 1/2 cup or more of cheese, 2/3rds of the green onions.  Season with salt and pepper to taste.  Taste it!!!! Spoon mixture into a casserole dish.\r\n3.  Top with reserved green onions, cheese and the bacon bits.\r\n4.  Bake uncovered in 400 degree oven until piping hot and cheese is melted. Your choice to put under the broiler to get some browning on top.', 'I think if you mix the bacon in with the main body, you will end up with soggy bacon, hence just putting it on top.  Cauliflower is wetter than baking potatoes.\r\n\r\nYou can make this a couple days in advance and refrigerate.  Then reheat and put under the broiler for a couple minutes to recrisp the bacon.  Soggy bacon is less than lovely.\r\n\r\nNote, the idea is to make it the same consistency of baked potatoes.  Hence very little water and richer milk as an additive.  Extra yummy is to microwave the milk first with grated 1 garlic  clove instead of the powder for a few minutes.  Smells so good!!', 8),
(191, 'Pull Apart Galic Bread', '1 8 inch loaf of choice (sour dough, pumpernickel)\r\n1 cup butter or more.  Needs lots for a while loaf \r\n3 tablespoons extra-virgin olive oil \r\n4 or 5 cloves garlic, finely grated  \r\n3 tablespoons finely chopped fresh parsley\r\n1 cup shredded mozzarella cheese \r\n1/2 cup grated Asiago/Parmesan cheese', 'Preheat the oven to 400 degrees F.\r\nUse a bread knife to cut a cross-hatch pattern into the top of the bread, stopping short of cutting through to the bottom of the loaf (so the loaf holds together).\r\nMelt the butter in a small skillet over low heat. Add the olive oil and garlic and cook, stirring often, until very pale golden, about 4 minutes. Stir in the parsley. Remove from the heat.\r\nGently separate the cubes of bread from the top of the loaf. Spoon some of the garlic butter in the cuts and spread it over the cut surfaces; use all but 2 tablespoons of the garlic butter for this. Stuff the motto cheese into the spaces.   Add the asiago cheese to the left over garlic butter and slather it all on top of the loaf. Wrap the loaf in foil and place it on a baking sheet.\r\nBake the bread until heated through, about 10 minutes. Unwrap the foil and continue baking until slightly crisp on the outside, 5 to 7 minutes more. Serve immediately.', 'the original recipe called for 1/4 cup of butter!!!  crazy.', 18),
(192, 'Twice Baked Potatoes - makes 16 halves!!', '8 baking potatoes, washed\r\n3 tablespoons canola oil\r\n2 sticks salted butter\r\n1 cup bacon bits (fry your own!)*****\r\n1 cup sour cream\r\n1 cup Cheddar or Jack cheese (or a mix of both), plus more for topping\r\n1 cup whole milk\r\n2 teaspoons seasoned salt\r\n3 green onions, sliced*****\r\nFreshly ground black pepper', 'Preheat the oven to 400 degrees F.\r\nPlace the potatoes on a baking sheet. Rub them with the canola oil and bake for 1 hour, making sure they\'re sufficiently cooked through.\r\nSlice the butter into pats. Place in a large mixing bowl and add the bacon bits and sour cream. Remove the potatoes from the oven. Lower the heat to 350 degrees F.\r\nWith a sharp knife, cut each potato in half lengthwise. Scrape out the insides into the mixing bowl, being careful not to tear the shell. Leave a small rim of potato intact for support. Lay the hollowed out potato shells on a baking sheet.\r\nSmash the potatoes into the butter, bacon and sour cream. Add the cheese, milk, seasoned salt, green onions and black pepper to taste and mix together well. (IMPORTANT: If you plan to freeze the twice-baked potatoes, do NOT add the green onions.)\r\nFill the potato shells with the filling. I like to fill the shells so they look abundant and heaping. Top each potato with a little more grated cheese and pop \'em in the oven until the potato is warmed through, 15 to 20 minutes.\r\n', 'Notes****\r\nI prefer to put the bacon on top of the potatoes.  \r\nI think chives work just as well. Just use more.  Save some to sprinkle on top along with the bacon and extra cheese.', 8),
(193, 'Fast Chicken Enchiladas', '1 posted chicken.  Bones and skin removed\r\n6 8\" tortillas\r\n1 cup sour cream\r\n2 cups cheddar cheese - divided\r\n1 medium onion - chopped\r\n1 pouch taco seasoning\r\n1 cup salsa\r\n1/2 cup hot taco sauce\r\n1/2 cup tomatillo sauce****\r\n', 'Strip chicken of bones and skin, shred.\r\ncombine chicken, sour cream and 1 cup cheddar cheese, onions in a pot.  Stir and put over stove element to warm for 15 minutes\r\nPlace the salsa and hot taco sauce into a pot and warm as well.\r\n\r\nWhen ready to assemble..... 10 minutes before eating.  spread a couple tbsps of tomatillo sauce over each tortilla.  Place approx 3/4 cup hot chicken mixture in a line in the centre of each tortilla.  Wrap, ends in first then roll in the sides.  Place open side down in a low sided roasted pan.  Repeat with all tortillas   \r\n\r\nPlace in the 400 oven for 10 minutes until the tortillas brown.  Take out, and cover with the extra 1 cup of shredded cheddar cheese. place back into the oven until the cheese has melted and hopefully browned.\r\n\r\nPlate and serve with hot salsa and sour cream on the side.', 'This method is to avoid soggy tortillas.', 10),
(194, 'Mexican Lasagna', '4 8\" tortillas\r\n2 tsp veg oil\r\n1 cup chopped onions\r\n2 tsp mince garlic\r\n1 cup chopped green peppers\r\n1 cup drained canned corn\r\n1 cup medium salsa\r\n1 tsp dried oregano\r\n1/2 tsp cumin\r\n1 1/2 cup shredded cheddar cheese**\r\n1/2 cup ricotta cheese****\r\n2 oz cream cheese, softened\r\n1/3 cup sour cream\r\n1 can/ 2 cups rinsed and drained red kidney beans, mashed\r\n\r\nServe with sour cream and salsa on the side.  \r\n', '1. Preheat oven to 375\r\n2  Trim tortillas to fit a 9 inch springform pan\r\n3.  in a skillet, heat oil over medium heat;  cook onions for 5 minutes. Stir in green peppers and corn.  cook for 8 minutes, stirring constantly until corn begins to char. briefly add garlic.   Stir in salsa, oregano and cumin.  Remove from heat.  Meanwhile, place beans on a plate and mash with a fork.  Then add the beans to the veggie mix.  \r\n4.  In a bowl, stir together the cheeses and sour cream\r\n5. Place 1 tortilla in the pan.  spread with 1/3 the veggie mix.  then 1/3 the cheese mix.  Sprinkle 1/3 of the cheddar on top of that.\r\n6. repeat and have a bare tortilla on top.  Sprinkle with cheddar.\r\n7. Cover with foil and bake for 45 minutes until hot.', 'This is a good recipe to clear out bits and pieces of veggies and cheese I have in the fridge.  It is definitely ok to make more filling than the recipe calls for.\r\n\r\nI use whatever cheese I have on hand. Cream cheese, Swiss cheese.....  whatever. \r\n ', 15),
(195, 'Salmon Cakes by Barefoot Contessa (great for leftover salmon)', '1/2 pound fresh salmon (or use leftover salmon)\r\nGood olive oil\r\nKosher salt and freshly ground black pepper\r\n4 tablespoons unsalted butter\r\n\r\nBelow 5 veggies can be put into food processor together)\r\n3/4 cup minced red onion (1 small onion)\r\n1 1/2 cups minced celery (4 stalks)\r\n1/2 cup minced red bell pepper (1 small pepper)\r\n1/2 cup minced yellow bell pepper (1 small pepper)\r\n1/4 cup minced fresh flat-leaf parsley\r\n\r\n1 tablespoon capers, drained\r\n1/4 teaspoon hot sauce (recommended: Tabasco)\r\n1/2 teaspoon Worcestershire sauce\r\n1 1/2 teaspoons crab boil seasoning (recommended: Old Bay)\r\n3 slices stale bread, crusts removed\r\n1/2 cup good mayonnaise\r\n2 teaspoons Dijon mustard\r\n2 extra-large eggs, lightly beaten', 'Preheat the oven to 350 degrees F.\r\n\r\nPlace the salmon on a sheet pan, skin side down. Brush with olive oil and sprinkle with salt and pepper. Roast for 15 to 20 minutes, until just cooked. Remove from the oven and cover tightly with aluminum foil. Allow to rest for 10 minutes and refrigerate until cold.\r\n\r\nMeanwhile, place 2 tablespoons of the butter, 2 tablespoons olive oil, the onion, celery, red and yellow bell peppers, parsley, capers, hot sauce, Worcestershire sauce, crab boil seasoning, 1/2 teaspoon salt, and 1/2 teaspoon pepper in a large saute pan over medium-low heat and cook until the vegetables are soft, approximately 15 to 20 minutes. Cool to room temperature.\r\n\r\nBreak the bread slices in pieces and process the bread in a food processor fitted with a steel blade. You should have about 1 cup of bread crumbs. Place the bread crumbs on a sheet pan and toast in the oven for 5 minutes until lightly browned, tossing occasionally.\r\n\r\nFlake the chilled salmon into a large bowl. Add the bread crumbs, mayonnaise, mustard, and eggs. Add the vegetable mixture and mix well. Cover and chill in the refrigerator for 30 minutes. Shape into 10 (2 1/2 to 3-ounce) cakes.\r\n\r\nHeat the remaining 2 tablespoons butter and 2 tablespoons olive oil in a large saute pan over medium heat. In batches, add the salmon cakes and fry for 3 to 4 minutes on each side, until browned. Drain on paper towels; keep them warm in a preheated 250 degree F oven and serve hot.', 'I made Tarter Sauce\r\n1 cup approx mayo\r\n2 tsp dijon mustard or to taste\r\n3 tbsp relish\r\n2 tbsp drained capers\r\nsplash of lemon juice\r\nsalt and pepper to taste\r\n', 14),
(196, 'Lasagna', '1 lb beef\r\n1 lb hot Italian sausage\r\n1 medium onion chopped\r\n2 jars favorite tomate sauce ( I like roasted tomato and garlic)\r\n1 large container full fat cottage cheese\r\n1 egg \r\n1 block of frozen spinach - thawed and squeezed dry\r\n1 full block mozzarella shredded (save a bit to put on top of the last layer of noodles)\r\n1/4 cup grated parmesan cheese\r\n9 or 10 whole wheat lasagna noodles (I like to put 4 noodles on the bottom layer to give it more support when lifting pieces out)\r\n', 'Remove sausage from casing.  Brown the beef and the sausage together in a medium sauce pan along with the onions.  Break up the meat with the back of a form to uniform crumbles. Once browned, pour in the tom sauce and bring to a simmer.  Add the drained spinach. Cover and simmer at least 30 minutes to 1 hour.\r\nMeanwhile cook the noodles  to dente and lay out on a tea towel to rest while preparing the rest of the meal.\r\nAssembly:  thin layer of meat sauce, then 3 noodles,Mix the egg with the cottage cheese,   Layer half the cottage cheese then half the mozzarella.  \r\n2nd layer of noodles and repeat the meat and cheeses.  \r\nTop with last layer of noodles. Spray lightly with olive oil.\r\nsprinkle last layer of noodles with thin layer of Parmesan cheese \r\nSpray a sheet of foil with oil. Cover the lasagna and bake at 350 for 30 minutes or until bubbling.  Remove the foil and turn the oven to broil.  Brown the cheese briefly.  Remove from the oven.  \r\nLet it rest for 5 minuets to set and serve.\r\n\r\n', 'I like to make  and bake the pasta a few hours early.  Then 45 minutes before I want to eat, I put the lasagna back into the oven for a second time so that it is twice baked.  Extra yummy that way.  \r\n\r\nKeto lagana:  3 eggplants sliced into 5 or 6 long slices each. sprinkle with lots of salt to sweat it.  Dab off after 30 minutes.  wipe off excess salt.  Roast the egg plant for 20 to 30 minutes until golden but not too overdone.  use instead of noodles.', 11),
(197, 'Super Easy and Delish Berry Bumble/Cobbler', '1/2 cup plus 2 tablespoons melted butter, divided\r\n1 cup self-rising flour\r\n1-1/2 cups sugar, divided\r\n1 cup 2% milk (or what you have)\r\n1/2 teaspoon vanilla extract\r\n1 bag frozen mixed berries - thawed and drained', 'Preheat oven to 350°. Pour 1/2 cup melted butter into an 8-in. square baking dish. In a small bowl, combine flour, 1 cup sugar, milk and vanilla until blended; pour into prepared dish. In another bowl, combine blackberries, remaining 1/2 cup sugar and remaining 2 tablespoons melted butter; toss until combined. Spoon over batter as evenly as possibly.\r\nBake until topping is golden brown and fruit is tender, 45-50 minutes. Serve warm.', 'Best served warm.  Can be reheated in the microwave on low heat.', 3),
(198, 'Super simple, delish  slow cooker beef stew.  ', '2 pounds beef stew meat, cut into 1-inch pieces\r\n¼ cup all-purpose flour\r\n½ teaspoon salt plus ½ teaspoon ground black pepper (or 1 tsp steak seasoning)\r\n1 clove garlic, minced\r\n1 bay leaf\r\n1 teaspoon paprika\r\n1 teaspoon Worcestershire sauce\r\n1 onion, chopped\r\n1&#8201;½ cups beef broth\r\n3 potatoes, diced\r\n4 carrots, sliced\r\n1 stalk celery, chopped', 'Step 1\r\nPlace meat in slow cooker. In a small bowl mix together the flour, salt, and pepper; pour over meat, and stir to coat meat with flour mixture. Stir in the garlic, bay leaf, paprika, Worcestershire sauce, onion, beef broth, potatoes, carrots, and celery.\r\n\r\n Step 2\r\nCover, and cook on Low setting for 10 to 12 hours, or on High setting for 4 to 6 hours.', 'As noted...   I use steak seasoning instead of just salt and pepper.\r\n\r\nI got this recipe from Allrecipes.  First time I have not browned the meat first and it turned out lovely.  Simplest stew recipe I have ever made.', 21),
(199, 'Jalapeno Popper Baked Chicken Breasts', '4 slices thick cut bacon, diced\r\n&#9634; 1 tablespoon vegetable oil\r\n&#9634; 1 tablespoon butter\r\n&#9634; 4 (1-pound, total) boneless, skinless chicken breasts, pounded to 1/4-inch thickness\r\n&#9634; salt and fresh ground pepper, to taste\r\n&#9634; 1/2 teaspoon garlic powder\r\n&#9634; 1/2 teaspoon smoked or sweet paprika\r\n&#9634; 6 ounces cream cheese\r\n&#9634; 4 to 5 jalapeño peppers, seeded and diced\r\n&#9634; 4 ounces shredded white and yellow cheddar cheese\r\n&#9634; chopped fresh parsley, for garnish', 'Preheat oven to 400&#730;F.\r\nLightly grease a 9x13 baking dish with cooking spray; set aside.\r\nAdd diced bacon to a large skillet and cook until crispy over medium-high heat.\r\nRemove bacon from skillet and set aside.\r\nReturn skillet to heat and add vegetable oil to the remaining bacon grease.\r\nPound chicken breasts to a 1/4-inch thickness and season with salt, pepper, garlic powder, and paprika.\r\nAdd chicken breasts to the hot oil (you may have to cook the chicken in batches if skillet isn\'t big enougand cook chicken breasts for 2 minutes, or until golden brown.\r\nFlip the chicken breasts, add butter, and continue to cook for 2 more minutes.\r\nRemove chicken breasts from skillet and arrange in previously prepared baking dish. Set aside.\r\nReturn skillet to heat and add in the cream cheese; cook for 1 minute, or until smooth and creamy.\r\nMix cream cheese and jalepanos.  Add dollops of the cream cheese mixture over the chicken breasts in the baking dish.\r\nTake half of the bacon and add on top of the cream cheese.\r\nTop with shredded cheese.\r\n\r\nBake, uncovered, for 17 to 19 minutes, or until chicken is cooked through and cheese is melted and lightly browned.\r\n\r\nRemove from oven and let stand 5 minutes.\r\nGarnish with remaining diced bacon and fresh parsley.\r\nServe.\r\n\r\n\r\n ', 'Creamy and spicy and definitely not low calorie.', 10),
(200, 'Easy Cheese Stuffed Jalapeños', '24 medium fresh jalapeno peppers\r\n1 package (8 ounces) cream cheese, softened\r\n3 cups finely shredded cheddar cheese\r\n1-1/2 teaspoons Worcestershire sauce\r\n4 bacon strips, cooked and crumbled', 'Preheat oven to 400°. Cut jalapenos in half lengthwise; remove seeds and membranes. In a large saucepan, blanch the peppers for 1 minute (the longer you boil the peppers, the milder they become). Drain and rinse in cold water; set aside.\r\nIn a small bowl, beat the cream cheese, cheddar cheese and Worcestershire sauce until smooth. Spoon 2 teaspoonfuls into each jalapeno; sprinkle with bacon. Arrange on greased baking sheets. Bake until filling is warmed, 3-5 minutes.', 'Wear gloves while handling the raw jalapeños\r\nI experimented with the blanch times.  more than 2 minutes took away all the heat.  No more than 1.5 minutes.', 9),
(201, 'Super tender braised lamb shanks / full meal in one pan', '6 large lamb shanks\r\n• 2 tablespoons olive oil\r\n• Kosher salt and freshly ground pepper\r\n• 1 large onion, cut into medium dice\r\n• 3 celery stalks, cut into medium chunks\r\n• 3 large carrots, cut into medium chunks\r\n• 3 large cloves garlic, minced\r\n• 1 tablespoon herbes de Provence or Italian\r\nseasoning\r\n• 3 tablespoons all-purpose flour\r\n• 2 cups (480 ml) chicken broth\r\n• 1 cup (240 ml) dry red wine, such as Cabernet\r\nSauvignon or Merlot\r\n• 1 can (14½ ounces/410 g) crushed tomatoes\r\n• 3 cans (16 ounces/455 g) cannellini or other white\r\nbeans, drained\r\n• 2 tablespoons chopped fresh parsley', 'Adjust the oven rack to the lower-middle position, and heat the oven to 450 F (235 C/gas 8).\r\n2. Heat a large, heavy-duty roasting pan over two burners over low heat. Meanwhile, coat the shanks with\r\nthe olive oil and season generously with salt and pepper.\r\n3. A few minutes before searing the shanks, increase the heat to medium-high until wisps of smoke rise from the\r\npan. Add the shanks and sear on all sides until browned, about 10 minutes. Transfer to a bowl; set aside.\r\n4. Add the onion, celery and carrots to the roasting pan. The shanks should have rendered enough fat to\r\nsauté the vegetables; if not, add another tablespoon of oil. Sauté until the onion is lightly browned, 5\r\nminutes. Add the garlic and herbes de Provence and cook, stirring, until fragrant, about 1 minute. Whisk in\r\nthe flour, then add the broth, wine, and tomatoes.\r\n5. Return the shanks to the pan. Place a sheet of heavy-duty foil over the pan. Press the foil down so that\r\nit touches the stew, and seal the foil completely around the edges. Repeat with a second sheet of foil\r\nto ensure a tight seal. Top with the lid, pushing it into the foil to create a tight seal. Turn the burners to\r\nmedium-high and cook until you hear the juices bubble. Set the pan in the oven and cook for 1½ hours.\r\n6. Transfer the pan to the stove top. Arrange the shanks on a serving platter and cover with foil to keep warm.\r\nStir the beans into the juices in the pan (remember that the pan handles are hot), and simmer over two\r\nburners over medium heat to blend the flavors, about 5 minutes. Stir in the parsley and serve.', 'This takes some time, but it is wonderful and a full meal in one pan with the beans.', 22),
(202, 'Loaded Baked Potato Casserole', 'Nonstick cooking spray\r\n\r\n6 slices bacon, cut 1/2-inch thick\r\n\r\n2 1/4 pounds russet potatoes (about 4), scrubbed clean and cut into 1-inch chunks (or baby potatoes, halved)\r\n\r\nKosher salt and freshly ground black pepper\r\n\r\n6 ounces cream cheese, at room temperature\r\n\r\n2 cups shredded Cheddar\r\n\r\n2/3 cup sour cream\r\n\r\n2 scallions, white and light green parts only, thinly sliced', 'Preheat the oven to 425 degrees F and spray a 3-quart casserole dish with nonstick spray. Set aside.\r\n\r\nCook the bacon in a medium nonstick skillet over medium heat, stirring occasionally, until brown and crispy, 6 to 7 minutes. Transfer to a paper towel-lined plate. Reserve 2 tablespoons of the bacon drippings. \r\nPut the potatoes into the prepared casserole dish. Toss with the reserved 2 tablespoons bacon drippings, 1 teaspoon salt and 1/2 teaspoon pepper. Roast until the potatoes are soft and begin to brown, about 45 minutes. \r\nMeanwhile, mix together the cream cheese and 1 cup Cheddar in a bowl until well combined. Dollop over the potatoes, then sprinkle with the remaining cup Cheddar and bake until the cheese is melted and bubbly and the potatoes are completely cooked through when poked with a knife, 13 to 15 minutes. \r\nDollop the sour cream evenly over the casserole and sprinkle with the scallions and bacon pieces. \r\n', 'Great for make ahead ', 8),
(203, 'Hassel Back Chicken Breasts', '1 cup milk\r\n1 tbsp white vinegar\r\n.... or 1 cup of buttermilk\r\n\r\n4 chicken breasts\r\n5 cups fresh spinach (200 g)\r\n¾ cup artichoke heart (100 g), drained, rinsed and roughly chopped\r\n1 teaspoon garlic powder\r\n¼ cup cream cheese (55 g)\r\n&#8531; cup grated mozzarella cheese (35 g)', '1 hour before:  mix milk and vinegar into a bowl or a plastic bag.  Add chicken breasts. Make sure breasts are completely covered.  Refrigerate for a few hours or leave on the counter for 30 minutes.\r\n\r\nDrain and pat the chicken dry. Discard the buttermilk. \r\n\r\nPreheat the oven to 350°F (180°C).\r\nSlice into the chicken several times, about ½ cm (¼ inch) apart, but only cut about 85% of the way through, leaving the bottom intact.\r\nCook the spinach on a medium heat until it is slightly wilted, then add the artichoke.\r\nStir in the garlic powder and cream cheese, and cook for a minute or two.\r\nSprinkle over the mozzarella and stir until melted.\r\nAllow to cool to the touch and then fill each segment of the chicken breast with about 1 teaspoon of the mixture.\r\nBake in the centre of the oven for 18-22 minutes until the chicken is cooked through and the juices run clear.', 'Very important for all chicken to marinate in the buttermilk mix to get juicy and not rubbery chicken.', 10),
(204, 'Crockpot Chicken Chimmicangos', 'Into the Crock Pot2 pounds chicken breasts\r\n1 tablespoon olive oil\r\n1/2 cup mild salsa (medium if you like spicy)\r\n3-4 tablespoons brown sugar **\r\n1 4 oz. can mild diced green chilies\r\n1 14.5 oz. can fire roasted diced tomatoes, drained (or regular)\r\n1 tablespoon chili powder\r\n1 1/2 teaspoons salt\r\n1 tsp EACH ground cumin, garlic pwdr, onion pwdr,\r\n1/2 tsp EACH smoked paprika, dry oregano, pepper\r\n1/2 teaspoon ground chipotle chili pepper (optional for more heat)\r\n1 teaspoons liquid smoke\r\n\r\n\r\n6 burrito size tortillas (I prefer raw/undercooked tortillas)*\r\n1 cup shredded sharp cheddar cheese\r\nolive oil or nonstick cooking spray\r\n\r\nCheesy Green Chili Sour Cream Sauce\r\n2 tablespoons olive oil\r\n1 tablespoon butter\r\n3 tablespoons flour\r\n2 cups low sodium chicken broth, warmed\r\n1/2 teaspoon cumin\r\n1/4-1/2 teaspoon salt\r\n1/4 teaspoon pepper\r\n1/2 cup sour cream\r\n1/2 4 oz. can mild chopped green chilies, or more to taste\r\n1/2 cup shredded sharp cheddar cheese\r\nHot sauce to taste (optional)\r\n\r\n\r\nOptional Toppings\r\nTomatoes\r\nAvocados/guacamole\r\ncilantro\r\nsalsa\r\ntortilla strips or chips', 'Throw everything into the crock pot for the chicken.  On low for 6 hours until you can shred.  Drain any excess fluid.\r\n\r\nMeanwhile, prepare Sauce by melting butter in olive oil in a medium saucepan over medium heat. Whisk in flour and cook, stirring constantly for 3 minutes. Reduce heat to low then gradually whisk in chicken broth. Add spices and bring to a simmer while stirring until thickened, about 2-3 minutes. Remove from heat and stir in green chilies, cheese until melted then sour cream. Add hot sauce to taste (optional).\r\n\r\n\r\nPreheat oven to 400 degrees F. Line a baking sheet with foil and add a baking rack on top. Prepare burritos by adding a heaping 1/2 cup filling to each tortilla (uncooked if using raw tortillas), top with desired amount of cheese and roll up burrito style. Place burritos on the baking rack and brush both sides lightly with olive oil or spray with nonstick cooking spray. Cook for 18-20 minutes or until golden. Broil to desired crispiness, flip over and broil the other side until golden.\r\n\r\nTo serve, top burritos Cheesy Green Chili Sour Cream Sauce and desired toppings.', 'Pretty yummy and lower fat than the deep fried versions', 21),
(205, 'Buddha Bowl from Tasty', '2 ½ tablespoons olive oil\r\n2 cloves garlic, minced\r\n½ teaspoon onion powder\r\n½ teaspoon cumin\r\n½ teaspoon paprika\r\n1 cup butternut squash (205 g), peeled, diced\r\n1 cup mushroom (75 g), diced\r\n1 cup brussel sprout (100 g), halved\r\nsalt, to taste\r\npepper, to taste\r\n&#8531; cup tahini (75 g)\r\n1 tablespoon maple syrup\r\n1 tablespoon apple cider\r\n1 tablespoon fresh orange juice\r\n2 tablespoons water\r\n3 cups quinoa (510 g), cooked\r\n2 cups kale (135 g)\r\n1 cup lentils (200 g), cooked\r\n½ cup red cabbage (50 g), diced\r\n½ cup beet (100 g), cooked, diced\r\n½ cup walnut (50 g)\r\n¼ cup fresh parsley (10 g), minced\r\n\r\n\r\n\r\n', 'Preparation\r\nPreheat the oven to 400°F (200°C).\r\nIn a small bowl, combine the olive oil, garlic, onion powder, cumin and paprika. Mix well.\r\nArrange the butternut squash, mushrooms and Brussels sprouts in separate piles on a baking sheet.\r\nSeason the vegetables with salt and pepper and drizzle with the seasoned oil. Mix well with your hands.\r\nBake for about 20-25 minutes, until tender.\r\nTo make the dressing, combine the tahini, maple syrup, apple cider, orange juice, water, and a pinch of salt and pepper in a small bowl. Mix well with a fork.\r\nCombine the quinoa, kale, butternut squash, mushrooms, brussels sprouts, lentils, red cabbage, beets, and walnuts in a large bowl and top with the tahini dressing and parsley.\r\n', 'good for 4 bowls or more.', 8),
(206, 'Tuna Poke Bowl ', '1 1/2 cups sushi rice\r\n\r\nKosher salt\r\n\r\n2 tablespoons rice vinegar\r\n\r\n1 tablespoon sugar\r\n\r\n1/2 cup frozen shelled edamame\r\n\r\n3 scallions, thinly sliced\r\n\r\n2 tablespoons fresh lime juice\r\n\r\n2 tablespoons fresh orange juice\r\n\r\n1 tablespoon low-sodium soy sauce\r\n\r\n1 tablespoon toasted sesame oil (or olive oil if preferred)\r\n\r\n1 teaspoon grated peeled fresh ginger\r\n\r\n1 pound sushi-grade tuna, cut into 1/2-inch cubes (I use frozen tuna steaks)\r\n\r\n1/2 English cucumber, peeled and finely chopped\r\n\r\nToasted sesame seeds, for topping', '1.  Rinse the rice in a strainer until the water runs clear. Bring 2 cups water, the rice and 1/2 teaspoon salt to a boil in a medium saucepan. Reduce the heat to low, cover and cook until the rice is tender and the water is absorbed, about 20 minutes. Let sit, covered, 10 minutes. (Or just make it in the microwave)\r\n\r\n2.  Meanwhile, combine the vinegar, sugar and 1 teaspoon salt in a small microwave-safe bowl and microwave until the sugar is dissolved, 30 seconds to 1 minute; stir. Transfer the cooked rice to a large serving bowl. Add the vinegar mixture and stir with a rubber spatula until the rice is fluffy but still sticky, 2 to 3 minutes; let cool completely.\r\n\r\n3.  Bring a small saucepan of salted water to a boil. Add the edamame and cook until tender and bright green, 3 to 5 minutes. Drain and rinse under cold water until cool. (Or cook 1 minute in the microwave)\r\n\r\n4.  Combine the scallions, lime juice, orange juice, soy sauce, sesame oil, ginger and 1/2 teaspoon salt in a large bowl. Add the tuna and edamame and stir to coat; season with salt. Divide the rice among bowls and top with the tuna mixture and cucumber. Sprinkle with sesame seeds.', 'Should serve 4 regular portions, but Al and I eat 3/4 of it.  \r\n\r\nI like to quickly sear the tuna as I like the texture better that way.  Quick and hot so interior is still raw.\r\n\r\nI often double the final sauce as I like a little extra to drizzle over the rice.   ', 14),
(207, 'Erika\'s Whole Wheat Pizza Crust', 'Ingredients:\r\n1 teaspoon granulated sugar\r\n1 packet of active yeast\r\n1 1/2 cups (360ml) warm water\r\n1 Tablespoon (15ml) olive oil\r\n1 Tablespoon (21g) honey\r\n1 teaspoon salt\r\n3 1/4 cups (407g) whole wheat flour\r\nolive oil for brushing crust\r\n', 'Directions:\r\nIn a large mixing bowl combine the sugar, yeast, and warm water (*note* if you only have instant yeast, wait until the flour step to add it). Stir it around and let sit for 5 minutes or until the yeast is foamy and dissolved. This is called \"proofing\" the yeast. If the yeast doesn\'t dissolve, your yeast is dead. Start again with active yeast. Add the olive oil, honey, and salt. Mix by hand with a whisk or with the dough hook on low speed for 30 seconds.\r\nAdd 3 1/4 cups of whole wheat flour stir with a wooden spoon until it comes together enough to dump it out on the counter. \r\nSprinkle a good amount of flour on the counter and dump the dough on top. Knead by hand (approx. 5 minutes). Keep adding flour and kneading it in if it’s really wet and sticking to your hand, but try not to go overboard - it’s ok if it’s still a little bit sticky, that’s what keeps your crust from being too dense at the end. \r\nShape the dough into a ball and place in a large mixing bowl that has been coated lightly with olive oil (I’m lazy and just scrape any of the loose gunk out of the dirty bowl and use it).  Spin the ball around to coat all sides in oil. Cover tightly with plastic wrap or place a clean towel on top and allow to rise in a warm environment.\r\nOnce the dough has doubled (1-2 hours), punch the dough down to release the air. It will deflate.\r\nCut the dough into two.\r\nRoll each half into a ball and let rest on a lightly floured counter for about 20 minutes (usually we do this step while heating up the pizza stone).\r\n', 'yields two 12-inch pizzas', 7),
(208, 'Deb\'s Chicken pasta grape salad', '3 cups uncooked bow tie pasta about 8 oz\r\n1/3 cup fresh orange juice\r\n1/4 cup fresh lemon juice\r\n2 Tbsp extra-virgin olive oil\r\n1 Tbsp stone ground mustard\r\n2 tsp sugar\r\n1/2 tsp kosher salt\r\n1/2 tsp ground black pepper\r\n1 1/2 tsp rice vinegar\r\n2 cups diced cooked chicken\r\n1 1/2 cups seedless red grapes halved\r\n2 celery stalks thinly sliced\r\n1/3 cup diced red onion\r\n1/3 cup Chopped walnuts toasted (optional)\r\n2 Tbsp chopped fresh parsley optional\r\n', 'Cook pasta according to package directions. Drain and allow to cool completely.\r\nIn a large bowl, combine orange juice, lemon juice, olive oil, mustard, sugar, salt, pepper and rice vinegar. Whisk together well.\r\nAdd cooked pasta, chicken, grapes, celery, red onion, walnuts, and parsley. Toss gently to combine. Refrigerate until ready to serve.', NULL, 11),
(209, 'Brian Lawson\'s Miso-Glazed Black Cod', '6 TBSP white miso paste\r\n4 tbsp water\r\n4 tbsp mirin (sweet Jap wine)\r\n4 tbsp sake\'2 tbsp brown sugar\r\n4 (7oz) black cod fillets', '1.  Set oven rack about 6 inches from the heat source and preheat the broker.  Line a baking sheet with foil and lightly grease the foil.\r\n2. Whisk Miso et al together in a small skillet over medium heat until it simmers and thickens sightly (1 to 3 minutes) Remove from heat and cool completely.\r\n3.  Place cod pieces on baking sheet and brush all over with miso.  Rest the cod at room temp to quickly marinate.  20 minutes or longer.\r\n4.  Broil fillets for approx 7 minutes, until fish flakes easily.  Remove pin bones.', 'Note:  you can replace the Mirin with rice wine vinegar, Sake replace with maple sugar or white wine.', 14),
(211, 'Chicken with 40 cloves of garlic', 'INGREDIENTS\r\n1 whole chicken, cut into 6 to 8 pieces - discard wings\r\nSalt and freshly ground pepper, to taste\r\n3 tbsp. olive oil\r\n3 tbsp. butter\r\n40 cloves garlic, peeled (about 3 heads of garlic)\r\n2 sprigs rosemary, chopped\r\n2 sprigs thyme, chopped\r\n2 sprigs marjoram or oregano, chopped\r\n1 tsp. crushed fennel seeds\r\n2 bay leaves\r\n3/4 cup white wine\r\n1/2 cup water\r\n1/4 cup whipping cream (35%)\r\n2 tbsp. chopped parsley, for garnishing\r\nFrench bread or baguette, for serving', 'PREPARATION\r\nPreheat the oven to 375 degrees F.\r\nSeason the chicken with salt and pepper.\r\nHeat the olive oil in a large ovenproof skillet or shallow Dutch oven over medium to medium high heat. When oil is hot, add the chicken pieces skin side down. Cook the chicken until well browned, about 5 to 6 minutes per side. Transfer to chicken to a large plate.\r\nAdd butter, garlic, rosemary, thyme, marjoram, crushed fennel seeds and bay leaves. Cook, stirring occasionally, until lightly golden, about 4 to 5 minutes.\r\nAdd wine, water and chicken back to pan. Place tight fitting lid on the pan. Transfer to oven. Bake until chicken is cooked and tender, about 1 hour.\r\nRemove chicken to serving platter. Remove bay leaves. Add cream to pan and bring just to a boil over medium high heat. Pour sauce and garlic over chicken. Garnish with parsley and serve with lots of bread.\r\nYield: 4 servings.\r\n \r\n \r\n', 'Good with ratatouille and mashed cauliflower...  add nutmeg next time.  Add baguette slices to serve with and dip into sauce.', 10);
INSERT INTO `recipe` (`recipeID`, `recipe_title`, `recipe_ingredients`, `recipe_method`, `recipe_note`, `catID`) VALUES
(213, 'Pan cooked brussel sprouts with cheese', '1 pound brussel sprouts, halve\r\n5 tbsp olive oil\r\n1 tbsp lemon juice\r\n1/4 cup shredded Parm or likewise', 'Place sprouts in a 12 inch skillet.  drizzle with oil.  Cover and cook over medium -high heat until the edges start turning brown.\r\nUncover and continue cooking for 2 to 3 minutes until the cut sides are fully brown.  \r\nIn the meanwhile.  combine the lemon juice and 1/4 tsp salt in a bowl.\r\nTake the pan off the heat. Add the lemon and salt and coat the sprouts.  Remove to a platter and sprinkle with cheese.', 'Seems like an easy way to get nicely browned and moist brussel sprouts.  ', 8),
(214, 'Ratatouille from Food Network', '1/4 cup plus 2 tablespoons extra-virgin olive oil\r\n\r\n2 yellow bell peppers, diced into 1/2-inch pieces (about 2 cups) \r\n\r\n1 large yellow onion, diced into 1/2-inch pieces (about 2 cups) \r\n\r\nKosher salt and freshly ground black pepper \r\n\r\n1 large eggplant (1 1/2 pounds), diced into 1/2-inch pieces (about 9 cups) \r\n\r\n1 large zucchini (1 pound), diced into 1/2-inch pieces (about 3 1/2 cups) \r\n\r\n3 cloves garlic, minced (about 1 tablespoon) \r\n\r\n3 tablespoons tomato paste \r\n\r\n1/2 teaspoon crushed red pepper flakes, optional \r\n\r\n1 1/2 pounds ripe tomatoes, diced into 1/2-inch pieces (about 4 cups) *******\r\n\r\n1/2 cup fresh parsley, chopped, plus more for serving *****\r\n\r\n6 large fresh basil leaves, torn, plus more for serving *****', 'Heat 1/4 cup olive oil in a medium saucepan over medium heat until shimmering, about 1 minute. Add the bell peppers, onion and 1 teaspoon salt and cook, stirring often, until the onions are translucent and the bell peppers have softened slightly, about 10 minutes. Add the eggplant, the remaining 2 tablespoons olive oil and 1 teaspoon salt. Cook, stirring often, until the eggplant is very soft, about 8 minutes. Add the zucchini and continue to cook, stirring often, until beginning to soften, about 5 minutes. Add the garlic, tomato paste and red pepper flakes, if using. Cook, stirring often, until the zucchini has softened, about 5 minutes.\r\nStir in the tomatoes, bring to a simmer and then reduce the heat to low and cover the pot. Simmer, stirring occasionally, until the ratatouille has reached a thick stew-like consistency, about 10 minutes. Stir in the parsley and basil with salt and pepper to taste. Spoon into a bowl and sprinkle with more fresh parsley and basil before serving.', 'I followed the recipe as is and really liked it. The egg plant really cooks down to create a nice consistency. \r\n\r\nServes 4 easily.\r\n\r\n*****I used dried herb.  I used canned diced tomatoes.\r\nBoth work perfectly well.\r\n\r\nI served it over mashed caulifour flavoured like mashed potatoes.  Delish!!\r\n\r\nI also served chicken breast on the side.  I ended up just cutting it up and adding it to the ratatouille on my plate.  So very good.\r\n\r\nCould easily add the chicken to the ratatouille and it becomes a great chicken stew.  ', 8),
(215, 'shove it in the oven chicken stew', '2 pounds boneless, skinless chicken thighs, cut into large pieces\r\n1 bunch leeks (about 4 medium), trimmed of dark green parts and root, light green and white part quartered lengthwise, cut into 1-inch lengths and washed thoroughly\r\n1½ pound new potatoes, your choice (red, yellow, purple, or a mix of all 3), halved\r\n½ pound carrots peeled and cut into medium chunks\r\n½ pound mushrooms, quartered if large, halved if small\r\n4 large cloves garlic, sliced\r\n¼ cup extra-virgin olive oil\r\n2 teaspoons dried tarragon\r\nSalt and freshly ground black pepper\r\n1 cup chicken broth\r\n½ cup cream heavy cream\r\n', 'Adjust oven rack to lowest position and heat oven to 425 degrees.\r\nMix chicken, leeks, potatoes, carrots, mushrooms, garlic, olive oil, tarragon, and a generous sprinkling of salt and pepper in a large heavy-duty roasting pan.  Set pan in oven and roast until cooked through and juices have released, about 45 minutes.  Remove from oven and set pan over two burners at medium-low heat. Stir in enough chicken broth to moisten; simmer to blend flavors and thicken slightly, a couple of minutes. Stir in cream; continue to simmer to heat through. Serve!', 'good and easy and great for dinner or for a group event\r\n\r\nserves 6', 10),
(216, 'Buffalo chicken chili from taste of home magazine', '2 cans (15-1/2 ounces) navy beans, rinsed and drained\r\n1 can (8 ounces) chicken broth\r\n1 can (14-1/2 ounces) fire-roasted diced tomatoes\r\n1 can (8 ounces) tomato soup\r\n***. could add some sliced carrots and celery\r\n1/2 cup Buffalo wing sauce... I use a whole bottle***\r\n1 onion diced\r\n1/2 teaspoon garlic powder\r\n1.5 pound boneless skinless chicken breast halves\r\n1/2 to 1 package (8 ounces) light cream cheese, cubed and softened.  to your taste.\r\nOptional toppings: Crumbled blue cheese, chopped celery and chopped green onions', 'In a 4- or 5-qt. slow cooker, combine the first 7 ingredients. Add chicken. Cover and cook on low 5-6 hours or until chicken is tender.\r\nRemove chicken; shred with 2 forks. Return to slow cooker. Stir in cream cheese. start with half a block.  Cover and cook on low until cheese is melted, about 30 minutes. Stir until blended. Serve with toppings as desired.\r\n', 'I think you could definitely add some chopped carrots and celery to beef up the veggie quota', 21),
(217, 'Fancy salad - Grilled peaches with Burrata', 'Peaches - 2 halved and stoned or 1 can of unsweetened halved peaches\r\nolive oil\r\nMixed greens (light) 1 healthy handful per person\r\nProsciutto - 2 slices per person torn a bit\r\nBurrata cheese - 1 or 11/2 balls\r\nShelled pistachios - cracked a bit\r\n\r\nDressing:\r\n6 tbsp olive oil\r\n4 tsp white balsamic vinegar or rice wine vinegar\r\n2 tsp runny honey\r\n1/8 tsp red chili paste (to taste, bit less)\r\n1/2 garlic clove - left whole as you remove it\r\n', 'To make the dressing:  whisk together oil, vinegar and honey.  Then stir in the chili paste and whole garlic clove. Let sit while you arrange the salad.\r\n\r\nHeat frying pan on high.  Lightly oil 2 sides of the peaches and grill until charred and caramelized on surface.\r\n\r\nScatter greens on a larger platter.  Drape the prosciutto over the greens. Add the peaches then place the burrata in the centre.  Or tear apart and scatter as well.  Your choice.\r\n\r\nRemove the garlic clove then spoon dressing over.  Probably have more than you need, can leave on the table for personal preference.  Scatter the nuts on top.  ', 'Serves 4.  Recipe from Gail Desjardins.  Looks very pretty when served on a platter.  ', 17),
(218, 'Healthy Chicken Tai Curry with Veg noodles', '1 1/2 pounds boneless, skinless chicken breasts (about 2 large)\r\n\r\n1 tablespoon extra-virgin olive oil\r\n\r\nKosher salt and freshly ground black pepper\r\n\r\n1/2 cup coconut milk\r\n\r\nJuice of 2 limes, plus lime wedges for serving\r\n\r\n2 tablespoons almond butter\r\n\r\n2 teaspoons red curry paste (see Cook\'s Note)\r\n\r\n1 large carrot, spiralized or just shredded\r\n\r\n1/2 small head red cabbage, sliced thin\r\n\r\n1 large English cucumber, spiralized\r\n\r\n2 scallions, thinly sliced \r\n\r\nChopped roasted, salted cashews, for serving\r\n', 'Preheat the broiler and line a baking sheet with foil. Drizzle the chicken with the olive oil and sprinkle with some salt and pepper. Transfer to the prepared baking sheet and broil, flipping halfway, until cooked through, about 10 minutes.\r\nMeanwhile, whisk together the coconut milk, lime juice, almond butter and curry paste in a large bowl. Add the carrots, cabbage and 1 teaspoon salt and toss to coat completely. Let sit for 15 minutes. Add the cucumber to the bowl and toss to combine.  \r\nThinly slice the chicken. Divide the veggies among 4 bowls and top with the chicken, scallions and some cashews. Serve with lime wedges.', 'Important: I double the sauce recipe. I bake the chicken, not broil.  I also season the chicken with perhaps some extra Thai sauce before baking.', 10),
(219, 'Betty\'s Famous Cinnamon Rolls - untried as of Dec.2022', '1 cup warm water\r\n4 1/2 tsp active dry yeast\r\n2 1/2 cups plus 1 tsp white sugar\r\n1 cup warm milk\r\n2 1/3 cups butter, melted\r\n2 eggs\r\n2 tsp salt\r\n8 cups flour\r\n3 tbsp cinnamon\r\n4 cups powdered sugar\r\n2 tsp vanilla extract\r\n1 tsp maple extract (optional)\r\n3 to 4 tsp milk.', '1.  pur warm water into a bowl. stir in yeast and 1 tsp white sugar.  Allow to stand until it forms a foam layer on top.  Approx 10 minutes.\r\n2.  Put warm milk, 2/3 cup white sugar, 2/3 cup melted butter, eggs, salt and yeast mixture into a mixing bowl.  Mix with electric mixer until all ingredients ae incorporated.  Add 4 cups flour and ix at medium speed until dough forms, about 5 minutes.  Beat remaining 4 cups of flour into dough until just combined.  Transfer to a lightly floured surface.  Kneed with hands until dough is slightly stiff and sticky.  5 minutes.\r\n3.  Transfer dough to a large great bowl.  Coverwith plastic wrap and let it rise in a warm place until doubled.  1.5 hours.\r\n4.  Remove plastic wrap and punch down the dough.  Transfer dough to a well floured surface.  Cut dough I half.  Let rest, covered, 5 minutes.\r\n5.  Meanwhile, for filling stir together 1 1/2 cups of white sugar and cinnamon in a bowl.\r\n6.  Roll each dough portion into a 12 x 15 inch rectangle.  brush with 1/2 cup melted butter.  Sprinkle each portion evenly with filling, leaving a 1 inch border on one long edge.  Starting with long edge, rightly roll up each dough portion and pinch edge to seal.  using unwaxed dental floss, cut each log into 12 slices.\r\n7.  Great a 13x18 inch baking sheet with 1/2 cup of melted butter and sprinkle with 1/3 cup of white sugar.\r\n8.  Arrange cinnamon rolls with a little space between them. Let rise in a warm place for 45 minutes.  Preheat oven to 350.\r\n9.  Bake until golden brown.  25 t0 30 minutes.\r\n10.  Beat together powdered sugar, 2/3 cup melted butter, vanilla and maple extracts.  Add enough milk, 1 tsp at a time to make a smooth icing.  Spread over warm rolls.', 'An Allrecipe version.  Curious about the no brown sugar.', 7),
(220, 'Creamy Tuscan Chicken...  good to serve guests', '½ cup all-purpose flour\r\n2 teaspoons kosher salt plus more to taste\r\n1 teaspoon ground pepper plus more to taste\r\n1 ½ pounds thin-sliced boneless skinless chicken breasts about ½ inch thick\r\n2 tablespoons olive oil\r\n1 tablespoon finely minced garlic\r\n1 cup less-sodium chicken broth\r\n¾ cup heavy cream\r\n2 tablespoons chopped fresh basil or 2 teaspoons dried\r\n1 tablespoon chopped fresh oregano or 1 teaspoon dried\r\n½ cup finely grated Parmesan cheese plus more to serve\r\n2 cups chopped fresh spinach\r\n1 pint cherry or grape tomatoes halved or quartered if large\r\n1 cup chopped marinated artichokes\r\n½ pound orzo or cooked hot pasta optional\r\n¼ cup chopped fresh parsley', 'Combine the flour, salt and pepper in a shallow bowl.\r\nHeat the olive oil in a very large skillet over medium high heat. Dredge the chicken cutlets in the flour mixture and once the oil is hot, cook the cutlets in the pan for about 2 minutes on each side until they are golden brown, and almost but not quite cooked through (a bit pink in the center). Transfer the cutlets to a large plate as they are cooked.\r\nTurn the heat down to medium and add the garlic. Stir for just one minute until you can smell the garlic. Add the chicken broth and stir so that any browned bit stuck to the bottom of the pan are released into the liquid. Stir in the cream, basil, oregano and gradually add the Parmesan, sprinkling it slowly as you stir. Bring to a simmer and cook, stirring frequently, until the sauce thickens, about 4 minutes.\r\nStir in the spinach and tomatoes, and simmer for another 2 minutes or so, until the spinach is wilted and everything is well combined. Tuck the chicken back in the pan, with any juices that may have collected, making sure it is at least mostly covered by the sauce. Cook for 2 more minutes until the chicken is hot and cooked through.\r\nEither serve the chicken over the hot pasta, or transfer it to a serving dish. Sprinkle with the parsley, and serve hot with extra Parmesan passed on the side.', 'I always double the spinach and up the amount of tomatoes.  I have served with mixed grain rice as well as orzo....  think I prefer orzo. \r\n\r\nThere is a ton of veggies in there, but could serve parmesan crusted broccoli or perhaps asparagus on the side.  Or a small salad.  ', 10),
(221, '20 Minute Garlic Butter Cashew Chicken from Half Baked Harvest', '1/2 cup hoisin sauce\r\n1/4 cup tamari or soy sauce\r\n1-2 tablespoons real maple syrup\r\n 2 tablespoons apple cider vinegar\r\n1 tablespoon sriracha\r\nblack pepper and chili flakes**\r\n\r\nCASHEW CHICKEN\r\n\r\n3 tablespoons sesame oil (or olive oil)\r\n1 1/2 pounds ground chicken\r\n1 tablespoon cornstarch (or 2 tbsp flour)\r\n1 teaspoon paprika\r\n1 1/2 cups broccoli - steamed\r\n3 tablespoons salted butter\r\n3-4 cloves garlic, chopped\r\n1 tablespoon chopped fresh ginger\r\n1 cup cashews\r\n1/3 cup pickled ginger**\r\n4 green onions, chopped\r\n', 'Instructions\r\n\r\n1. To make the sauce. Combine all ingredients in a glass jar.\r\n2. In a large skillet, combine the oil, chicken, cornstarch, paprika, and black pepper. Cook over medium heat, breaking up the meat as it cooks until browned, about 5 minutes. Add the butter, garlic, ginger, and cashews. Cook 2 minutes, until the butter browns and the chicken gets crispy.\r\n3. Pour over 2/3 of the sauce. Cook until the sauce thickens slightly. Then, add the broccoli and pickled ginger. Cook another 2-5 minutes. Remove from the heat.\r\n4. Serve the chicken, broccoli, and remaining sauce over bowls of rice. Top with sesame seeds and green onion. Enjoy!', 'Fast and easy. ** I did not add any chili flakes and found it spicy enough with the sriracha alone.  **I also did not have any picked ginger and it was still delish.  \r\n\r\nI only had 1 pound of chicken.  Could easily add more broccoli or more vegetables in general.\r\n\r\n**. 2nd time I made it and I think in the future, I will try chicken thighs.  Not sure I love the same texture of ground c with rice.', 10),
(222, 'Easy Cheesy Chicken Enchilada Bake', '4 boneless, skinless chicken breasts\r\nchicken broth\r\ngarlic powder\r\nonion powder\r\nAnd any other Mexican flavouring spices you like (I like chipotle seasoning)\r\n\r\n1 red pepper\r\n1 medium onion\r\nbunch of sliced mushrooms (good double handful)\r\nolive oil\r\nsalt and pepper\r\n\r\n1 regular container of sour cream\r\n1 tin of pickled chilies\r\n\r\n16 ounces of preferred cheese, shredded (cheddar, mixed, Monterey)\r\nAny extra bit of cheese you want to use up from the cheese drawer\r\n\r\n\r\n2 - 16 ounce jars of green enchilada sauce\r\n6 large tortilla wraps\r\n', 'Preheat oven to 350\r\n\r\nPlace chicken breasts in a pot with chicken broth and spices.  Poach until cooked and easily shredded.  Remove from fluid and shred.\r\n\r\nSlice all vegetables into bite sized pieces and sauté in a frying pan until tender.  Sprinkle with salt and pepper while cooking.\r\n\r\nPut the shredded chicken into a large bowl with the sour cream and tin of pickled chilies.  Mix to combine.\r\n\r\nPut half a cup of the enchilada sauce into the bottom of a 9 x 13 inch baking pan.\r\n\r\nRip the tortilla wraps into 6 or 8 pieces each.  Put into a bowl with the enchilada sauce.  Mix and dredge enough pieces of tortillas to cover the bottom of the pan in a single layer.   Sprinkle a bit of the sauce over the tortillas if you did not dredge the sauce well on to the wrap pieces.\r\n\r\nCover the tortillas with half of the chicken  and sour cream combo.  Spread half of the vegetables on top of that and top with 1/3 of the cheese.\r\n\r\nDrege another layer of the tortilla wraps and lay them across the layer of chicken/vegetables.  Repeat the chicken then vegetable layers.  Cover with 1/3 of the shredded cheese.\r\n\r\nLay the 3rd layer of soaked tortilla pieces on top of all that.  Sprinkle any remaining enchillada sauce over that.  Then layer on the final 1/3 of the shredded Cheese.  \r\n\r\nCover with foil and bake for 45 minutes.  Take off the foil when it is hot throughout and let the top cheese layer brown a bit before removing from the oven.  Let rest 5 minutes to settle and serve.\r\n\r\n\r\n\r\n', 'Serve with additional sour cream and salsa, or more enchilada sauce on the side.\r\n\r\nYou can always add more spice by increasing the chilies or even diced jalepanos if you like.  ', 10),
(223, 'Proven delicous root veg gratin casserole - from Ina Garten', '\r\nGood olive oil\r\n\r\n1 1/2 cups sliced yellow onion (1 large)\r\n\r\n1 tablespoon minced garlic (3 cloves)\r\n\r\n1 pound sweet potatoes, peeled and sliced 1/4 inch thick\r\n\r\n1 pound celery root, peeled and sliced 1/4 inch thick\r\n\r\n1 pound Yukon Gold potatoes, peeled and sliced 1/4 inch thick\r\n\r\n2 1/2 cups heavy cream\r\ntap here\r\n\r\n1/2 cup chicken stock, preferably homemade\r\n\r\n2 cups grated Gruyere cheese (6 ounces with rind)\r\n\r\n2 teaspoons minced fresh thyme leaves\r\n\r\nKosher salt and freshly ground black pepper\r\n\r\n2 1/2 cups coarse fresh bread crumbs, crusts removed**. optional', 'Preheat the oven to 350 degrees F. Butter a 13-by-10-by-2 1/2-inch baking dish.\r\nHeat 2 tablespoons of olive oil in a large (12-inch) saute pan over medium heat, add the onion and cook for 10 minutes, tossing occasionally, until lightly browned and tender. Add the garlic and cook for one minute.\r\nMix veggies and layer half of them into the dish.  Sprinkle with salt and pepper and fresh or dried thyme.  Then the cooked onions.   Then the grated cheese.  \r\nRepeat with the final cheese on top.  Breadcrumbs are optional.  I did not put them on.  \r\n\r\nThen combine the cream/heavy milk and chicken stock and pour over top.  Press veggies down.  \r\n\r\nCombine the bread crumbs and 2 tablespoons of olive oil and distribute evenly on top. Bake uncovered for 1 1/2 hours, until the vegetables are very tender when tested with a small knife and the top is browned and bubbly. Allow to set for 15 minutes and serve hot.\r\nMake ahead: Bake in advance and reheat while the turkey rests, or assemble the dish, cover and refrigerate for up to 24 hours, then bake before serving.', 'This is so good!!  if there is extra creamy sauce still in the dish when the veggies are done, that cheesy goodness is wonderful spooned over chicken or any meat being served.  yum.', 8),
(224, 'Spinach Crescent Roll puffs', '1 package 10 ounces chopped spinach, thawed and drained with the moisture squeezed out.\r\n1/2 cup mozzarella cheese\r\n\r\n1/4 cup Parmesan cheese\r\n1/2 cup softened cream cheese\r\n1/2 teaspoon onion powder\r\n1/2 teaspoon garlic powder\r\n1 egg separated, egg white beaten\r\n1 can KRAFT refrigerated crescent rolls', 'Preheat oven to 350 degrees. Line a baking sheet with parchment paper.\r\nMix the first 6 ingredients together with the egg yolk in a medium-sized mixing bowl until well blended together.spinach filling\r\nUnroll crescent dough and cut each triangle in half making 2 triangles. In the middle of each one place 1 tablespoon of the spinach mixture. Fold up the corners of the crescent dough around the spinach mixture making a little \"package\" and pinch to seal it. Place on baking sheet. When you have finished making all of your little packages, brush each one with the egg white.\r\nBake for 12-15 minutes or until lightly golden brown on top.', 'I served at USA thanksgiving at the Tods 2023.  Was asked for the recipe.', 9),
(225, 'Cucumber, Avocado, Shrimp bites', 'Servings: 22 shrimp appetizers\r\nIngredients for Cajun Shrimp:\r\n\r\n\r\n1 lb large shrimp, peeled and deveined\r\n2 garlic cloves, finely minced\r\n1 Tbsp cilantro, finely chopped, plus more to garnish\r\n1 tsp paprika\r\n1/2 tsp cayenne pepper\r\n1/2 tsp sea salt\r\n1/4 tsp black pepper\r\n2 Tbsp olive oil, divided\r\n\r\n\r\n\r\nFor the Avocado Spread:\r\n\r\n1 avocado\r\n1/4 tsp salt\r\n1 Tbsp lime juice, plus more to squeeze over finished appetizers\r\n1 English Cucumber, sliced into 22 rings\r\n', 'How to Make Cajun Shrimp:\r\n\r\nPlace shrimp in a large mixing bowl and pat dry with paper towels. Add minced garlic, 1 Tbsp cilantro, 1 tsp paprika, 1/2 tsp cayenne pepper, 1/2 tsp salt, 1/4 tsp black pepper and 1 Tbsp olive oil. Stir well to combine.\r\n\r\nHeat a large heavy pan over medium/high heat with 1 Tbsp olive oil. Once oil is hot, add shrimp in a single layer ( add one by one as too many as once will lower the pan temp too quickly for the sear effect) and sauté 2 min per side or until cooked through.\r\n\r\n\r\nHow to Make Avocado Spread & Assemble:\r\n\r\nIn a small bowl, mash together 1 avocado, 1/4 tsp salt and 1 Tbsp lime juice until creamy. Divide the avocado mix over 20-22 cucumber slices.\r\nSqueeze fresh lime juice over the shrimp avocado bites and garnish with more finely chopped cilantro. If not serving right away, cover and refrigerate up to 4 hours before serving.\r\n', 'https://natashaskitchen.com/avocado-cucumber-shrimp-appetizers/', 9),
(226, 'Attractive mixed vegetable dish for company- corn and green beans', '1/2 cup sliced almonds\r\n2 tbsp olive oil\r\n2 mined garlic cloves\r\n1 1/2 pounds green beans\r\n5 sprigs thyme\r\nsalt and pepper\r\n3 tbsp unsalted butter\r\n2 cups corn kernels\r\n', 'Heat oven to 350 degrees.  spread almonds on a baking sheet and bake until golden 6 to 7 minutes.\r\nMeanwhile, in a large deep skillet, heat oil over medium heat.  add garlic and stir until fragrant....30 seconds.  Add green beans and thyme, season with salt and pepper. and toss to safely coat in the oil.  \r\nAdd 1/2 cup of water.  Cover and stem  for 5 minutes until beans are tender.  Stir in butter and corn.  Cook, stirring occasionally until all are tender and glazed.  Discard the thyme and season with salt and pepper.\r\nTransfer to a large platter and spoon any remaining sauce over.  Garnish with almonds and more pepper.', 'Mary Tod made and it looked fancy and tasted delish.\r\n\r\nserves 6 to 8', 8),
(227, 'Creamy Spinach and Artichoke Salmon - from Halfbaked Harvest', '4 salmon filets, skin on or off (your preference)\r\n&#9634; kosher salt and black pepper\r\n&#9634; 1/2 teaspoon paprika\r\n&#9634; 1 tablespoon extra virgin olive oil\r\n&#9634; 3 tablespoons salted butter\r\n&#9634; 2 small shallots, sliced or smashed\r\n&#9634; 3 cloves garlic, smashed\r\n&#9634; 2 tablespoons chopped fresh sage\r\n&#9634; 1/2 teaspoon crushed red pepper flakes\r\n&#9634; 1 1/4 cups canned full-fat coconut milk or heavy cream\r\n&#9634; 2 ounces cream cheese, cubed\r\n&#9634; 1/2 cup grated parmesan or manchego cheese\r\n&#9634; 4 cups fresh baby spinach\r\n&#9634; 1 (12 ounce) jar marinated artichokes roughly chopped\r\n&#9634; juice from 1/2 a lemon\r\n&#9634; flaky sea salt for sprinkling', '1. Preheat the oven to 350 degrees. Rub the salmon with paprika, salt, and pepper.\r\n\r\n2. Optional: If you have salmon with skin on***** sear the salmon before baking. Heat the olive oil in a large skillet over  high heat. When the oil shimmers, add the salmon and cook for 2-3 minutes, until the salmon is seared on 1 side. Remove from the skillet. If using skin-on salmon, sear the skin side.\r\n\r\n3. To the same (oven-safe) skillet, add the butter, shallots, and garlic. Cook until the garlic is fragrant, 2 minutes. Add the sage and continue cooking another 2-3 minutes, until the butter is browned and the garlic golden and caramelized. Add the crushed red pepper flakes, coconut milk, and cream cheese. Season the sauce with salt and pepper. Bring to a simmer over medium heat, stirring constantly until smooth and creamy. Add the parmesan, spinach, and artichokes, and cook until the spinach is wilted, 3-5 minutes. Stir in the lemon juice. Remove from the heat. If desired, remove the smashed garlic.\r\n\r\n4. Slide the salmon into the sauce. Transfer to the oven and bake 10-15 minutes or until salmon is cooked through.\r\n\r\n5. To serve, plate each piece of salmon, then spoon the sauce over top. Serve with flaky sea salt.\r\nNotes\r\n\r\nTo Prepare Ahead of Time: Skip step 2 completely and do not sear the salmon. Then complete the recipe through step 3. Let the sauce cool, then slide the salmon into the sauce. Chill for up to 1 day ahead of time. When ready to bake, remove the dish from the fridge 30 minutes prior to baking, then bake as directed. ', '***. I prefer if the salmon does not have skin.  Hard to find that.  So, buy a large fillet of salmon.  Place it skin side up over a large cooling rack.  Place that over kitchen sink.  Pour boiling water over the skin, the skin will shrink and soften.  Peel off.  much easier than trying to cut it off.\r\n\r\nI made this for Shauna\'s freezer when Rhodes was born.  Delish!!\r\n\r\nI added a fair bit more spinach than the recipe and it just dissolved into the sauce.\r\n\r\nExtra sauce is nice too.  Bottom line...  I like extra sauce, so I just keep adding and tasting.  Extra artichokes, spinach, etc.  Taste and re-taste.', 14),
(228, 'Chocolate Lava cake for 4 people', '5 tablespoons unsalted butter, plus more, softened, for greasing ramekins\r\n2 tablespoons granulated sugar\r\n¼ cup heavy cream\r\n1 ¼ cups dark chocolate chip, divided\r\n2 large eggs\r\n2 large egg yolks\r\n&#8531; cup light brown sugar\r\n½ teaspoon kosher salt\r\n1 teaspoon vanilla extract\r\n2 tablespoons all purpose flour\r\n1 cup whipped cream, for serving\r\n1 cup fresh berries, for serving', 'Coat the inside of 4 1-cup (125 G) ramekins with softened butter, then sprinkle with the granulated sugar, tilting to coat completely. Set aside on a rimmed baking sheet.\r\nHeat the heavy cream in a small pot until boiling.\r\nPour the boiling cream over ½ cup (120 ml) dark chocolate in a small bowl and let sit for 3 minutes. Stir until the chocolate is melted and smooth. Refrigerate for at least 30 minutes, or store in the freezer for up to 3 months.\r\nPreheat the oven to 425°F (220°C).\r\nIn a small microwave-safe bowl, combine the remaining ¾ cup (170 G) chocolate and the butter. Microwave in 30-second intervals, stirring between, until completely melted.\r\nIn a medium bowl, beat the eggs, egg yolks, brown sugar, salt, and vanilla with an electric hand mixer on medium-high speed until light and frothy, about 8 minutes.\r\nGently fold the chocolate mixture into the egg mixture, being careful not to deflate the eggs. Add the flour and fold to incorporate.\r\nDivide half of the batter between the prepared ramekins. Add ½ tablespoon of the chilled ganache to the center of each ramekin, then scoop the remaining batter on top.\r\nBake for 12 minutes, until the tops are set and the cakes begin to pull away from the sides of the ramekins.\r\nLet the lava cakes cool slightly, then invert onto plates. Dust with powdered sugar and garnish with berries. Serve immediately.\r\n', 'You can also coat the ramekins with sifted cocoa.\r\nYou can make ahead and put the first part in the fridge to stay cool.  Make the rest and leave on the counter until ready to assemble once dinner has been eaten.\r\nThe cakes should sit for 4 or 5 minutes before trying to remove them, otherwise they will fall apart.\r\n\r\nTaste delish, just need to be careful getting them out of the ramekin.\r\n', 3),
(229, 'Cheese stuffed tenderloin - made and it is good!', '2 green onions, chopped\r\n\r\n2 slices cooked bacon, crumbled\r\n\r\n3 tablespoons shredded Cheddar cheese\r\n\r\n2 tablespoons cream cheese, softened\r\n\r\n2 tablespoons frozen chopped spinach\r\n\r\n2 tablespoons finely chopped white mushrooms\r\n\r\n¼ teaspoon chopped garlic\r\n\r\n1 pinch dried parsley\r\n\r\nsalt and ground black pepper to taste\r\n\r\n1 pork tenderloin, butterflied and pounded flat\r\n\r\n1 cup dry bread crumbs', 'Preheat oven to 350 degrees F (175 degrees C). Grease a baking sheet.\r\n\r\nMix green onions, bacon, Cheddar cheese, cream cheese, spinach, mushrooms, garlic, parsley, salt, and pepper in a bowl. Spread onto one side of pounded tenderloin. Roll tenderloin around the filling in a jelly-roll fashion. Coat rolled tenderloin with bread crumbs; place on the prepared baking sheet.\r\n\r\nBake in the preheated oven until pork is no longer pink in the center, about 1 1/2 hours. An instant-read thermometer inserted into the center should read at least 145 degrees F (63 degrees C).', 'I did not coat in breadcrumbs.  Not needed\r\nI had to use thread to hold the rolls together, a bother, but worth the effort.  Looks great for company.  I served with a small pitcher of light gravy.', 12),
(230, 'Taco Soup - Pioneer Woman', '\r\n1 1/2 lb. ground beef\r\n1 yellow onion, chopped\r\n3 cloves garlic, minced\r\n1 jalapeño, chopped\r\n2 (14.5-oz.) cans fire roasted tomatoes \r\n1 (1-oz.) packet taco seasoning \r\n1 (4-oz.) can green chiles\r\n1 qt. chicken broth\r\n1 (15-oz.) can pinto beans, drained and rinsed\r\n1 (15-oz.) can black beans, drained and rinsed\r\n1 (15-oz.) can of corn, drained\r\nKosher salt, to taste\r\nSour cream, for serving\r\nCilantro, for serving\r\nGrated cheddar cheese, for serving\r\nAvocado, for serving', 'Heat a large Dutch oven over medium heat. Add the beef and onion and cook, stirring to break the beef into small pieces, until it is no longer pink and the onion is softened, 6 to 8 minutes. \r\n2\r\nStir in the garlic and jalapeño, if using, and cook, stirring, for two minutes. \r\n3\r\nStir in the tomatoes, taco seasoning, green chiles, chicken broth, corn, pinto beans, and black beans. Bring to a boil over medium-high heat. Reduce the heat to medium-low, partially cover and cook, stirring occasionally, until the flavors meld, about 20 minutes. Season with salt to taste. \r\n4\r\nServe, topped with sour cream, chopped cilantro leaves, cheddar cheese, and avocado, if you like. ', 'This is really good.', 5),
(231, 'Chickpea, Sausage and Kale Pasta  4 servings - M Stewart', '½ pound short pasta\r\n\r\n¾ pound Italian sausage meat\r\n\r\n1 tablespoon olive oil, plus more for drizzling\r\n\r\n2 tablespoons minced garlic\r\n\r\n1 can (15.5 ounces) rinsed and drained chickpeas\r\n\r\n5 cups ribbed and shredded kale\r\n\r\n½ cup grated Parmesan\r\n\r\nSalt and pepper\r\n\r\nLemon juice, for drizzling', 'Cook pasta, then drain. In a skillet, cook sausage meat in 1 tablespoon olive oil until opaque, breaking up with a spoon. Add garlic and cook 30 seconds. Add chickpeas and cook 3 minutes. Add kale and wilt. Add pasta and Parmesan; season. Drizzle with olive oil and lemon juice.\r\n', 'Could add extra cheese of whatever odds and ends are hanging in the drawer.  Extra Kale is always good as well.', 11),
(232, 'Crab Louis Salad - from Eating Well Magazine', 'Dressing\r\n\r\n½ cup ketchup\r\n\r\n½ cup mayonnaise\r\n\r\n¼ cup minced yellow onion\r\n\r\n1 clove garlic, minced\r\n\r\n1 tablespoon dill pickle relish (has to be dill)\r\n\r\n2 teaspoons dried dill *\r\n\r\n1 teaspoon prepared horseradish**\r\n\r\n1 teaspoon lemon juice\r\n\r\n\r\n\r\n\r\nSalad\r\n\r\n8 asparagus spears, trimmed ***\r\n\r\n1 medium head green-leaf lettuce, torn\r\n\r\n2 medium tomatoes, cut into wedges\r\n\r\n2 hard-boiled eggs, quartered\r\n\r\n2 stalks celery, sliced\r\n\r\n1 ripe avocado, sliced\r\n\r\n½ medium cucumber, sliced\r\n\r\n2 scallions, sliced\r\n\r\n½ cup sliced canned pitted black olives, rinsed\r\n\r\n¼ cup sliced red onion\r\n\r\n6 ounces cooked crabmeat ****\r\n\r\nLemon wedges for serving', 'To prepare dressing: Whisk ketchup, mayonnaise, yellow onion, garlic, relish, dill, horseradish and lemon juice in a medium bowl.\r\n\r\nTo prepare salad: Bring 1 inch of water to a boil in a large pot fitted with a steamer basket. Place a bowl of ice water near the stove. Add asparagus to the pot, cover and steam until tender-crisp, 3 to 5 minutes. Transfer to the ice bath. Drain and pat dry.\r\n\r\nPlace lettuce on a serving platter. Arrange the asparagus, tomatoes, eggs, celery, avocado, cucumber, scallions, olives and red onion on top. Top with crabmeat and dollop with half the dressing (reserve the remaining dressing for another use). Serve with lemon wedges, if desired.\r\n', 'Serves 4\r\n* Not necessary, can just add more dill relish\r\n** I prefer creamed horseradish, just add a touch less mayonnaise\r\n*** I tend to roast the asparagus first - or use jarred if I have some\r\n**** I have used shrimp as well as fake crab (pollock) as well as salmon cakes\r\n', 17),
(233, 'Randi\'s Shrimp Scampi...  good over rice or cauliflower rice 2 servings', 'half an onion chiopped\r\n2 tbsp butter\r\n4 - 6 cloves garlic\r\n1/2 bottle white wine for 2 people\r\nred pepper flakes...  per taste\r\n4-6 tbsp cream cheese\r\nJuice from 1 lemon\r\n1 tbsp brown sugar\r\n', 'Fry, in butter, the onion.  Addd the garlic and red pepper, but do not brown.  Add the wine and let boil down till1/2.  Add the cream cheese and melt into the sauce.  Add lemon juice and brown sugar.  \r\nTaste, for salt and pepper etc.  then add the shrimp.  Cook for a few minutes.  ', 'Just keep tasting as you go.', 14),
(234, 'Egg Bites - great for gatherings/buffets', '1 egg per person in attendance - 12 eggs will give you 12 muffin sized egg bites.  Most people will eat 2 egg bites.\r\n1 tbsp milk per egg used\r\nsalt and pepper to taste\r\n\r\nOptions:\r\nbaby spinach\r\nfeta cheese\r\n\r\ncheddar cheese shredded\r\nham thinly sliced and chopped\r\n\r\nor any other ingredients you like in scrambled eggs\r\n\r\n', 'Heat oven to 350.  Place rack in the middle of the oven.\r\n\r\nTake out a muffin tin.  Grease if it is not stick proof.\r\n\r\nScramble the eggs in a large bowl, add milk and salt and \r\npepper to taste.\r\n\r\nInto each muffin cup, scatter bits of whatever filling you want to use.  approx. 1 tablespoon per item. Ie, 1 tbsp feta and 1 tbsp spinach per egg.  Or 1 tbsp shredded cheddar and 1 tbsp chopped ham\r\n\r\nPour the scrambled eggs over the optional ingredients.  Put into the oven for 15 minutes until the eggs do not jiggle.  Note, with spinach the surface may seem wet, but 15 minutes should have cooked the eggs', 'This is so easy and great to put out on a buffet \r\n\r\nhttps://tasty.co/recipe/spinach-and-feta-baked-egg-cups\r\n', 6),
(235, 'Ina Garten Mushroom Soup', '30 g / 2 tbsp unsalted butter\r\n1 medium yellow onion, chopped\r\n2 garlic cloves, minced\r\n400 g / 14 oz white mushrooms, chopped\r\n200 g / 7 oz Swiss Brown/Cremini mushrooms, chopped. ***\r\n3 ¼ cups vegetable stock or chicken stock\r\n¼ tsp kosher salt\r\n&#8539; tsp black pepper\r\n¾ cup crème fraiche or full-fat cream ******', 'Chop Mushrooms: Cut mushrooms into quarters, then dice into smaller pieces.\r\n\r\nCook Onion and Garlic: In a large pot over medium-high heat, melt the butter. Add the garlic and onion. Cook for about 3 minutes until soft but not browned.\r\n\r\nCook the Mushrooms: Add the mushrooms and stir occasionally for about 10 minutes. The pot will be crowded, so the mushrooms won’t brown much, but that’s okay.\r\n\r\nSimmer for 15 Minutes: Add the salt and pepper. Bring to a boil, then reduce the heat to medium and simmer uncovered for 15 minutes.\r\n\r\nAdd Cream: Stir in the cream (or crème fraiche) and let it cook for another 5 minutes.\r\n\r\nBlend the Soup: . Blend until smooth with handheld.\r\n\r\nFinal Simmer: Return the blended soup to the pot and simmer for 1-2 minutes until most bubbles are gone and the soup is hot.\r\n\r\nServe: Pour the soup into bowls. Drizzle with extra virgin olive oil or cream, top with croutons and parsley or chervil. Serve with bread for dunking.\r\nNotes\r\n\r\n\r\n\r\n\r\n\r\n', '***. I just use whatever mushrooms are on sale.\r\n****** I just use low fat coconut milk for less fat.  Still delish.\r\n\r\nhttps://inagarteneats.com/barefoot-contessa-mushroom-soup/\r\n\r\n', 5),
(236, 'Moussaka from Pioneer Woman - makes 9 x 12\" pan', '2 large eggplant (about 2 1/2 pounds total), sliced 1/2-inch thick\r\n1 Tbsp. kosher salt, divided\r\n1/4 cup olive oil, divided\r\n1 tsp. ground black pepper, divided\r\n4 medium yukon gold potatoes, peeled and sliced 1/4-inch thick\r\nFOR THE BECHAMEL:\r\n1/2 cup unsalted butter\r\n2 cloves garlic, grated\r\n2/3 cup all-purpose flour\r\n2 tsp. kosher salt\r\n1/4 tsp. ground nutmeg\r\n5 cups warm whole milk\r\n1 1/2 cups grated pecorino romano cheese, divided\r\n2 large egg yolks, room temperature\r\nFOR THE MEAT SAUCE:\r\n2 Tbsp. olive oil\r\n1 large yellow onion, chopped\r\n3 cloves garlic, finely chopped\r\n1 Tbsp. tomato paste\r\n2 lb. lean ground beef (90/10)\r\n1/2 cup red wine\r\n1 28-ounce can crushed tomatoes\r\n1 1/2 tsp. kosher salt\r\n2 tsp. chopped fresh oregano, plus more to serve\r\n1 bay leaf\r\n1/4 tsp. ground nutmeg\r\n1/4 tsp. ground cinnamon\r\n1/4 tsp. crushed red pepper flakes\r\n1/4 tsp. ground black pepper\r\nCooking Spray', '1. START THE BECHMEL SAUCE FIRST AS IT HAS TO COOL\r\n\r\nFor the eggplant and potato layers: Heat the oven to 425ºF. Place one rack in the upper third of the oven and a second rack in the lower third of the oven.\r\n2\r\nPlace the eggplant slices on two baking sheets and sprinkle with 2 teaspoons of kosher salt. Allow to sit for 30 minutes.\r\n3\r\nPat the eggplant dry. Brush both sides with 3 tablespoons of olive oil and sprinkle with ½ teaspoon of pepper. On another baking sheet, arrange the potato slices. Brush both sides with the remaining 1 tablespoon of oil and sprinkle with the remaining 1 teaspoon salt and ½ teaspoon of pepper.\r\n4\r\nArrange the baking sheets of eggplant on the upper third of the oven and the baking sheet of potatoes on the lower third. Bake until the eggplant and potatoes are golden brown and soft, 20 to 22 minutes, turning the pans halfway through baking. Reduce the oven to 375°F.\r\n5\r\nFor the bechamel: In a medium saucepan, melt the butter over medium heat. Stir in the garlic and cook until fragrant, about 30 seconds. Whisk in the flour, salt, and nutmeg until smooth; cook, whisking frequently, for 3 to 4 minutes. Gradually whisk in the warm milk until smooth; bring to a boil, whisking frequently. Reduce the heat, and simmer, whisking frequently, until the sauce is the texture of a thin pudding, 15 to 20 minutes.\r\n6\r\nRemove from the heat, and whisk in 1 cup of cheese until smooth. Let the sauce cool, whisking occasionally, for 10 minutes. Gradually whisk in the egg yolks until well combined. Cover until ready to use.\r\n7\r\nFor the meat sauce: In a large Dutch oven, heat the oil over medium-high heat. Add the onion and cook, stirring frequently, until it is just soft, 3 to 5 minutes. Stir in the garlic and tomato paste; cook, stirring frequently, until the tomato paste is browned, 1 to 2 minutes. Add the beef and cook, stirring frequently to break up the beef until it is browned, about 5 minutes. Stir in the wine and cook until it is reduced by half, 3 to 4 minutes. Stir in the tomatoes, salt, oregano, bay leaf, nutmeg, cinnamon, red pepper flakes, and black pepper. Reduce the heat to medium; simmer, stirring occasionally, for 15 minutes. Remove from the heat.\r\n8\r\nSpray a 13-by-9-inch baking pan with cooking spray. Place the pan on a foil-lined baking sheet. Spread ½ cup of the bechamel into the bottom of the prepared pan. Add the potatoes in a single layer, overlapping slightly as necessary to fill the space. Arrange half of the eggplant in a single layer on top of the potatoes, overlapping as necessary. Spread the meat sauce over the eggplant. Top with the remaining eggplant. Spread the bechamel onto the second layer of eggplant. Sprinkle the top with the remaining ½ cup of cheese.\r\n9\r\nBake until the top is lightly browned, 45 to 55 minutes. Let stand for 15 minutes before serving. Top with a sprinkle of oregano.\r\nTip: The meat sauce can be made and the vegetables can be roasted up to 2 days in advance for a quicker assembly. Save the bechamel for the day of to ensure it is smooth and spreadable.', 'This takes a fair bit of time to make, but it is well worth it. I love the nutmeg and cinnamon in the meat sauce!!\r\n\r\nAlso, it is easy to cut in half and make in an 8 X 8 pan.', 12),
(237, 'Classic creamed spinach from Taste of Home', '3/4 pound fresh spinach, torn\r\n2 tablespoons olive oil\r\n6 tablespoons butter, cubed\r\n1/4 cup chopped onion\r\n1/4 cup all-purpose flour\r\n1/2 teaspoon salt\r\n1/8 teaspoon ground nutmeg\r\n1-1/2 cups whole milk\r\n', 'In a Dutch oven, cook spinach in oil until wilted, about 3 minutes. Remove from pan; set aside. Melt butter in the Dutch oven; add onion and saute until crisp-tender, about 2 minutes.\r\nStir in flour, salt and nutmeg until combined. Gradually whisk in milk until blended. \r\n\r\nBring to a boil; cook and stir until thickened, about 2 minutes. Add the spinach. Reduce heat to low; cook, uncovered, until heated through, about 5 minutes.', 'I love the sauce.  It is similar to a nutty béchamel sauce\r\n\r\nOne of Al\'s favourite vegetable side dishes for steak.', 8),
(238, 'Turkey Salad from Pioneer Woman', '1/4 cup walnuts\r\n1/4 cup mayonnaise\r\n1/4 cup plain whole milk yogurt\r\n1 Tbsp. dijon mustard\r\n1 Tbsp. apple cider vinegar\r\n1 1/2 tsp. light brown sugar\r\n1/2 tsp. kosher salt\r\n1/4 tsp. black pepper\r\nA few dashes of hot sauce (optional)\r\n2 cups shredded or chopped cooked turkey**\r\n1/4 cup dried cranberries\r\n1/4 cup flat-leaf parsley, chopped\r\n1 celery stalk, chopped\r\n1/2 firm apple (such as Gala, Fiji, or Honeycrisp), cored and cubed\r\n1/2 small red onion, chopped\r\nLettuce, bread, or crackers, for serving', 'Preheat the oven to 325°F.\r\n2\r\nSpread the walnuts on a baking sheet and roast until fragrant and lightly golden, 7 to 9 minutes. Let cool, then coarsely chop.\r\n3\r\nIn a large bowl, stir together the mayonnaise, yogurt, dijon mustard, vinegar, brown sugar, salt, pepper, and hot sauce, if using. Add the turkey, dried cranberries, parsley, celery, apple, onion, and walnuts. Toss well to combine.\r\n4\r\nTurkey salad can be served chilled or at room temperature in lettuce cups, on a sandwich, or with crackers as a snack. ', '**. I have used chicken breast as well and loved it.  Great for lunch on its own.\r\n\r\nMakes about 6 portions...  my size portions.', 10),
(239, 'Half Baked Harvest Beef Chili', '2 lbs ground beef\r\n2 small yellow onions, chopped\r\n2 bell peppers\r\n2 tbsp chili powder\r\n1 tbsp chipotle chili powder\r\n1 tbsp smoked paprika\r\n1 tbsp dried oregano\r\n1 tbsp garlic powder\r\n2 tsp ground cumin\r\nsalt and pepper\r\n4 cups low sodium beef broth\r\n1 (28) can crushed tomatoes\r\n1 (6-ounce) can tomato paste\r\n2 (4 ounce) cans diced green chilis\r\n1/2 cup picked jalapeños, chopped\r\n1 tbsp worcestershire sauce\r\n1 (14) can pinto or black beans\r\n', 'Place the beef and onions in a large dutch oven.  Cook and break up over medium high heat for 10 minutes.  Add the bell peppers, chili powder, chipotle Chile powder, paprika, oregano, garlic, cumin and 1 1/2 tsp salt.  Stir to coat\r\n2.  Add 4 cups of broth, the tomatoes, tomato paste, green chilies, jalapeños and Worcestershire.  Season with salt and pepper.  Increase heat to high and bring to boil, then reduce heat to low.  Partially cover and cook, stirring occasionally, until the flavours are melded and chili has reached desired thickness, 2 - 3 hours.  Add more broth if it gets dry.\r\n3.  Just before serving, stir in the beans and heat 1 to 2 minutes.  Spoon into bowls and top as desired.', 'Serve with greek yogurt, shredded cheddar cheese, sliced avocado, thinly sliced green onion, chopped fresh cilantro, oyster crackers', 12),
(240, 'Brother Bryan\'s Pizza Dough Recipe  - brilliant!!', '7 1/2 cups flour (Robin Hood pizza flour)\r\n2 1/2 cups water\r\n3 Tblsp olive oil\r\n2 tsp salt\r\n2 tsp yeast', 'Mix everything together\r\nKnead for 10 minutes\r\nLet rise until doubled (about 1 1/2 hours)\r\nPunch the dough down\r\nDivide into 4 or 5 balls (I did 4)\r\nCoat balls in olive oil\r\nOil inside of Tupperware container\r\nPut balls in TW container\r\nPut lid on TW container\r\nPut TW container in fridge\r\nIf the dough balls get too big punch them down and reform into balls.\r\nTake out 1 hour before needed\r\nMake pizza bases', 'We made 4 balls and only used 3 for dinner for 4 of us.  Put the last one in the freezer for another day.  We had A LOT of pizza left over for dinner another night.  ', 7),
(241, 'Pioneer Woman onion and blue cheese sauce for steak', '4 tbsp butter\r\n1 very large white onion - thinly sliced\r\n1 cup heavy cream\r\n1/2 cup crumbled blue cheese', 'Saute onions in 4 tablespoons butter over high heat. Cook for 5 to 7 minutes, or until dark and caramelized. Reduce heat to simmer and pour in cream. Cook for 3 to 5 minutes, or until reduced by half. Stir in blue cheese until melted. Serve steaks on top of a generous ladling of sauce.', 'This is SO good!!', 12),
(242, 'Mexican Street Corn Pasta Salad - great salad for ribs side as very filling.', 'dressing:\r\n\r\n3/4 cup sour cream\r\n3/4 cup mayonnaise\r\n1½ limes, juiced\r\n3/4 tsp salt\r\n1/2 tsp garlic powder\r\n1/2 tsp onion powder\r\n1/4 tsp cayenne pepper\r\n\r\n\r\nsalad:\r\n\r\n1 lb medium sized pasta (close to size of kernels is good or shell form)\r\n2 tbs butter\r\n4 ears corn\r\n1 small red bell pepper, fine diced\r\n1 large avocado, diced\r\n3 tbs cilantro, chopped\r\n1/2 cup cotija cheese, crumbled + more for topping or use feta\r\ngarnish: cotija + cilantro', 'instructions\r\n\r\n\r\nCook the pasta al dente according to package directions. Drain and set aside. I drizzle on some olive oil and toss to prevent the pasta from sticking together.\r\nIn a small bowl, whisk together the sour cream, mayonnaise, zest of 1/2 lime, lime juice, salt, garlic powder, onion powder and cayenne pepper until smooth and uniform. Taste the dressing and make sure it is satisfactory to your preference and palate. Adjust with salt or lime juice if needed.\r\nGrill or pan sear your corn ears in the butter. Shave/slice the corn off of the corn ears.\r\nIn a large bowl, add in the pasta, corn, bell pepper, avocado,, cotija/feta, dressing and toss until all is coated. Top with cilantro, cotija and Tajin.\r\n', 'Note:  serve this with the cilantro in a small bowl for individual sprinkling.  Al HATES cilantro.\r\n\r\nGreat to make the day before.  Taste and add more of whatever.  I add more lime and Cayenne pepper plus more mayo and sour cream as the 2nd day comes.', 17),
(243, 'Mediterranean Chicken Bake  with Zucchini and tomatoes', '1 lb boneless, skinless chicken thighs\r\n3 zuccinis - cut into half moons\r\n3 regular tomatoes or 1.5 cups cherry tomatoes cut in half\r\n1/2 red or large white onion thinly sliced\r\n3 tbs olive oil\r\n3 garlic cloves\r\n1.5 tsp Italian seasoning\r\n.5 tsp smokey paprika\r\n1/4 tsp pepper\r\n1/2 tsp salt\r\n\r\n1/2 cup mozzarella cheese or feta cheese (or combo of both)\r\n1/4 shredded parmesan cheese', 'Heat oven to 375 degrees.  Oil a 8x13 inch pan.  \r\nCut chicken thighs into bite size pieces.  Add zucchinis and tomatoes also cut into bite size pieces.  Put all into a large bowl.  Add onions thinly sliced.  drizzle with olive oil and add garlic and herbs.  Toss well.  Add all to the prepared dish.  \r\n\r\nspread the 2 different cheeses over the top.\r\n\r\nCover with foil and bake for 20 minutes\r\n\r\nTake cover off and bake again for 15 - 20 minutes.  If the cheese does not brown, turn on the broiler and brown for 1 or 2 minutes.  Serve immediately. ', 'I found this on Pinterest and quite liked it.  Healthy.  Could be served with rice or orzo cooked in chicken broth, but for 2people, this does not need it. We end up with 1 serving as left overs.  (Al eats huge)', 10),
(244, 'Onion-Blue Cheese Sauce for steak - Yum!!  From Pioneer Woman', '4 Tbsp butter\r\n1 whole VERY large yellow onion\r\n1 cup heavy cream ( I used cocoanut milk)\r\n1.2 cup crumbled blue cheese\r\n', 'Saute onions in 4 tablespoons butter over high heat. Cook for 5 to 7 minutes, or until dark and caramelized. Reduce heat to simmer and pour in cream. Cook for 3 to 5 minutes, or until reduced by half. Stir in blue cheese until melted. Serve steaks on generous portion of sauce.\r\n', 'I made this for Al\'s birthday in 2025.  I thought it was amazing.  \r\n\r\nSpoon the sauce on the plate and place the steak on top of it.  ', 12),
(245, 'Parmesan baked Cod/ Pollack etc - easy fast and delicious', '4 cod fillets (4 ounces each)\r\n2/3 cup mayonnaise or sour cream\r\n4 green onions, chopped\r\n1/4 cup grated Parmesan cheese\r\n1 teaspoon Worcestershire sauce', 'Preheat oven to 400°. Place cod in an 8-in. square baking dish coated with cooking spray. Mix remaining ingredients; spread over fillets.\r\nBake, uncovered, until fish just begins to flake easily with a fork, 15-20 minutes.', 'I also added some Italian herb. \r\nI used sour cream instead of mayonnaise - lower calorie count and still very tasty.\r\nI baked a bunch of odd vegetables beforehand to serve along side.  \r\n', 14);
INSERT INTO `recipe` (`recipeID`, `recipe_title`, `recipe_ingredients`, `recipe_method`, `recipe_note`, `catID`) VALUES
(246, 'Cheesy Spinach Artichoke Chicken Casserole - Taste of Home', '3 cups uncooked bow tie pasta********\r\n2 tablespoons butter\r\n1/2 pound sliced fresh mushrooms\r\n1 medium onion, chopped\r\n2 large eggs\r\n1-1/2 cups 2% milk\r\n1 teaspoon Italian seasoning\r\n1/2 teaspoon salt\r\n1/4 teaspoon pepper\r\n1/4 to 1/2 teaspoon crushed red pepper flakes\r\n3 cups cubed cooked chicken\r\n1 can (14 ounces) water-packed quartered artichoke hearts, rinsed and drained********\r\n1 package (10 ounces) frozen chopped spinach, thawed and squeezed dry\r\n2 cups shredded Monterey Jack cheese******\r\n2 tablespoons grated Parmesan cheese\r\n\r\nTopping: *****\r\n1/3 cup seasoned bread crumbs\r\n2 tablespoons grated Parmesan cheese\r\n1 tablespoon butter, melted\r\n1/2 teaspoon paprika', 'Preheat oven to 350°. Cook the pasta according to package directions; drain.\r\nIn a large skillet, heat the butter over medium-high heat; saute the mushrooms and onion until tender. Remove from heat.\r\n\r\nIn a large bowl, whisk together eggs, milk and seasonings. Stir in chicken, artichoke hearts, spinach, cheeses and mushroom mixture. Stir in pasta.\r\nTransfer to a greased 13x9-in. baking dish. Bake, covered, 40 minutes.\r\n\r\nMix the topping ingredients; sprinkle over casserole. Bake, uncovered, until bubbly and topping is golden brown, 5-10 minutes.', 'I used small shell shaped pasta\r\nI prefer marinated artichokes but if I can\'t find them, I add 1/2 a lemon for the bite\r\nI use whatever cheese I have in the fridge - mixed.\r\nI don\'t bother with the topping ', 11),
(247, 'Italian soup from AllRecipes - great soup!  good empty the fridge', '1 pound sweet Italian sausage\r\n\r\n2 or 3 clove garlic, minced\r\n\r\n2 (14 ounce) cans beef broth*****\r\n\r\n1 (14.5 ounce) can Italian-style stewed tomatoes\r\n\r\n2 cup sliced carrots*****\r\n\r\n\r\n¼ teaspoon salt\r\n\r\n¼ teaspoon ground black pepper\r\n\r\n2 (14.5 ounce) can great Northern white  beans, undrained\r\n\r\n2 small zucchini, cubed\r\n\r\n2 cups spinach - packed, rinsed and torn\r\n\r\n.......................................\r\nParmesan cheese', 'Heat a stockpot or Dutch oven over medium-high heat. Add sausage and garlic; cook and stir until browned, 5 to 7 minutes.\r\n\r\nStir in broth, tomatoes, and carrots; season with salt and pepper. Reduce heat to medium-low, cover, and simmer 15 minutes.\r\n\r\nStir in beans with liquid and zucchini; cover and simmer another 15 minutes, or until zucchini is tender.\r\n\r\n\r\nRemove soup from heat and add spinach; replace the lid and allow spinach to wilt.\r\n\r\n\r\nStir until warmed through. Serve with parmesan cheese on top and enjoy!', '****. I used red wine instead of 1 cup of broth and added 1/2 cup of 2 % milk.  note it changes to a weird purple color but taste great.\r\n****. use any veg you have going to waste in the fridge (celery, peppers, onions, finely chopped broccoli, etc)\r\nthe original recipe called for 1 cup of carrots...  easily double\r\n\r\nI also added 1 tsp of Italian seasoning\r\n\r\nYou could easily double the spinach as well', 5),
(248, 'Berry Croissant Breakfast Bake from Robyn Q', '- 6 croissants, cut into fourths\r\n&#8259; 6 ounces blueberries \r\n&#8259; 6 ounces raspberries \r\n&#8259; 1 1/2 cups half and half\r\n&#8259; 3 eggs\r\n&#8259; 2 tablespoons maple syrup\r\n&#8259; Zest of 1 lemon \r\n&#8259; 1-2 teaspoons vanilla extract \r\n&#8259; 1/2 teaspoon cinnamon\r\n&#8259; 1/4 teaspoon nutmeg\r\nGlaze ingredients: \r\n&#8259; 2 tablespoons cream cheese, softened\r\n&#8259; 1/4 cup powdered sugar\r\n&#8259; 2 tablespoons half and half\r\n&#8259; 1/4 teaspoon cinnamon ', '1. Coat a 9 x 13 baking dish with nonstick cooking spray or butter. \r\n2. Place the cut pieces of croissants into the prepared baking dish. Add the raspberries and blueberries on top of the croissants. Sprinkle the zest of a lemon on top of the berries. \r\n3. In a bowl whisk together the eggs, half and half, maple syrup, vanilla, cinnamon and nutmeg until completely combined. \r\n4. Pour the egg mixture evenly over the croissants and berries. \r\n5. Cover with plastic wrap and place in the refrigerator overnight or at least 2 hours. \r\n6. Preheat oven to 350 degrees.\r\n7. Remove the plastic wrap from the baking dish and place it in the preheated oven and bake for 35-40 minutes or until it is golden brown. \r\n8. To make the glaze place the softened cream cheese powdered sugar, half and half and cinnamon in a small bowl and mix with a hand mixer until smooth. \r\n9. Drizzle the glaze over the breakfast bake. Enjoy! \r\n10. YUM!', 'Hudson loved this and ate a lot of it.\r\n\r\nPerfect for brunch\r\nBest if prepared previous night.', 6),
(249, 'Christmas Fudge Wreath', '1 (12-ounce) bag semisweet chocolate morsels\r\n9 ounces (3/4 of a 12-ounce bag) butterscotch morsels\r\n1 (14-ounce) can sweetened condensed milk\r\n1 teaspoon vanilla extract\r\n8-inch springform pan , lightly greased with softened butter\r\nM & M’s, red and green, for garnish', '1. Place a heavy pot on the stove and preheat it over low heat. Add chips and milk and stir until chips are melted and milk combined. Save the empty condensed milk can.\r\nStir in vanilla and remove fudge from heat. \r\n2. Cover empty condensed milk can with plastic food wrap and center it in the greased cake pan. Spoon fudge into pan around can. \r\n3. The fudge will set up almost immediately. Decorate your wreath with red and green M & M’s. Chill covered in the refrigerator and slice fudge very thin when ready to serve, a little goes a long way. Enjoy!', 'I use a small glass instead of the can as it is smoother.  I also found it tricky to remove the glass afterward, so just twist slowly and gently after it has been in the fridge for an hour or so.  ', 2),
(250, 'Easy Chicken Parmesan Bake with noodles - from Pioneer Woman', 'FOR THE PASTA:\r\n\r\n1 lb. Whole Wheat Rotini *\r\n\r\n2 jars (24 Oz. Size) Marinara Sauce, Divided \r\n\r\n2 cloves Garlic, Minced**\r\n\r\n1/2 tsp. Dried Basil\r\n\r\n12 oz. weight Fontina Cheese, Freshly Grated, Divided ***\r\n\r\n1/4 cup Finely Grated Parmesan Cheese\r\n\r\nFOR THE CHICKEN:\r\n\r\n3 Tbsp. Vegetable Or Canola Oil\r\n\r\n1 lb. Boneless, Skinless Chicken Thighs*****\r\n\r\n1 1/4 cups All-purpose Flour, Divided\r\n\r\n1 tsp. Salt\r\n\r\n1 tsp. Pepper\r\n\r\n1 tsp. Garlic Powder\r\n\r\n3 Eggs, Lightly Beaten****\r\n\r\n2 cups Seasoned Panko Bread Crumbs****\r\n\r\n1/2 cup Seasoned Fine Breadcrumbs****', NULL, '*. use any short noodle you have,\r\n**. Use dried garlic for ease\r\n*** I just used motzarella cheese\r\n**** I skip all the breadcrumbs.  Makes the dish too heavy for me.  I just season the chicken and dip it in flour.\r\n*****I used chicken breasts.  2 large.  sliced them horizontally to make cutlets.  \r\n', 10),
(251, 'Salisbury Steak - from Pioneer Woman - Nice for a change', '\r\n1 1/2 pounds lean ground beef\r\n\r\n1/2 cup seasoned breadcrumbs\r\n\r\n1 tablespoon ketchup\r\n\r\n2 teaspoons dry mustard\r\n\r\n4 dashes Worcestershire sauce\r\n\r\n1 cube beef bouillon, crumbled (or powdered beef base)\r\n\r\nSalt and pepper\r\n\r\n1 tablespoon butter\r\n\r\n1 tablespoon olive oil\r\n\r\nGravy:\r\n\r\n1 whole onion, halved and thinly sliced (or diced if you prefer)\r\n\r\nSliced mushrooms***\r\n\r\n2 cups beef broth, more if needed for thinning\r\n\r\n1 tablespoon ketchup\r\n\r\n1 teaspoon seasoning sauce, such as Kitchen Bouquet, optional***\r\n\r\n4 dashes Worcestershire\r\n\r\n1 teaspoon cornstarch, optional\r\n\r\nSalt and pepper\r\n', 'For the meat mixture: Combine the ground beef, breadcrumbs, ketchup, dry mustard, Worcestershire sauce, bouillon and some salt and pepper. Knead until all combined. Form into 4 to 6 oval patties, and then make lines across the patties to give them a \"steak\" appearance.\r\nFry the patties in a skillet with the butter and oil over medium-high heat on both sides until no longer pink in the middle. Remove from the skillet and pour off any excess grease.\r\n\r\n\r\nFor the gravy:  Add mushrooms to pan then add in the sliced onions. Stir and cook until golden brown and somewhat soft, for several minutes. Add the beef stock, ketchup, seasoning sauce, if using, and the Worcestershire. Then combine the cornstarch with a little beef broth and add to the sauce if using. Stir and cook to reduce.\r\nAdd a sprinkle of salt and pepper and more broth if needed for thinning. Then return the patties to the gravy. Spoon the gravy over the top and let them simmer and heat back up for a couple of minutes.\r\n', '*** Kitchen Bouquet - I just use dark soya sauce or Beef Bisto\r\n\r\ngood with any veggies, potatoes and carrots or whatever you have on hand.', 12),
(252, 'Chopped Buffalo Chicken Salad - Main - from Half Baked - serves 4 ', '2/3 cup buffalo sauce (or use hot sauce)\r\n&#9634; 1/4 cup honey\r\n&#9634; 2 tablespoons extra virgin olive oil\r\n&#9634; 2 pounds chicken breasts, cut into cubes\r\n&#9634; 1 tablespoon seasoned salt\r\n&#9634; 6 cups shredded lettuce\r\n&#9634; 1/3 cup fresh cilantro, chopped\r\n&#9634; 1 cup cherry tomatoes, sliced\r\n&#9634; 1 cup grilled corn kernels (about 2 ears)\r\n&#9634; 1/4 cup chopped, peperoncini\r\n&#9634; 1 cup crumbled blue cheese or cubed cheddar\r\n&#9634; 6 strips cooked bacon, crumbled\r\n&#9634; 1 avocado, chopped\r\nDRESSING\r\n\r\n&#9634; 1/2 cup sour cream or plain Greek yogurt\r\n&#9634; 1/3 cup mayo\r\n&#9634; 1/2 cup pickled jalapeños\r\n&#9634; 1/3 cup fresh cilantro\r\n&#9634; 3 tablespoons fresh basil\r\n&#9634; 2 tablespoons chopped fresh dill\r\n&#9634; 1 teaspoon garlic powder\r\n&#9634; kosher salt and black pepper', 'In a bowl, mix the buffalo sauce with the honey.\r\nSave 1/4 cup separately.\r\n\r\nMix cubed chicken with salt, pepper etc with the saved 1/4 cup of the buffalo/honey sauce.  Let sit until ready to cook.\r\n\r\nMake the dressing and store in the fridge.\r\n\r\nBBQ or sear the chicken in a frying pan.  Cooking through.  10 to 12 minutes.\r\n\r\nMeanwhile, assemble the other salad main body ingredients.\r\n\r\nIn a bowl, assemble the lettuce, cilantro, tomatoes, corn and peperoncini.  Toss with 1/2 the dressing.\r\n\r\nIndividuals, place seasoned lettuce combo in a bowl.  Layer chicken, blue cheese and bacon, avocado on top.\r\n\r\nServe with extra honey buffalo sauce on the side.\r\n', 'I like buffalo sauce.\r\nSeasoned salt....  if you idon\'t have it, use salt and a variety of dry mixed herbs, including garlic.\r\nAvocado....  I tend to skip for the calories.  Al will not eat.\r\n\r\nDressing, I like low fat sour cream.  Cilantro.... Al HATES, so I skip it.  \r\n\r\nSupposedly this recipe serves 6, but it really serves 4 Donalds as a main meal if you use all the lettuce.', 17),
(254, 'Curry chicken soup..  healthier version than curried chicken', '1/4 cup vegetable oil\r\n3 cups chopped onions (about 1 pound)\r\n5 garlic cloves, chopped\r\n1 1/2 tablespoons garam masala\r\n1 1/2 teaspoons ground coriander\r\n1 teaspoon turmeric\r\n1/2 teaspoon cayenne pepper\r\n2 bay leaves\r\n2 cups dried red lentils\r\n8 cups low-salt chicken broth\r\n2 cups diced cooked chicken\r\n1 cup canned unsweetened coconut milk\r\n3 tablespoons fresh lemon juice\r\n2 cups cooked basmati rice\r\nLemon wedges', 'Step 1\r\n\r\nHeat vegetable oil in heavy large pot over medium-high heat. Add onions and cook until golden brown, stirring frequently, about 15 minutes. Add garlic and sauté 2 minutes. Add garam masala and next 4 ingredients; stir 1 minute. Add lentils; stir until coated. Add chicken broth. Bring soup to boil; reduce heat to medium and simmer until lentils are very tender, about 20 minutes. Discard bay leaves.\r\nStep 2\r\n\r\nWorking in batches, puree soup in blender until smooth. Return to pot. Stir in chicken, coconut milk, and lemon juice. Season to taste with salt and pepper.\r\nStep 3\r\n\r\nDivide rice among bowls. Pour soup over. Garnish with lemon wedges; serve.', 'Very good.  I tend to cook the raw chicken in the broth with the lentils.  then shred.', 10),
(256, 'Mulligatawny Soup from Epicurious', '1/4 cup vegetable oil 3 cups chopped onions (about 1 pound) 1 or 2 large carrots - chopped 2 stalks celery - chopped 5 garlic cloves, chopped 1 1/2 tablespoons garam masala 1 1/2 teaspoons ground coriander 1 teaspoon turmeric 1/2 teaspoon cayenne pepper - I used 1 tsp 2 bay leaves 2 cups dried red lentils 8 cups low-salt chicken broth 2 or 3 chicken breasts 1 cup canned unsweetened coconut milk/cream salt and pepper 3 tablespoons fresh lemon juice 2 cups cooked basmati rice Lemon wedges \r\n', 'Heat the oil in a large heavy pot. Then add onions and sautÃ© (means fry gently), stirring often for 15 minutes until golden. Add garlic and sautÃ© for 1 minute until you can smell it. Add the spices.... garam marsala through bay leaves. Stir all together for 1 minute. Add dry lentils, stir all together for 1 minute. Add broth and raw chicken breasts. Cook for 20 minutes. Remove chicken breast and bay leafs. Shred the chicken. Gently pulse the soup with a handheld blender to mostly shred the lentils. Leaving the carrots largely intact. Add shredded chicken back in with the bay leafs. Add cocoanut milk/cream. Let low simmer to enhance the chicken. Cook rice separately. spoon rice into bowl. Spoon chicken stew over and squeeze lemon over it.', 'tastes like curry chicken!! So good. Some said an apple tasted good too, but I think it is great without. Makes 4 main course servings. Lots of fibre so it is quite filling. Maybe serve with some whole wheat naan bread. \r\n', 5);
